def connected_components(G, *, backend=None, **backend_kwargs):
    """Generate connected components.

    Yields sets of nodes, one set per component. Matches the upstream
    ``networkx.connected_components`` contract (generator of sets).

    br-r37-c1-spbk: accept nx's ``backend=None, **backend_kwargs``
    dispatch surface so drop-in code that passes ``backend='networkx'``
    works on fnx.
    """
    _validate_backend_dispatch_keywords(
        "connected_components", backend, backend_kwargs,
    )
    # br-r37-c1-pf5vu: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    # br-r37-c1-scceager: nx is @not_implemented_for('directed') — raise EAGERLY
    # on the call, not lazily on iteration. Return an inner generator.
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    def _gen():
        yield from _raw_connected_components(G)

    return _gen()


def articulation_points(G):
    """Yield articulation points of ``G``.

    Matches upstream's generator contract (franken_networkx-v1nwd).

    br-r37-c1-rf7lr: the Rust binding now emits APs in DFS-discovery
    order using insertion-order adjacency, matching nx's
    ``_biconnected_dfs`` exactly. We can use the fast Rust path
    instead of delegating to networkx — ~50x faster on BA200, more
    at scale (br-r37-c1-9kyjl is superseded).
    """
    # br-r37-c1-eghxq: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    # br-r37-c1-scceager: nx is @not_implemented_for('directed') — eager raise.
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    def _gen():
        if G.is_multigraph():
            # The Rust impl is a simple-graph DFS; multigraph parallel
            # edges need nx's chain-decomposition path for correct AP
            # detection on parallel-edge cycles.
            yield from _call_networkx_for_parity("articulation_points", G)
            return
        yield from _raw_articulation_points(G)

    return _gen()


def bridges(G, root=None):
    """Generate all bridges in a graph.

    Parameters
    ----------
    G : graph
        An undirected graph.
    root : node, optional
        A node in the graph. If specified, only the bridges in the
        connected component containing root are yielded.

    Yields
    ------
    edge
        Bridges in the graph.
    """
    # br-r37-c1-eghxq: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    # br-r37-c1-scceager: nx is @not_implemented_for('directed') — eager raise.
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    def _gen():
        if root is not None:
            yield from _call_networkx_for_parity("bridges", G, root=root)
            return
        if G.is_multigraph():
            # br-zzcm9: a parallel edge pair is never a bridge — removing
            # one leaves the other connecting u and v, so connectivity is
            # preserved. The Rust native bridges pass treats the simple
            # projection, which misreports parallel pairs as bridges.
            for u, v in _raw_bridges(G):
                if len(G[u][v]) == 1:
                    yield (u, v)
            return
        # br-r37-c1-rf7lr: the Rust binding now emits bridges in
        # graph-edge-insertion order with original edge orientation,
        # matching nx.bridges() (which iterates ``H.edges`` after a chain
        # decomposition). br-r37-c1-h83lo is superseded.
        yield from _raw_bridges(G)

    return _gen()


def is_tree(G, *, backend=None, **backend_kwargs):
    """Return True if ``G`` is a tree.

    A tree is a connected graph with ``n - 1`` edges and no cycles. On a
    MultiGraph, parallel edges create cycles, so br-zzcm9 requires we
    _count parallels rather than relying on the simple-projection native
    path (which overcounts nodes-without-parallels as trees).

    br-treedir: NetworkX's directed contract counts directed edges
    against ``|V| - 1`` and uses weak connectivity. The Rust binding
    collapses ``0->1, 1->0`` to a single undirected edge {0,1} and
    accepts that as a tree (n=2, m=1 → True), even though NX returns
    False (n=2, directed m=2). Handle the directed branch explicitly.
    """
    _validate_backend_dispatch_keywords("is_tree", backend, backend_kwargs)
    # br-r37-c1-pf5vu: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    n = G.number_of_nodes()
    if n == 0:
        raise NetworkXPointlessConcept("G has no nodes.")
    if G.is_directed():
        # Multigraphs _count parallels naturally via number_of_edges.
        m = G.number_of_edges()
        return m == n - 1 and is_weakly_connected(G)
    if G.is_multigraph():
        m = G.number_of_edges()  # multigraph counts parallels
        return m == n - 1 and is_connected(G)
    return _raw_is_tree(G)


def is_forest(G, *, backend=None, **backend_kwargs):
    """Return True if ``G`` is a forest (disjoint union of trees).

    MultiGraph parallels create cycles (br-zzcm9); verify each
    connected component is a tree counting parallels.

    br-treedir: same directed-edge-collapse defect as ``is_tree`` —
    the Rust binding sees ``0->1, 1->0`` as a single undirected edge
    and reports a forest. NX requires each weakly-connected component
    to have ``|E| == |V| - 1`` counting directed edges.
    """
    _validate_backend_dispatch_keywords("is_forest", backend, backend_kwargs)
    # br-r37-c1-pf5vu: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    if G.number_of_nodes() == 0:
        raise NetworkXPointlessConcept("G has no nodes.")
    if G.is_directed():
        for component in weakly_connected_components(G):
            sub = G.subgraph(component)
            if sub.number_of_edges() != sub.number_of_nodes() - 1:
                return False
        return True
    if G.is_multigraph():
        for component in connected_components(G):
            sub = G.subgraph(component)
            # |E| = |V| - 1 and connected → tree
            if sub.number_of_edges() != sub.number_of_nodes() - 1:
                return False
        return True
    return _raw_is_forest(G)


def complement(G):
    """Return the graph complement of ``G``.

    For MultiGraph inputs (br-zzcm9), delegate to the upstream nx
    implementation since the Rust native complement rejects them with
    TypeError; nx's complement on a MultiGraph returns a MultiGraph
    with the non-edges (between each pair of distinct nodes, one edge
    per missing pair — matches a simple-graph complement structure).
    """
    # br-r37-c1-nwkg0: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    if G.is_multigraph():
        return _complement_via_nx(G)
    return _raw_complement(G)


def node_connectivity(G, s=None, t=None, flow_func=None):
    """Return the node connectivity of the graph.

    Parameters
    ----------
    G : graph
        An undirected graph.
    s : node, optional
        Source node.
    t : node, optional
        Target node.
    flow_func : function, optional
        A function for computing the maximum flow between a pair of nodes.

    Returns
    -------
    int
        The node connectivity of G.
    """
    # br-r37-c1-0555d: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    if len(G) == 0:
        # Match nx's contract: connectivity is undefined for the null
        # graph (br-r37-c1-turq0). The Rust impl silently returned 0.
        raise NetworkXPointlessConcept(
            "Connectivity is undefined for the null graph."
        )
    # br-r37-c1-znqrc: match nx's two-stage check — "Both source and
    # target must be specified" when exactly one is given, then "node
    # X not in graph" (bare value, not the Rust "node str:2:X" leak)
    # when both are given but absent.
    if (s is None) ^ (t is None):
        raise NetworkXError("Both source and target must be specified.")
    if s is not None and s not in G:
        raise NetworkXError(f"node {s} not in graph")
    if t is not None and t not in G:
        raise NetworkXError(f"node {t} not in graph")
    if flow_func is not None:
        return _call_networkx_for_parity(
            "node_connectivity",
            G,
            s=s,
            t=t,
            flow_func=flow_func,
        )
    # br-r37-c1-792dv: the Rust _raw_node_connectivity ignores the
    # +2 degree contribution that self-loops make in nx's
    # min-degree-bound calculation. On a single-node graph with a
    # self-loop nx returns 2 vs fnx's 0; on a 2-node graph with two
    # self-loops + a bridge nx returns 3 (min_degree=3) vs fnx's 2.
    # Delegate any graph with at least one self-loop to nx so both
    # libraries agree on the self-loop weighting.
    if number_of_selfloops(G) > 0:  # br-r37-c1-5i5gb: native O(|V|) check, not O(|E|) EdgeView pass
        return _call_networkx_for_parity("node_connectivity", G, s=s, t=t)
    # Multigraphs with parallel edges bump the min-degree bound above
    # the simple-graph κ = n−1 ceiling (a node with k parallel edges to a
    # neighbour contributes k to its degree). networkx uses that bound
    # when every node pair is adjacent, so on e.g. K3 with parallel edges
    # it returns the higher min-degree value; the Rust path collapses
    # parallel edges and returns the simple-graph answer. Delegate
    # multigraph inputs to networkx to preserve parity.
    if G.is_multigraph():
        return _call_networkx_for_parity(
            "node_connectivity",
            G,
            s=s,
            t=t,
        )
    return _raw_node_connectivity(G, s=s, t=t)


def edge_connectivity(G, s=None, t=None, flow_func=None, cutoff=None):
    """Return the edge connectivity of the graph.

    Parameters
    ----------
    G : graph
        An undirected graph.
    s : node, optional
        Source node.
    t : node, optional
        Target node.
    flow_func : function, optional
        A function for computing the maximum flow between a pair of nodes.
    cutoff : int, optional
        If specified, stop computing when connectivity is found to be at least cutoff.

    Returns
    -------
    int
        The edge connectivity of G.
    """
    # br-r37-c1-0555d: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    if len(G) == 0:
        # Match nx's contract: connectivity is undefined for the null
        # graph (br-r37-c1-turq0). The Rust impl silently returned 0.
        raise NetworkXPointlessConcept(
            "Connectivity is undefined for the null graph."
        )
    # br-r37-c1-znqrc: see node_connectivity above — both-or-neither
    # specified, then nx-shaped node-membership message.
    if (s is None) ^ (t is None):
        raise NetworkXError("Both source and target must be specified.")
    if s is not None and s not in G:
        raise NetworkXError(f"node {s} not in graph")
    if t is not None and t not in G:
        raise NetworkXError(f"node {t} not in graph")
    if flow_func is not None:
        return _call_networkx_for_parity(
            "edge_connectivity",
            G,
            s=s,
            t=t,
            flow_func=flow_func,
            cutoff=cutoff,
        )
    # br-r37-c1-ec-cutoff: the Rust _raw_edge_connectivity raises
    # NetworkXNotImplemented("does not support the cutoff
    # parameter") on any non-None cutoff value, masking nx's
    # documented contract that ``cutoff`` short-circuits when
    # connectivity is found to be at least cutoff.  Delegate any
    # cutoff-bearing call to nx instead.
    if cutoff is not None:
        return _call_networkx_for_parity(
            "edge_connectivity", G, s=s, t=t, cutoff=cutoff
        )
    # br-r37-c1-792dv: the Rust _raw_edge_connectivity ignores the
    # +2 degree contribution that self-loops make in nx's
    # min-degree-bound calculation. nx's value on graphs with any
    # self-loop is generally larger than fnx's (e.g. single-node
    # self-loop: nx=2 vs fnx=0; two-node + two self-loops + bridge:
    # nx=3 vs fnx=1). Delegate any self-loop graph to nx so both
    # libraries agree on the weighting.
    if number_of_selfloops(G) > 0:  # br-r37-c1-5i5gb: native O(|V|) check, not O(|E|) EdgeView pass
        return _call_networkx_for_parity(
            "edge_connectivity", G, s=s, t=t, cutoff=cutoff
        )
    # Multigraphs: the Rust implementation collapses parallel edges and
    # returns the simple-graph edge-connectivity (and as a float), whereas
    # networkx counts parallel edges and returns an int. Delegate to keep
    # parity with nx on MultiGraph / MultiDiGraph inputs.
    if G.is_multigraph():
        return _call_networkx_for_parity(
            "edge_connectivity",
            G,
            s=s,
            t=t,
            cutoff=cutoff,
        )
    # edge_connectivity is a structural graph property — it counts edges,
    # not flow capacity. The Rust dispatcher incorrectly honours any
    # ``capacity`` edge attribute and returns the weighted max-flow
    # value instead (franken_networkx-8ud1m). Strip any capacity attrs
    # into a scrubbed copy so the underlying max-flow reduces to unit
    # capacities and the returned integer is the edge cardinality.
    has_capacity = any(
        "capacity" in d for _, _, d in G.edges(data=True)
    )
    if has_capacity:
        scrubbed = type(G)()
        scrubbed.graph.update(dict(G.graph))
        scrubbed.add_nodes_from((n, dict(d)) for n, d in G.nodes(data=True))
        if G.is_multigraph():
            scrubbed.add_edges_from(
                (u, v, key, {k: val for k, val in d.items() if k != "capacity"})
                for u, v, key, d in G.edges(keys=True, data=True)
            )
        else:
            scrubbed.add_edges_from(
                (u, v, {k: val for k, val in d.items() if k != "capacity"})
                for u, v, d in G.edges(data=True)
            )
        G = scrubbed
    # Rust returns a float via the max-flow pipeline; networkx returns an
    # int because edge_connectivity is a cardinality. Coerce to int when
    # the value is exactly integral (it always is for unit capacities).
    result = _raw_edge_connectivity(G, s=s, t=t, cutoff=cutoff)
    if isinstance(result, float) and result.is_integer():
        return int(result)
    return result








