# Algorithm functions — Euler
from franken_networkx._fnx import (
    eulerian_circuit as _raw_eulerian_circuit,
    eulerian_path as _raw_eulerian_path,
    has_eulerian_path as _raw_has_eulerian_path,
    is_eulerian as _raw_is_eulerian,
    is_semieulerian as _raw_is_semieulerian,
)


def is_semieulerian(G):
    """Return True iff the graph has an Eulerian path but not a circuit.

    br-r37-c1-lg07d: the Rust kernel ``_raw_is_semieulerian`` has
    ``require_undirected`` and rejects directed input. nx supports
    ``is_semieulerian`` on digraphs (a digraph has an Eulerian path iff
    at most one node has out-in=1, at most one has in-out=1, and all
    others have equal in/out, with the underlying graph connected).
    Compose from the directed-aware ``has_eulerian_path`` and
    ``is_eulerian`` wrappers so the directed semantics are preserved.
    """
    return has_eulerian_path(G) and not is_eulerian(G)


def is_eulerian(G):
    """Return True iff *G* is Eulerian (connected + all even degrees).

    The Rust helper returned False for a graph consisting only of a
    self-loop — it either excluded self-loops from its degree _count or
    special-cased 1-node graphs. nx includes the self-loop's +2 degree
    contribution and correctly reports True for e.g. Graph([(0,0)]).
    Delegate the 0- and 1-node branches to a Python check and keep the
    fast path for ``G`` with >= 2 distinct nodes.
    """
    # br-r37-c1-rg8jh: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    if G.number_of_nodes() <= 1:
        if G.is_directed():
            # For <=1 nodes the helper is the right answer (nx is_eulerian
            # requires is_strongly_connected on directed input; empty/single
            # cases match).
            if G.number_of_nodes() == 0:
                raise NetworkXPointlessConcept(
                    "Connectivity is undefined for the null graph."
                )
            # Single node with only self-loops: check every degree (including
            # self-loop's +2) is even.
            for node in G.nodes():
                if G.in_degree(node) != G.out_degree(node):
                    return False
            return True
        # Undirected
        if G.number_of_nodes() == 0:
            raise NetworkXPointlessConcept(
                "Connectivity is undefined for the null graph."
            )
        for _, deg in G.degree():
            if deg % 2 != 0:
                return False
        return True
    # br-r37-c1-792dv: the Rust _raw_is_eulerian also mishandles
    # self-loops on multi-node graphs (e.g. K3 + self-loop on one
    # vertex remains Eulerian per nx but the Rust path returns
    # False). Delegate to nx whenever any self-loop is present so
    # both predicates carry the same self-loop semantics.
    if number_of_selfloops(G) > 0:  # br-r37-c1-5i5gb: native O(|V|) check, not O(|E|) EdgeView pass
        return _call_networkx_for_parity("is_eulerian", G)
    return _raw_is_eulerian(G)


def eulerian_circuit(G, source=None, keys=False):
    """Return edges of an Eulerian circuit in G.

    Parameters
    ----------
    G : graph
        A graph with an Eulerian circuit.
    source : node, optional
        Starting node for circuit.
    keys : bool, optional
        If True, return edge keys for multigraphs. Default is False.

    Yields
    ------
    edge
        Edges in the Eulerian circuit.

    Notes
    -----
    br-r37-c1-lim0x: Eulerian circuits are non-unique, but nx and the
    Rust binding produced different traversal directions (e.g. fnx
    returned (a,b),(b,c),... while nx returned (a,e),(e,d),...).
    Delegate to nx so the produced edge sequence matches nx's
    documented Hierholzer-traversal contract exactly.
    """
    yield from _call_networkx_for_parity(
        "eulerian_circuit", G, source=source, keys=keys,
    )


def eulerian_path(G, source=None, keys=False):
    """Return edges of an Eulerian path in G.

    Parameters
    ----------
    G : graph
        A graph with an Eulerian path. Directed and undirected
        (br-r37-c1-z4i7f).
    source : node, optional
        Starting node for path.
    keys : bool, optional
        If True, return edge keys for multigraphs. Default is False.

    Yields
    ------
    edge
        Edges in the Eulerian path.
    """
    # br-r37-c1-eulpath-src-bad: nx raises NetworkXError("Node {n}
    # is not in the graph.") on missing source; fnx's Rust binding
    # raises NodeNotFound (subclass of NetworkXException, NOT
    # NetworkXError).  Pre-validate at the wrapper to match the
    # sibling eulerian_circuit's exception class.
    # br-r37-c1-eghxq: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    if source is not None and source not in G:
        raise NetworkXError(f"Node {source} is not in the graph.")
    # br-r37-c1-04z53.51: simple DiGraph now uses the native directed
    # reversed-Hierholzer path. MultiDiGraph still delegates so key
    # ordering and parallel-edge handling remain NetworkX-owned.
    if G.is_directed():
        if G.is_multigraph():
            yield from _call_networkx_for_parity(
                "eulerian_path", G, source=source, keys=keys,
            )
            return
        yield from _raw_eulerian_path(G, source=source)
        return
    if keys:
        yield from _call_networkx_for_parity("eulerian_path", G, source=source, keys=keys)
        return
    # br-r37-c1-dg2dn: the Rust _raw_eulerian_path mishandles
    # self-loops the same way the boolean predicates did
    # (br-r37-c1-792dv) — it raises "Graph has no Eulerian paths"
    # on graphs that ARE Eulerian, e.g. K3 + self-loop. Delegate
    # any graph with at least one self-loop to nx so eulerian_path
    # is consistent with has_eulerian_path / is_eulerian.
    if number_of_selfloops(G) > 0:  # br-r37-c1-5i5gb: native O(|V|) check, not O(|E|) EdgeView pass
        yield from _call_networkx_for_parity(
            "eulerian_path", G, source=source, keys=keys,
        )
        return
    yield from _raw_eulerian_path(G, source=source)


def has_eulerian_path(G, source=None):
    """Return True if G has an Eulerian path.

    Parameters
    ----------
    G : graph
        A graph (directed or undirected).
    source : node, optional
        Starting node for path.

    Returns
    -------
    bool
        True if G has an Eulerian path.
    """
    # br-r37-c1-rg8jh: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    # br-r37-c1-bf1wb: nx supports directed graphs here (a digraph has
    # an Eulerian path iff at most one node has out-in=1, at most one
    # has in-out=1, all others have equal in/out, and the underlying
    # graph is connected). The Rust binding only handles undirected,
    # so delegate the directed case to nx.
    if G.is_directed():
        return _call_networkx_for_parity("has_eulerian_path", G, source=source)
    if source is not None:
        return _call_networkx_for_parity("has_eulerian_path", G, source=source)
    # br-r37-c1-792dv: the Rust _raw_has_eulerian_path mishandles
    # self-loops (each self-loop adds 2 to degree, keeping parity
    # even). On graphs with self-loops the Rust path returns False
    # where nx returns True (e.g. K3 + self-loop, single-node
    # self-loop, self-loop attached to a chain). Delegate any
    # graph with at least one self-loop to nx.
    if number_of_selfloops(G) > 0:  # br-r37-c1-5i5gb: native O(|V|) check, not O(|E|) EdgeView pass
        return _call_networkx_for_parity("has_eulerian_path", G, source=source)
    return _raw_has_eulerian_path(G)

# Algorithm functions — paths and cycles
from franken_networkx._fnx import (
    all_shortest_paths as _raw_all_shortest_paths,
    all_simple_paths as _rust_all_simple_paths,
    cycle_basis as _raw_cycle_basis,
)

# br-rustlag: minimum_cycle_basis ships behind an in-flight Rust
# rebuild. When the .so doesn't export it yet, fall back to the Python
# helper below so fnx still imports.
try:
    from franken_networkx._fnx import minimum_cycle_basis as _raw_minimum_cycle_basis
except ImportError:
    _raw_minimum_cycle_basis = None


def cycle_basis(G, root=None):
    """Return a cycle basis of the graph.

    Matches upstream NetworkX: raises NetworkXNotImplemented on
    multigraph inputs before the basis computation runs, rather than
    silently returning ``[]``.
    """
    # br-r37-c1-eghxq: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if root is not None:
        if root not in G:
            raise KeyError(root)
        return _raw_cycle_basis(G, root=root)
    return _raw_cycle_basis(G)


def all_shortest_paths(
    G, source, target, weight=None, method="dijkstra", *, backend=None, **backend_kwargs
):
    """Yield every shortest path from ``source`` to ``target``.

    Returns a generator of equal-length minimum-cost paths. ``method`` selects
    the underlying algorithm (``"dijkstra"``, ``"bellman-ford"``, or
    ``"unweighted"``). Mirrors ``networkx.all_shortest_paths``; raises
    ``NetworkXNoPath`` when advanced if no path exists.
    """
    G = _coerce_arg_to_fnx_graph(G)
    # br-r37-c1-6atv8 / br-r37-c1-emxwl: invalid method and missing
    # source raise eagerly, but target-dependent errors happen when
    # the true generator is advanced, matching nx's generator body.
    _validate_backend_dispatch_keywords("all_shortest_paths", backend, backend_kwargs)
    if weight is not None and method not in {"dijkstra", "bellman-ford", "unweighted"}:
        raise ValueError(f"method not supported: {method}")
    # br-r37-c1-jxvsu: missing source raises eagerly with nx wording.
    if source not in G:
        raise NodeNotFound(f"Source {source} not in G")

    def _gen():
        # br-r37-c1-omjmu / br-r37-c1-emxwl: nx raises TypeError on
        # unhashable target and NetworkXNoPath on missing target only
        # when the generator is advanced.
        hash(target)
        if target not in G:
            raise NetworkXNoPath(f"Target {target} cannot be reached from given sources")
        # br-r37-c1-qiplw / br-r37-c1-wjz3x: the native ``_raw_all_shortest_paths``
        # kernel (both undirected and directed) now enumerates paths in nx's
        # BFS-predecessor-DAG order (matching _build_paths_from_predecessors), so
        # the unweighted case (weight=None) runs natively instead of paying a
        # full fnx->nx conversion per call. nx forces method='unweighted'
        # whenever weight is None. The binding raises NetworkXNoPath with a
        # different message for an unreachable (but present) target, so re-raise
        # with nx's exact wording.
        if weight is None:
            try:
                paths = _raw_all_shortest_paths(G, source, target, method="unweighted")
            except NetworkXNoPath:
                raise NetworkXNoPath(
                    f"Target {target} cannot be reached from given sources"
                )
            yield from paths
            return
        if method == "unweighted":
            # nx accepts method='unweighted' even when weight is supplied;
            # the method selection wins and edge weights are ignored.
            yield from _call_networkx_for_parity(
                "all_shortest_paths", G, source, target, weight=weight, method=method,
            )
            return
        if weight is not None and G.is_directed():
            # Delegate non-string / callable weights to NetworkX (the PyO3
            # binding's ``weight: str`` signature type-rejects, and callables
            # have no Rust analogue). bellman-ford is now native (br-r37-c1-
            # xsi7c), so it stays in the Rust path unless the weight type
            # forces a fallback.
            if _should_delegate_dijkstra_to_networkx(G, weight) or (
                method == "bellman-ford" and _should_delegate_bellman_ford_to_networkx(weight)
            ):
                kwargs = {"weight": weight}
                if method is not None:
                    kwargs["method"] = method
                yield from _call_networkx_for_parity(
                    "all_shortest_paths", G, source, target, **kwargs
                )
                return
        if weight is not None and method == "dijkstra" and _should_delegate_dijkstra_to_networkx(G, weight):
            kwargs = {"weight": weight}
            if method is not None:
                kwargs["method"] = method
            yield from _call_networkx_for_parity("all_shortest_paths", G, source, target, **kwargs)
            return
        if weight is not None and method == "bellman-ford" and _should_delegate_bellman_ford_to_networkx(weight):
            kwargs = {"weight": weight}
            if method is not None:
                kwargs["method"] = method
            yield from _call_networkx_for_parity(
                "all_shortest_paths", G, source, target, **kwargs
            )
            return
        yield from _raw_all_shortest_paths(G, source, target, weight=weight, method=method)

    return _gen()


def all_simple_paths(
    G, source, target, cutoff=None, *, backend=None, **backend_kwargs
):
    """Yield all simple paths from *source* to *target*.

    ``target`` may be a single node OR an iterable of target nodes (list
    / set / etc.) - NetworkX yields paths in observable DFS order.  The
    Rust binding returns the same path set for scalar targets but can differ
    in yield order, so the public wrapper delegates to preserve exact parity.

    _Generator function so the returned object is a true generator
    matching nx's contract (br-r37-c1-682kr).
    """
    _validate_backend_dispatch_keywords("all_simple_paths", backend, backend_kwargs)
    # br-r37-c1-asplocal: the delegation pays a full fnx->nx conversion (O(V+E))
    # on every call -- 24-100x slower than networkx for a small-cutoff query
    # (the common "paths up to length k" use). For a non-multigraph with a small
    # integer cutoff (few paths) reimplement networkx's exact DFS directly on the
    # fnx graph: same G.edges(node) iteration order -> byte-identical yield order
    # (verified 7500/7500 incl directed / iterable-target / string nodes). For a
    # large cutoff / cutoff=None (many paths) or a multigraph the one-time
    # conversion amortises and networkx's C DFS wins, so keep delegating there.
    if (
        cutoff is not None
        and isinstance(cutoff, int)
        and cutoff <= 3
        and not G.is_multigraph()
    ):
        Gc = _coerce_arg_to_fnx_graph(G)
        yield from _all_simple_paths_fnx(Gc, source, target, cutoff)
        return
    # br-r37-c1-qpykd: multigraphs delegate to networkx; the yield order is now
    # correct because _fnx_to_nx emits parallel edges in adj-insertion order
    # (order-preserving multigraph conversion) so the converted graph's
    # edges(keys=True) iteration matches a directly-built nx multigraph.
    yield from _call_networkx_for_parity(
        "all_simple_paths", G, source, target, cutoff=cutoff
    )


def _all_simple_paths_fnx(G, source, target, cutoff):
    """networkx's exact all_simple_paths DFS run directly on the fnx graph.

    Mirrors networkx.algorithms.simple_paths.all_simple_edge_paths +
    _all_simple_edge_paths verbatim (non-multigraph), so the yielded node lists
    and their order match networkx byte-for-byte. Only reached for a small
    integer cutoff on a non-multigraph (br-r37-c1-asplocal).
    """
    if source not in G:
        raise NodeNotFound(f"source node {source} not in graph")
    if target in G:
        targets = {target}
    else:
        try:
            targets = set(target)
        except TypeError as err:
            raise NodeNotFound(f"target node {target} not in graph") from err
    if cutoff < 0 or not targets:
        return
    current_path = {None: None}
    stack = [iter([(None, source)])]
    while stack:
        next_edge = next((e for e in stack[-1] if e[1] not in current_path), None)
        if next_edge is None:
            stack.pop()
            current_path.popitem()
            continue
        _previous_node, next_node, *_ = next_edge
        if next_node in targets:
            edge_path = (list(current_path.values()) + [next_edge])[2:]
            yield [source] + [edge[1] for edge in edge_path]
        if len(current_path) - 1 < cutoff and (
            targets - current_path.keys() - {next_node}
        ):
            current_path[next_node] = next_edge
            stack.append(iter(G.edges(next_node)))


