def is_k_edge_connected(G, k):
    """Return True if *G* is k-edge-connected.

    br-ikeck0: nx.is_k_edge_connected raises
    ``ValueError('k must be positive, not {k}')`` for k<1. fnx's
    Rust binding accepted k=0 and returned True (vacuously). Match
    nx's validation.
    """
    G = _coerce_arg_to_fnx_graph(G)
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if k < 1:
        raise ValueError(f"k must be positive, not {k}")
    if not isinstance(k, int):
        if G.number_of_nodes() < k + 1:
            return False
        if any(degree < k for _, degree in G.degree()):
            return False
        if k == 1:
            return is_connected(G)
        if k == 2:
            return is_connected(G) and not has_bridges(G)
        return edge_connectivity(G) >= k
    return _raw_is_k_edge_connected(G, k)


def average_node_connectivity(G, flow_func=None):
    """Return the average node connectivity of the graph.

    Parameters
    ----------
    G : graph
        An undirected graph.
    flow_func : function, optional
        A function for computing the maximum flow between a pair of nodes.

    Returns
    -------
    float
        The average node connectivity of G.
    """
    # br-r37-c1-qz40o: Rust BFS-based local_node_connectivity uses a
    # heuristic that doesn't give correct values in all cases. Always
    # delegate to nx which uses proper max-flow on an auxiliary graph.
    return _call_networkx_for_parity(
        "average_node_connectivity",
        G,
        flow_func=flow_func,
    )

def all_pairs_dijkstra(G, cutoff=None, weight="weight"):
    """_Iterator of ``(source, (distances, paths))`` pairs via Dijkstra.

    For every node ``source`` in ``G``, yields the same ``(distances, paths)``
    dicts as ``single_source_dijkstra(G, source, cutoff=cutoff, weight=weight)``.
    Mirrors ``networkx.all_pairs_dijkstra``.
    """
    G = _coerce_arg_to_fnx_graph(G)
    # br-r37-c1-opxj0: explicit non-unit weighted calls need exact nx distance
    # type/order parity; default-unit graphs keep the native raw path below.
    if _should_delegate_dijkstra_to_networkx(G, weight) or _graph_has_explicit_nonunit_weight(G, weight):
        kwargs = {"weight": weight}
        if cutoff is not None:
            kwargs["cutoff"] = cutoff
        caller = (
            _call_networkx_for_dijkstra_parity
            if isinstance(weight, str)
            else _call_networkx_for_parity
        )
        yield from caller("all_pairs_dijkstra", G, **kwargs)
        return
    if cutoff is not None:
        for node in G:
            yield (node, single_source_dijkstra(G, node, cutoff=cutoff, weight=weight))
        return
    _graph_has_nonunit_weight(G, weight)
    # br-r37-c1-sk5be: iterate outer keys in node-insertion order
    # matching nx (Rust dict yields in arbitrary order).
    raw = _raw_all_pairs_dijkstra(G, weight=weight)
    for node in G.nodes():
        if node in raw:
            # raw[node] is (dists, paths) already in nx's Dijkstra finalize
            # (heap-pop) order. br-r37-c1-k9q6q: a stable sort by distance
            # preserves the push-seq tie-break the kernel encodes; the old
            # BFS-hop tiebreak diverged from nx on equal-distance nodes.
            dists, paths = raw[node]
            d_dict = dict(dists)
            order = _reorder_by_distance(d_dict)
            ordered_dists = {k: dists[k] for k in order if k in dists}
            ordered_paths = {k: paths[k] for k in order if k in paths}
            yield (node, (ordered_dists, ordered_paths))

