def _ancestors_descendants_missing_node_msg(G, source):
    kind = "digraph" if G.is_directed() else "graph"
    return f"The node {source} is not in the {kind}."


def ancestors(G, source):
    """Return all nodes having a path to ``source`` in ``G``.

    Matches nx (br-7f0fn): accepts undirected and multigraph inputs as
    well as DiGraph, returning all nodes in the connected / reachable
    set (excluding ``source`` itself). Raises NetworkXError if source
    isn't in G (message distinguishes graph vs digraph). Returns a
    plain ``set`` (not ``frozenset``).

    br-r37-c1-i9whv: hash check up front for nx parity on unhashable
    inputs (TypeError, not NetworkXError).
    """
    # br-r37-c1-eghxq: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    hash(source)
    if source not in G:
        raise NetworkXError(_ancestors_descendants_missing_node_msg(G, source))
    # br-r37-c1-descbfs: native kernel handles undirected (component BFS) and
    # directed (predecessor reachability) — see algorithms.rs::ancestors. The
    # previous undirected Python BFS over G[n] paid the per-neighbor PyO3 tax.
    # Returns a plain set (order-invariant) matching nx.
    return set(_raw_ancestors(G, source))


def descendants(G, source):
    """Return all nodes reachable from ``source`` in ``G``.

    Matches nx (br-7f0fn): on undirected / multigraph, returns the
    reachable node set (symmetric with ``ancestors``). Returns a
    plain ``set``.

    br-r37-c1-i9whv: hash check up front for nx parity.
    """
    # br-r37-c1-eghxq: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    hash(source)
    if source not in G:
        raise NetworkXError(_ancestors_descendants_missing_node_msg(G, source))
    # br-r37-c1-descbfs: the native kernel handles BOTH directed (successor
    # reachability) and undirected (component BFS via bfs_edges) — see
    # algorithms.rs::descendants. The previous undirected branch ran a Python
    # BFS over the lazy AtlasView (per-neighbor PyO3 tax, ~5x slower than nx);
    # route it through the native kernel too. Returns a plain set (order-
    # invariant) matching nx.
    return set(_raw_descendants(G, source))


def topological_sort(G):
    """Yield nodes in topological order.

    Matches nx's Kahn's-algorithm tie-break order: zero-in-degree nodes
    are queued in graph insertion order (br-codtrav). The Rust native
    uses a different tie-break, so we re-implement Kahn's in Python so
    the emitted order is byte-identical to nx's on DAG fixtures.

    Raises ``NetworkXUnfeasible`` on a cyclic graph for nx parity
    (br-zzcm7).
    """
    if not G.is_directed():
        raise NetworkXError("Topological sort not defined on undirected graphs.")
    from collections import deque as _deque

    # br-r37-c1-toposucc: walk the successor adjacency (``G.succ[u].items()``)
    # directly instead of ``G.edges(u)`` per node. ``G.edges(u)`` materialised a
    # full guarded _EdgeListWithSetAlgebra (nbunch_iter + per-call view churn)
    # for every popped node, making topological_sort ~34x slower than nx; the
    # adjacency walk is the same primitive nx uses and is O(out-degree) per node.
    # Parallel edges are counted via ``len(keydict)`` for MultiDiGraph parity
    # (a single successor with k parallel edges contributes k to in-degree, and
    # the same FIFO queue/insertion-order tie-break is preserved exactly).
    succ = G.succ
    indegree = {v: 0 for v in G}
    if G.is_multigraph():
        # MultiDiGraph: a successor with k parallel edges contributes k.
        for u in G:
            for v, keydict in succ[u].items():
                indegree[v] += len(keydict)
        queue = _deque(v for v in G if indegree[v] == 0)
        _count = 0
        while queue:
            u = queue.popleft()
            yield u
            _count += 1
            for v, keydict in succ[u].items():
                indegree[v] -= len(keydict)
                if indegree[v] == 0:
                    queue.append(v)
    else:
        # DiGraph: pull the whole (node, [successor]) map in ONE native call,
        # then run Kahn's over O(1) dict lookups — no per-node ``succ[u]``
        # AtlasView getitem. Gate on EXACT class identity (filtered views
        # subclass DiGraph but keep an empty native inner); fall back to a
        # successor-KEY walk otherwise. Same node/adjacency order => exact
        # FIFO insertion-order tie-break.
        nak = getattr(G, "_native_adjacency_keys", None)
        if nak is not None and type(G) is DiGraph:
            succ_map = dict(nak())
            indegree = {v: 0 for v in G}
            for _succs in succ_map.values():
                for v in _succs:
                    indegree[v] += 1
            queue = _deque(v for v in G if indegree[v] == 0)
            _count = 0
            while queue:
                u = queue.popleft()
                yield u
                _count += 1
                for v in succ_map[u]:
                    indegree[v] -= 1
                    if indegree[v] == 0:
                        queue.append(v)
        else:
            for u in G:
                for v in succ[u]:
                    indegree[v] += 1
            queue = _deque(v for v in G if indegree[v] == 0)
            _count = 0
            while queue:
                u = queue.popleft()
                yield u
                _count += 1
                for v in succ[u]:
                    indegree[v] -= 1
                    if indegree[v] == 0:
                        queue.append(v)
    if _count != len(G):
        raise NetworkXUnfeasible(
            "Graph contains a cycle or graph changed during iteration"
        )




def topological_generations(G):
    """Yield per-generation sets of nodes in topological order.

    Raises ``NetworkXUnfeasible`` on a cyclic graph for nx parity
    (br-zzcm7).
    """
    G = _coerce_arg_to_fnx_graph(G)
    try:
        yield from _raw_topological_generations(G)
    except HasACycle as exc:
        raise NetworkXUnfeasible(
            "Graph contains a cycle or graph changed during iteration"
        ) from exc
    except NetworkXError as exc:
        # br-r37-c1-1ewpw: nx uses "Topological sort not defined on
        # undirected graphs." for both topological_sort AND
        # topological_generations. The Rust binding uses
        # "Topological generations not defined ...". Translate so
        # drop-in code matching the message text works.
        if "Topological generations not defined" in str(exc):
            raise NetworkXError(
                "Topological sort not defined on undirected graphs."
            ) from exc
        raise


def _dag_longest_path_digraph_native(G, weight, default_weight):
    topo_pred_snapshot = getattr(G, "_native_dag_topo_pred_data_key", None)
    if topo_pred_snapshot is not None:
        topo_order, pred_groups = topo_pred_snapshot(weight, default_weight)
    else:
        topo_order = list(topological_sort(G))
        pred_map = {node: [] for node in topo_order}
        for u, v, edge_weight in G._native_in_edges_data_key(weight, default_weight):
            pred_map[v].append((u, edge_weight))
        pred_groups = [pred_map[node] for node in topo_order]

    dist = {}
    for v, preds in zip(topo_order, pred_groups):
        if preds:
            pred_iter = iter(preds)
            u, edge_weight = next(pred_iter)
            best_len = dist[u][0] + edge_weight
            maxu = (best_len, u)
            for u, edge_weight in pred_iter:
                candidate_len = dist[u][0] + edge_weight
                if candidate_len > best_len:
                    best_len = candidate_len
                    maxu = (candidate_len, u)
        else:
            maxu = (0, v)
        dist[v] = maxu if maxu[0] >= 0 else (0, v)

    u = None
    v = max(dist, key=lambda x: dist[x][0])
    path = []
    while u != v:
        path.append(v)
        u = v
        v = dist[v][1]
    path.reverse()
    return path


def dag_longest_path(G, weight="weight", default_weight=1, topo_order=None):
    """Return the longest path in a DAG.

    Parameters
    ----------
    G : DiGraph
        A directed acyclic graph (DAG).
    weight : str, optional
        Edge attribute name to use for weights. Default is 'weight'.
    default_weight : int, optional
        Default weight for edges without the weight attribute. Default is 1.
    topo_order : iterable, optional
        Precomputed topological order of the nodes.

    Returns
    -------
    list
        The longest path as a list of nodes.

    br-r37-c1-sn6tm: nx's algorithm is tie-break-sensitive — it picks
    the FIRST predecessor by iteration order when two paths have equal
    length (``max(us, key=lambda x: x[0])`` returns the first max).
    Previously we delegated to nx via ``_call_networkx_for_parity``
    which converts through ``_fnx_to_nx``; that conversion emits edges
    in per-node adj iteration order (``_topo_emit_edges_by_adj``),
    which does NOT preserve the ``pred[v]`` insertion order users
    actually built. nx then saw a different tie-break and returned a
    different (but equally valid) longest path. Implementing the
    algorithm directly on fnx's native ``G.pred[v]`` view sidesteps the
    conversion loss and reproduces nx semantics exactly.
    """
    if not G.is_directed():
        raise NetworkXNotImplemented(
            "not implemented for undirected type"
        )
    if len(G) == 0:
        return []

    if topo_order is None and type(G) is DiGraph:
        native_in_edges = getattr(G, "_native_in_edges_data_key", None)
        if native_in_edges is not None:
            return _dag_longest_path_digraph_native(
                G, weight, default_weight
            )

    if topo_order is None:
        topo_order = topological_sort(G)

    is_multi = G.is_multigraph()
    dist = {}  # {v: (length, u)}
    for v in topo_order:
        us = []
        pred_items = G.pred[v].items()
        for u, data in pred_items:
            if is_multi:
                # Pick the heaviest parallel edge between u and v.
                edge_weight = max(
                    (
                        attrs.get(weight, default_weight)
                        if isinstance(attrs, dict)
                        else default_weight
                        for attrs in data.values()
                    ),
                    default=default_weight,
                )
            else:
                edge_weight = (
                    data.get(weight, default_weight)
                    if isinstance(data, dict)
                    else default_weight
                )
            us.append((dist[u][0] + edge_weight, u))
        # nx's tie-break: max with key=x[0] returns the FIRST element
        # with the max first component (Python's max stability).
        maxu = max(us, key=lambda x: x[0]) if us else (0, v)
        dist[v] = maxu if maxu[0] >= 0 else (0, v)

    u = None
    v = max(dist, key=lambda x: dist[x][0])
    path = []
    while u != v:
        path.append(v)
        u = v
        v = dist[v][1]
    path.reverse()
    return path


def dag_longest_path_length(G, weight="weight", default_weight=1):
    """Return the length of the longest path in a DAG.

    Parameters
    ----------
    G : DiGraph
        A directed acyclic graph (DAG).
    weight : str, optional
        Edge attribute name to use for weights. Default is 'weight'.
    default_weight : int, optional
        Default weight for edges without the weight attribute. Default is 1.

    Returns
    -------
    int
        The length of the longest path.

    br-daglongundir: nx is @not_implemented_for('undirected') and
    raises NetworkXNotImplemented('not implemented for undirected type').
    Gate on G.is_directed() so the exception class matches.

    br-r37-c1-jwa0g: the length is computed from the (pure-Python,
    weight-correct) ``dag_longest_path`` result by summing edge weights
    via Python ``G[u][v]`` access — exactly nx's algorithm.  The Rust
    ``_fnx.dag_longest_path_length`` fast path was dropped: its
    ``edge_attrs()`` reader is blind to weights stored by
    ``add_weighted_edges_from`` or post-creation ``G[u][v][w]=...``
    mutation (Rust attr-sync gap, br-r37-c1-7s20o), so it silently
    returned the hop count for such graphs.  Summing from an integer
    ``0`` also makes int/float return-type preservation natural —
    sum-of-ints stays int — matching nx without any restoration logic.
    The cyclic-graph error contract is inherited from
    ``dag_longest_path`` -> ``topological_sort`` (NetworkXUnfeasible,
    "Graph contains a cycle or graph changed during iteration").
    """
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")
    path = dag_longest_path(
        G, weight=weight, default_weight=default_weight
    )
    path_length = 0
    if G.is_multigraph():
        for u, v in zip(path, path[1:]):
            keydict = G[u][v]
            heaviest = max(
                keydict,
                key=lambda k: keydict[k].get(weight, default_weight),
            )
            path_length += keydict[heaviest].get(weight, default_weight)
    else:
        for u, v in zip(path, path[1:]):
            path_length += G[u][v].get(weight, default_weight)
    return path_length

