def _pagerank_needs_networkx_weight_parity(G, weight):
    if weight is None:
        return False

    # br-r37-c1-s0tno: route the scan through a native O(|E|) Rust
    # helper for simple Graph/DiGraph. The previous Python iteration
    # over G.edges() cost ~40 ms on BA5000 — it was the entire fnx
    # vs nx pagerank-wrapper gap (the Rust algorithm is already at
    # parity with nx). Native helper returns None for multigraphs;
    # fall back to the Python scan there so per-key parallel-edge
    # attrs are inspected correctly.
    if _native_has_nonfinite_edge_weight is not None and not G.is_multigraph():
        try:
            native = _native_has_nonfinite_edge_weight(G, weight)
        except Exception:
            native = None
        if native is not None:
            return bool(native)

    edges = G.edges(keys=True, data=True) if G.is_multigraph() else G.edges(data=True)
    for edge in edges:
        attrs = edge[-1]
        if weight not in attrs:
            continue
        try:
            value = float(attrs[weight])
        except (TypeError, ValueError, OverflowError):
            return True
        if not _math.isfinite(value):
            return True
    return False


def _pagerank_scipy(G, alpha, max_iter, tol, weight):
    """scipy.sparse-backed PageRank power iteration.

    br-r37-c1-y5y7i: matches nx's _pagerank_scipy for the simple case
    (no personalization/nstart/dangling). Uses BLAS-backed matvec
    instead of pure-Rust scalar iteration — 2-3× faster on dense graphs.
    """
    import numpy as np
    import scipy.sparse as sp

    N = len(G)
    if N == 0:
        return {}

    nodelist = list(G)
    # br-r37-c1-raqel: build COO directly for pagerank to skip dtype
    # checks in to_scipy_sparse_array. Native path returns (rows, cols, data).
    if (
        _native_adjacency_arrays is not None
        and not G.is_multigraph()
        and (weight is None or isinstance(weight, str))
    ):
        native_weight = weight if isinstance(weight, str) else None
        native_result = None
        native_index_used = False
        if native_weight is None and _native_adjacency_index_arrays is not None:
            native_index_result = _native_adjacency_index_arrays(G, nodelist, None)
            if native_index_result is not None:
                rows, cols = native_index_result
                rows = np.asarray(rows, dtype=np.intp)
                cols = np.asarray(cols, dtype=np.intp)
                data = np.ones(len(rows), dtype=float)
                A = sp.coo_array(
                    (data, (rows, cols)), shape=(N, N), dtype=float
                ).tocsr()
                native_index_used = True
            else:
                native_result = _native_adjacency_arrays(G, nodelist, native_weight, 1.0)
        else:
            native_result = _native_adjacency_arrays(G, nodelist, native_weight, 1.0)
        if native_result is not None:
            rows, cols, data = native_result
            A = sp.coo_array(
                (data, (rows, cols)), shape=(N, N), dtype=float
            ).tocsr()
        elif not native_index_used:
            A = to_scipy_sparse_array(G, nodelist=nodelist, weight=weight, dtype=float)
    else:
        A = to_scipy_sparse_array(G, nodelist=nodelist, weight=weight, dtype=float)
    S = np.asarray(A.sum(axis=1)).flatten()
    S[S != 0] = 1.0 / S[S != 0]
    Q = sp.dia_array((S, 0), shape=A.shape).tocsr()
    A = Q @ A

    x = np.full(N, 1.0 / N)
    p = np.full(N, 1.0 / N)
    is_dangling = np.where(S == 0)[0]

    for _ in range(max_iter):
        xlast = x
        x = alpha * (x @ A + x[is_dangling].sum() * p) + (1 - alpha) * p
        err = np.abs(x - xlast).sum()
        if err < N * tol:
            return dict(zip(nodelist, map(float, x)))
    raise PowerIterationFailedConvergence(max_iter)


def pagerank(
    G,
    alpha=0.85,
    personalization=None,
    max_iter=100,
    tol=1.0e-6,
    nstart=None,
    weight="weight",
    dangling=None,
    *,
    backend=None,
    **backend_kwargs,
):
    """Return the PageRank of the nodes in graph ``G``."""
    _validate_backend_dispatch_keywords("pagerank", backend, backend_kwargs)
    # br-r37-c1-y77dc: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)

    # br-r37-c1-pyo3prefix: the Rust binding declares ``max_iter`` as
    # an unsigned int and rejects floats with ``TypeError: argument
    # 'max_iter': 'float' object cannot be interpreted as an
    # integer``.  nx raises the same TypeError via ``range(max_iter)``
    # but *without* the ``argument 'max_iter':`` prefix.  Pre-validate
    # in Python so drop-in callers regex-matching nx's wording match.
    max_iter = _coerce_index_arg(max_iter, "max_iter")

    # The Rust pagerank honours the ``weight`` attribute and matches nx
    # within 1e-16 on non-negative weights. Try the fast-path whenever
    # the unsupported kwargs (personalization / nstart / dangling) are
    # absent; the Rust impl raises NetworkXNotImplemented if it detects
    # negative edge weights (numerically unstable for power iteration),
    # and we fall through to the pure-Python path in that case. Non-string
    # hashable weight keys also stay on the Python path because the PyO3
    # binding accepts only str/None.
    pagerank_weight = weight
    if (
        isinstance(weight, str)
        and _native_has_edge_attr is not None
        and not G.is_multigraph()
        and isinstance(G, (Graph, DiGraph))
    ):
        try:
            native_has_attr = _native_has_edge_attr(G, weight)
        except Exception:
            native_has_attr = None
        if native_has_attr is False:
            pagerank_weight = None

    # br-gauntlet-pagerank-sync: pagerank reads edge weights from the Rust
    # ``inner`` adjacency via native helpers (``_native_has_nonfinite_edge_weight``
    # in the parity scan and ``_native_adjacency_arrays`` in ``_pagerank_scipy``).
    # A post-construction mutation such as ``G.edges[u, v]["weight"] = w`` only
    # updates the Python-side attribute dict, leaving ``inner`` stale, so the
    # native scan/matvec silently ignore the new weights (observable bug: fnx
    # returned the *unweighted* PageRank while nx returned the weighted one).
    # Push Python attrs down only when a real string weight attr can be read.
    if isinstance(pagerank_weight, str):
        _sync_rust_edge_attrs(G)

    if (
        personalization is None
        and nstart is None
        and dangling is None
        and (pagerank_weight is None or isinstance(pagerank_weight, str))
    ):
        if _pagerank_needs_networkx_weight_parity(G, pagerank_weight):
            return _call_networkx_for_parity(
                "pagerank",
                G,
                alpha=alpha,
                personalization=None,
                max_iter=max_iter,
                tol=tol,
                nstart=None,
                weight=pagerank_weight,
                dangling=None,
            )
        # br-r37-c1-y5y7i: use scipy.sparse matvec for 2-3× speedup
        # over pure-Rust scalar iteration on dense graphs.
        return _pagerank_scipy(G, alpha, max_iter, tol, pagerank_weight)

    if len(G) == 0:
        return {}

    directed_graph = G.to_directed()
    nodes = list(directed_graph)
    node_count = len(nodes)

    if nstart is None:
        current = dict.fromkeys(nodes, 1.0 / node_count)
    else:
        current = _normalize_pagerank_vector(nstart, nodes, zero_sum="nan")

    if personalization is None:
        personalization_vector = dict.fromkeys(nodes, 1.0 / node_count)
    else:
        personalization_vector = _normalize_pagerank_vector(personalization, nodes)

    if dangling is None:
        dangling_weights = personalization_vector
    else:
        dangling_weights = _normalize_pagerank_vector(dangling, nodes, zero_sum="nan")

    transition_weights = {}
    dangling_nodes = []
    for node in nodes:
        neighbor_weights = _pagerank_outgoing_weights(directed_graph, node, weight)
        total_weight = _math.fsum(neighbor_weights.values())
        if total_weight == 0:
            transition_weights[node] = None
            dangling_nodes.append(node)
            continue
        transition_weights[node] = {
            nbr: neighbor_weight / total_weight
            for nbr, neighbor_weight in neighbor_weights.items()
        }

    for _ in range(max_iter):
        previous = current
        current = dict.fromkeys(nodes, 0.0)
        dangling_sum = alpha * _math.fsum(previous[node] for node in dangling_nodes)

        for node in nodes:
            neighbor_weights = transition_weights[node]
            if not neighbor_weights:
                continue
            scaled_rank = alpha * previous[node]
            for nbr, neighbor_weight in neighbor_weights.items():
                current[nbr] += scaled_rank * neighbor_weight

        for node in nodes:
            current[node] += (
                dangling_sum * dangling_weights.get(node, 0)
                + (1.0 - alpha) * personalization_vector.get(node, 0)
            )

        error = _math.fsum(abs(current[node] - previous[node]) for node in nodes)
        if error < node_count * tol:
            return current

    raise PowerIterationFailedConvergence(max_iter)


def closeness_centrality(
    G,
    u=None,
    distance=None,
    wf_improved=True,
    *,
    backend=None,
    **backend_kwargs,
):
    """Compute closeness centrality for nodes.

    Parameters
    ----------
    G : graph
        A NetworkX graph.
    u : node, optional
        Return only the value for node u.
    distance : edge attribute key, optional
        Use the specified edge attribute as the edge distance.
    wf_improved : bool, optional (default=True)
        If True, use Wasserman-Faust improved formula for disconnected graphs.

    Returns
    -------
    dict or float
        Dictionary of nodes with closeness centrality as value, or a single
        float if u is specified.
    """
    _validate_backend_dispatch_keywords("closeness_centrality", backend, backend_kwargs)
    # br-r37-c1-y77dc: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)

    # br-r37-c1-clsingle: a single-node request (u=...) on the standard
    # unweighted, wf_improved, undirected path previously delegated to networkx,
    # which paid a full fnx->nx graph conversion (O(V+E)) just to run one BFS --
    # ~25x SLOWER than nx for one node on n=1500. Compute the single BFS from u
    # directly instead. The total path length is a sum of INTEGER hop counts, so
    # the result is byte-identical to nx (and to _raw_closeness_centrality[u]).
    if (
        u is not None
        and distance is None
        and wf_improved
        and not G.is_directed()
        and u in G
    ):
        sp = single_source_shortest_path_length(G, u)
        totsp = sum(sp.values())
        len_G = len(G)
        closeness = 0.0
        if totsp > 0.0 and len_G > 1:
            closeness = (len(sp) - 1.0) / totsp
            closeness *= (len(sp) - 1.0) / (len_G - 1)
        return closeness

    # Delegate to NetworkX for unsupported parameters
    if u is not None or distance is not None or not wf_improved:
        return _call_networkx_for_parity(
            "closeness_centrality",
            G,
            u=u,
            distance=distance,
            wf_improved=wf_improved,
        )
    # Use fast Rust implementation for standard case
    return _raw_closeness_centrality(G)


def edge_betweenness_centrality(
    G,
    k=None,
    normalized=True,
    weight=None,
    seed=None,
    *,
    backend=None,
    **backend_kwargs,
):
    """Compute edge betweenness centrality for edges.

    Parameters
    ----------
    G : graph
        A NetworkX graph.
    k : int, optional
        Number of nodes to sample for approximation.
    normalized : bool, optional (default=True)
        If True, normalize by 2/(n(n-1)) for undirected or 1/(n(n-1)) for directed.
    weight : edge attribute key, optional
        Use the specified edge attribute as edge weight.
    seed : random state, optional
        Random seed for sampling when k is specified.

    Returns
    -------
    dict
        Dictionary of edges with betweenness centrality as value.
    """
    G = _coerce_arg_to_fnx_graph(G)
    _validate_backend_dispatch_keywords(
        "edge_betweenness_centrality", backend, backend_kwargs
    )

    # Delegate to NetworkX for unsupported parameters
    if k is not None or not normalized or weight is not None or seed is not None:
        return _call_networkx_for_parity(
            "edge_betweenness_centrality",
            G,
            k=k,
            normalized=normalized,
            weight=weight,
            seed=seed,
        )
    # br-gauntlet-ebc-multi: nx keys multigraph edge-betweenness by
    # ``(u, v, key)`` 3-tuples and computes a separate value per parallel
    # edge; the native ``_raw_edge_betweenness_centrality`` kernel collapses
    # parallel edges to a single ``(u, v)`` 2-tuple, losing both the key
    # dimension and the per-edge values. Delegate multigraphs to nx so the
    # key shape and values match the reference.
    if G.is_multigraph():
        return _call_networkx_for_parity(
            "edge_betweenness_centrality",
            G,
            k=k,
            normalized=normalized,
            weight=weight,
            seed=seed,
        )
    # Use fast Rust implementation for standard case, then re-key the
    # dict in G.edges() iteration order to match nx's contract.
    # br-r37-c1-pi615: the Rust dict had keys in canonical (smaller-
    # first) edge order, but nx returns keys in G.edges() traversal
    # order with the tuple direction nx encountered. Values are
    # identical — only the dict key shape needed alignment.
    raw = _raw_edge_betweenness_centrality(G)
    reordered = {}
    for u, v in G.edges():
        if (u, v) in raw:
            reordered[(u, v)] = raw[(u, v)]
        elif (v, u) in raw:
            reordered[(u, v)] = raw[(v, u)]
    return reordered


def katz_centrality(
    G,
    alpha=0.1,
    beta=1.0,
    max_iter=1000,
    tol=1.0e-6,
    nstart=None,
    normalized=True,
    weight=None,
    *,
    backend=None,
    **backend_kwargs,
):
    """Compute Katz centrality for nodes.

    Parameters
    ----------
    G : graph
        A NetworkX graph.
    alpha : float, optional (default=0.1)
        Attenuation factor.
    beta : float or dict, optional (default=1.0)
        Weight attributed to immediate neighborhood.
    max_iter : int, optional (default=1000)
        Maximum iterations for power iteration.
    tol : float, optional (default=1e-6)
        Convergence tolerance.
    nstart : dict, optional
        Starting value of centrality for each node.
    normalized : bool, optional (default=True)
        If True, normalize values.
    weight : edge attribute key, optional
        Use the specified edge attribute as edge weight.

    Returns
    -------
    dict
        Dictionary of nodes with Katz centrality as value.
    """
    _validate_backend_dispatch_keywords("katz_centrality", backend, backend_kwargs)
    # br-r37-c1-y77dc: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)

    # br-r37-c1-tqimg: nx is decorated with
    # @not_implemented_for('multigraph'); fnx silently accepted MG.
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")

    # Delegate to NetworkX when non-default parameters are used
    if (
        alpha != 0.1
        or beta != 1.0
        or max_iter != 1000
        or tol != 1.0e-6
        or nstart is not None
        or not normalized
        or weight is not None
    ):
        return _call_networkx_for_parity(
            "katz_centrality",
            G,
            alpha=alpha,
            beta=beta,
            max_iter=max_iter,
            tol=tol,
            nstart=nstart,
            normalized=normalized,
            weight=weight,
        )
    # Use fast Rust implementation for standard case.
    # br-r37-c1-hc209: the binary install can lag behind the source change in
    # crates/fnx-python/src/algorithms.rs that passes ``err.iterations`` (int)
    # into ``PowerIterationFailedConvergence::new_err``. Older binaries
    # passed a pre-formatted message string, which nx's exception class then
    # double-formats. Catch and re-raise with the canonical helper so str(exc)
    # / args parity holds regardless of binary state.
    try:
        return _raw_katz_centrality(G)
    except PowerIterationFailedConvergence as exc:
        # Rust's max_iter is the same default as the Python wrapper.
        raise _make_power_iteration_failed_convergence(max_iter) from exc.__cause__


def _make_power_iteration_failed_convergence(max_iter):
    error = PowerIterationFailedConvergence.__new__(PowerIterationFailedConvergence)
    Exception.__init__(
        error,
        error,
        f"power iteration failed to converge within {max_iter} iterations",
    )
    return error


def hits(
    G,
    max_iter=100,
    tol=1.0e-8,
    nstart=None,
    normalized=True,
    *,
    backend=None,
    **backend_kwargs,
):
    """Return HITS hubs and authorities values for nodes.

    br-hitsdelta: on karate_club_graph the values diverge from nx by
    ~1.6%, but experiments show the cause is karate_club_graph's
    edge-insertion-order mismatch (fnx's karate differs from nx's in
    node/edge ordering, affecting the SVD initial basis). On
    order-aligned graphs (explicit add_edge sequences) fnx.hits
    matches nx at machine precision. A full fix requires aligning
    fnx's karate_club_graph output exactly with nx. Queued as
    br-karateorder.
    """
    _validate_backend_dispatch_keywords("hits", backend, backend_kwargs)

    import numpy as np
    import scipy as sp

    if len(G) == 0:
        return {}, {}

    A = adjacency_matrix(G, nodelist=list(G), dtype=float)

    if nstart is not None:
        nstart = np.array(list(nstart.values()))
    if max_iter <= 0:
        raise _make_power_iteration_failed_convergence(max_iter)

    try:
        _, _, vt = sp.sparse.linalg.svds(A, k=1, v0=nstart, maxiter=max_iter, tol=tol)
    except sp.sparse.linalg.ArpackNoConvergence as exc:
        raise _make_power_iteration_failed_convergence(max_iter) from exc

    authorities = vt.flatten().real
    hubs = A @ authorities
    if normalized:
        hubs /= hubs.sum()
        authorities /= authorities.sum()

    return (
        dict(zip(G, map(float, hubs))),
        dict(zip(G, map(float, authorities))),
    )


# ---------------------------------------------------------------------------
# Graph structural algorithms — pure Python over Rust primitives
# ---------------------------------------------------------------------------


def ego_graph(G, n, radius=1, center=True, undirected=False, distance=None):
    """Return the ego graph of node *n* within *radius* hops.

    br-egoedgeord: always compute the node set in Python and copy
    edges in G's original insertion order. The Rust fast-path
    ``_fnx.ego_graph_rust`` re-orients every edge with the ego node
    first (so ``(2, 1), (2, 3)`` instead of ``(1, 2), (2, 3)`` on
    ``fnx.path_graph(5)``), diverging from nx which preserves the
    input graph's edge orientation.
    """
    # br-r37-c1-egonotfound: nx delegates to
    # single_source_shortest_path_length / single_source_dijkstra,
    # both of which raise NodeNotFound("Source %s is not in G") on
    # missing source — not the NetworkXError that fnx surfaced via
    # G.neighbors(n).  Mirror nx's exception class and message.
    if n not in G:
        raise NodeNotFound(f"Source {n} is not in G")
    # br-r37-c1-egonan: NaN / +inf radius — nx routes through
    # single_source_shortest_path_length which short-circuits NaN
    # cutoff to source-only (matches the cycle 142 fix on the
    # Dijkstra cutoff family).  fnx's BFS uses ``depth >= radius``
    # which is False for NaN, so iteration never terminates the
    # depth check and yields the full reachable component.  Coerce
    # NaN to ``-1`` (so the immediate first ``depth >= radius``
    # check at depth 0 succeeds and only the source node is kept).
    import math as _math
    if isinstance(radius, float) and _math.isnan(radius):
        radius = -1
    # br-r37-c1-fauol: track BFS visit order (insertion order in
    # ``seen``) so the resulting ego graph's node order matches nx's
    # BFS-from-source ordering. Previously we collapsed to a set and
    # iterated arbitrary hash order.
    if distance is not None:
        # Weighted ego: include nodes within weighted distance <= radius.
        sp = dict(single_source_dijkstra_path_length(G, n, weight=distance))
        sp = {node: dist for node, dist in sp.items() if dist <= radius}
        ordered_nodes = list(sp.keys())  # already in distance order
        nodes_within = set(ordered_nodes)
    elif undirected and G.is_directed():
        # Treat directed graph as undirected for BFS.
        seen = {n: 0}
        queue = [n]
        while queue:
            next_queue = []
            for u in queue:
                depth = seen[u]
                if depth >= radius:
                    continue
                for v in G.successors(u):
                    if v not in seen:
                        seen[v] = depth + 1
                        next_queue.append(v)
                for v in G.predecessors(u):
                    if v not in seen:
                        seen[v] = depth + 1
                        next_queue.append(v)
            queue = next_queue
        ordered_nodes = list(seen.keys())
        nodes_within = set(ordered_nodes)
    else:
        # Plain BFS (directed or undirected) honouring radius.
        seen = {n: 0}
        queue = [n]
        while queue:
            next_queue = []
            for u in queue:
                depth = seen[u]
                if depth >= radius:
                    continue
                neighbors = (
                    G.successors(u) if G.is_directed() else G.neighbors(u)
                )
                for v in neighbors:
                    if v not in seen:
                        seen[v] = depth + 1
                        next_queue.append(v)
            queue = next_queue
        ordered_nodes = list(seen.keys())
        nodes_within = set(ordered_nodes)

    # br-r37-c1-fauol: nx.ego_graph uses G.subgraph(sp).copy(), which
    # iterates the result in G's original insertion order (filtered to
    # nodes_within). Match that contract instead of BFS-visit order.
    ordered_nodes = [node for node in G.nodes() if node in nodes_within]

    # br-r37-c1-s8w2p: SubgraphView class can't be empty-constructed.
    graph = _concrete_class_for(G)()
    graph.graph.update(dict(G.graph))
    for node in ordered_nodes:
        graph.add_node(node, **dict(G.nodes[node]))
    if G.is_multigraph():
        for u, v, key, data in G.edges(keys=True, data=True):
            if u in nodes_within and v in nodes_within:
                graph.add_edge(u, v, key=key, **data)
    else:
        # br-r37-c1-js9iw: walk ONLY the ego nodes' adjacency (O(E_subgraph))
        # instead of materializing every edge in G (O(E_total)) and filtering.
        # Reproduces networkx's subgraph(nodes).copy() edge order exactly:
        # iterate subgraph nodes in G's node order, and for each its adjacency
        # order; undirected edges dedup via a `seen` set so each edge is emitted
        # from the node encountered first (matching nx's EdgeView contract).
        directed = G.is_directed()
        edges_to_add = []
        seen = set()
        for u in ordered_nodes:
            adj_u = G[u]
            for v in adj_u:
                if v not in nodes_within:
                    continue
                if not directed and v in seen:
                    continue
                data = adj_u[v]
                if data:
                    for attr_key in data:
                        if not isinstance(attr_key, str):
                            graph.add_edge(u, v, **data)
                            break
                    else:
                        edges_to_add.append((u, v, data))
                else:
                    edges_to_add.append((u, v))
            if not directed:
                seen.add(u)
        if edges_to_add:
            raw_add_edges_from = (
                _DIGRAPH_RAW_ADD_EDGES_FROM
                if graph.is_directed()
                else _GRAPH_RAW_ADD_EDGES_FROM
            )
            raw_add_edges_from(graph, edges_to_add)
    if not center and n in graph:
        graph.remove_node(n)
    # Always return fnx type for consistency.
    return graph


def core_number(G):
    """Return the core number for each node of ``G``.

    br-coremg: nx.core_number is @not_implemented_for('multigraph',
    'directed_multigraph') and raises NetworkXNotImplemented for any
    multigraph input (and has a self-loop guard). The Rust Rust
    core_number accepted MultiGraph input silently. Gate upfront.

    br-r37-c1-dg2dn: nx also raises NetworkXNotImplemented when the
    graph has any self-loop ("Input graph has self loops which is
    not permitted; Consider using G.remove_edges_from(nx.selfloop_edges(G)).").
    The Rust path silently included self-loops in the degree _count
    and returned a value dict — propagating into k_core / k_shell /
    k_crust / k_corona, which all consume core_number.

    br-coredir: NetworkX's directed contract (per the docstring:
    "For directed graphs the node degree is defined to be the
    in-degree + out-degree") counts both arcs of an antiparallel
    pair separately. The Rust ``_raw_core_number`` calls
    ``gr.undirected()`` and folds antiparallel edges together,
    producing core numbers half the size. Delegate the directed
    case to NX so the in+out degree _count matches.
    """
    # br-r37-c1-eghxq: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    # br-gauntlet-perf4: the prior ``any(G.has_edge(u, u) for u in G)`` probe
    # called the Python ``has_edge`` wrapper once per node; on graphs with
    # private attribute storage that wrapper takes a slow path
    # (``u not in self`` + ``self.adj[u]``) which chains into the NodeView
    # ``__iter__`` length-guard, so the "O(|V|)" guard ballooned to ~1.77s of a
    # 1.95s core_number call at n=20000. ``number_of_selfloops`` is a single
    # native O(|E|) pass over the adjacency. (Same NetworkXNotImplemented wording.)
    if number_of_selfloops(G) > 0:
        raise NetworkXNotImplemented(
            "Input graph has self loops which is not permitted; "
            "Consider using G.remove_edges_from(nx.selfloop_edges(G))."
        )
    if G.is_directed():
        return _call_networkx_for_parity("core_number", G)
    raw = _raw_core_number(G)
    # br-r37-c1-9fa26: the Rust binding returns the dict with keys
    # sorted; nx iterates in node-insertion order. Reorder so
    # ``for node, core in result.items():`` matches nx's contract.
    return {node: raw[node] for node in G if node in raw}  # br-gauntlet-perf4: `for node in G` (fast native Graph.__iter__) not `G.nodes()` (NodeView iterator is ~350x slower; identical order)


def _self_loop_guard_for_core_family():
    """br-r37-c1-dg2dn: shared self-loop guard message used by
    core_number / k_core / k_shell / k_crust / k_corona to match nx's
    NetworkXNotImplemented wording exactly.
    """
    return (
        "Input graph has self loops which is not permitted; "
        "Consider using G.remove_edges_from(nx.selfloop_edges(G))."
    )


def k_core(G, k=None, core_number=None):
    """Return the k-core of *G* (maximal subgraph with minimum degree >= k).

    br-coremg: same MG-rejection as core_number.
    br-r37-c1-dg2dn: also reject self-loop inputs (nx contract).
    br-r37-c1-cfcls: use fnx.subgraph to ensure fnx return type.
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if core_number is None:
        # br-coredir: route through the public wrapper so directed
        # graphs use NX's in+out degree _count instead of the Rust
        # binding's undirected collapse.
        # br-r37-c1-lczjd: core_number() runs the native O(|E|)
        # number_of_selfloops self-loop guard itself and raises the
        # identical NetworkXNotImplemented, so the redundant Python
        # ``any(u == v for u, v in G.edges())`` EdgeView pass (~86ms of
        # k_crust's 199ms at n=20000; already dropped from core_number
        # by br-gauntlet-perf4) is skipped here.
        core_number = globals()["core_number"](G)
    elif number_of_selfloops(G) > 0:
        # Caller supplied core_number, so core_number() never runs;
        # still reject self-loops per nx, via the native fast check.
        raise NetworkXNotImplemented(_self_loop_guard_for_core_family())
    if k is None:
        # br-r37-c1-kcore-empty: nx's _core_subgraph does
        # ``k = max(core.values())`` with no fallback — empty
        # graph raises ``ValueError("max() iterable argument is
        # empty")``.  fnx previously silently coerced to k=0,
        # masking the empty-input case.  Match nx's contract.
        k = max(core_number.values())
    nodes = [n for n, c in core_number.items() if c >= k]
    return subgraph(G, nodes)


def k_shell(G, k=None, core_number=None):
    """Return the k-shell of *G* (nodes with core number exactly k).

    br-r37-c1-dg2dn: reject self-loop inputs (nx contract).
    br-r37-c1-cfcls: use fnx.subgraph to ensure fnx return type.
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if core_number is None:
        # br-coredir: route through the public wrapper so directed
        # graphs use NX's in+out degree _count instead of the Rust
        # binding's undirected collapse.
        # br-r37-c1-lczjd: skip the redundant Python EdgeView self-loop
        # guard — core_number() raises the identical NetworkXNotImplemented
        # via the native number_of_selfloops check.
        core_number = globals()["core_number"](G)
    elif number_of_selfloops(G) > 0:
        # Caller supplied core_number, so core_number() never runs;
        # still reject self-loops per nx, via the native fast check.
        raise NetworkXNotImplemented(_self_loop_guard_for_core_family())
    if k is None:
        # br-r37-c1-kcore-empty: nx's _core_subgraph does
        # ``k = max(core.values())`` with no fallback — empty
        # graph raises ``ValueError("max() iterable argument is
        # empty")``.  fnx previously silently coerced to k=0,
        # masking the empty-input case.  Match nx's contract.
        k = max(core_number.values())
    nodes = [n for n, c in core_number.items() if c == k]
    return subgraph(G, nodes)


def k_crust(G, k=None, core_number=None):
    """Return the k-crust of *G* (nodes with core number <= k).

    br-r37-c1-dg2dn: reject self-loop inputs (nx contract).
    br-r37-c1-cfcls: use fnx.subgraph to ensure fnx return type.
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if core_number is None:
        # br-coredir: route through the public wrapper so directed
        # graphs use NX's in+out degree _count instead of the Rust
        # binding's undirected collapse.
        # br-r37-c1-lczjd: skip the redundant Python EdgeView self-loop
        # guard — core_number() raises the identical NetworkXNotImplemented
        # via the native number_of_selfloops check.
        core_number = globals()["core_number"](G)
    elif number_of_selfloops(G) > 0:
        # Caller supplied core_number, so core_number() never runs;
        # still reject self-loops per nx, via the native fast check.
        raise NetworkXNotImplemented(_self_loop_guard_for_core_family())
    if k is None:
        # br-r37-c1-qzdbg: nx's k_crust uses ``max(core.values())
        # - 1`` (one less than _core_subgraph's default), per the
        # explicit comment in nx source: "Default for k is one
        # less than in _core_subgraph, so just inline."  fnx
        # previously used the unmodified max, returning the full
        # graph as the "main crust" — wrong for every
        # non-trivial input.
        k = max(core_number.values()) - 1
    nodes = [n for n, c in core_number.items() if c <= k]
    return subgraph(G, nodes)


def k_corona(G, k, core_number=None):
    """Return the k-corona of *G* (k-core nodes with exactly k neighbors in k-core).

    br-r37-c1-dg2dn: reject self-loop inputs (nx contract).
    br-r37-c1-cfcls: use fnx.subgraph to ensure fnx return type.
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if core_number is None:
        # br-coredir: route through the public wrapper so directed
        # graphs use NX's in+out degree _count instead of the Rust
        # binding's undirected collapse.
        # br-r37-c1-lczjd: skip the redundant Python EdgeView self-loop
        # guard — core_number() raises the identical NetworkXNotImplemented
        # via the native number_of_selfloops check.
        core_number = globals()["core_number"](G)
    elif number_of_selfloops(G) > 0:
        # Caller supplied core_number, so core_number() never runs;
        # still reject self-loops per nx, via the native fast check.
        raise NetworkXNotImplemented(_self_loop_guard_for_core_family())
    core_nodes = {n for n, c in core_number.items() if c >= k}
    corona_nodes = []
    for n in core_nodes:
        if core_number[n] == k:
            nbrs_in_core = sum(1 for nb in G.neighbors(n) if nb in core_nodes)
            if nbrs_in_core == k:
                corona_nodes.append(n)
    return subgraph(G, corona_nodes)


def line_graph(G, create_using=None):
    """Return the line graph of *G*.

    The line graph L(G) has a node for each edge in G. Two nodes in L(G)
    are adjacent iff the corresponding edges in G share an endpoint.

    br-r37-c1-cfcls: Always use fnx type as default, not G.__class__.
    """
    graph = _empty_graph_from_create_using(create_using, default=_concrete_class_for(G))

    if G.is_directed():
        if G.is_multigraph():
            edge_iter = G.edges(keys=True)
        else:
            edge_iter = G.edges()

        for from_node in edge_iter:
            graph.add_node(from_node)
            head = from_node[1]
            if G.is_multigraph():
                for neighbor, keyed_attrs in G[head].items():
                    for key in keyed_attrs:
                        graph.add_edge(from_node, (head, neighbor, key))
            else:
                for neighbor in G[head]:
                    graph.add_edge(from_node, (head, neighbor))
        return graph

    node_index = {node: index for index, node in enumerate(G)}

    def canonical_edge(edge):
        return tuple(sorted(edge[:2], key=node_index.get)) + edge[2:]

    def edge_key(edge):
        return node_index[edge[0]], node_index[edge[1]]

    edges = set()
    for node in G:
        if G.is_multigraph():
            incident = [
                canonical_edge((node, neighbor, key))
                for neighbor, keyed_attrs in G[node].items()
                for key in keyed_attrs
            ]
        else:
            incident = [canonical_edge((node, neighbor)) for neighbor in G[node]]
        if len(incident) == 1:
            graph.add_node(incident[0])
        for index, left in enumerate(incident):
            for right in incident[index + 1 :]:
                edges.add(tuple(sorted((left, right), key=edge_key)))

    graph.add_edges_from(edges)
    return graph


def make_max_clique_graph(G, create_using=None):
    """Return the maximal-clique intersection graph of *G*.

    br-r37-c1-cfcls: Always use fnx type as default, not G.__class__.
    """
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    graph = _empty_graph_from_create_using(create_using, default=_concrete_class_for(G))
    cliques = list(find_cliques(G))
    for index in range(len(cliques)):
        graph.add_node(index)
    for left_index, left in enumerate(cliques):
        left_nodes = set(left)
        for right_index in range(left_index + 1, len(cliques)):
            if left_nodes & set(cliques[right_index]):
                graph.add_edge(left_index, right_index)
    return graph


def power(G, k):
    """Return the k-th power of *G*.

    The k-th power G^k has the same nodes as G. Two nodes u, v are
    adjacent in G^k iff their shortest path distance in G is <= k.
    """
    # br-r37-c1-9rd4z: accept nx-typed inputs.
    G = _coerce_arg_to_fnx_graph(G)
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if k <= 0:
        raise ValueError("k must be a positive integer")

    # br-r37-c1-s8w2p: materialize SubgraphView and use canonical class
    # to avoid the cycle-225-family TypeError. Both branches build the
    # output via G.__class__() which fails for views.
    G = _coerce_arg_to_fnx_graph(G)
    if isinstance(k, _numbers.Integral):
        raw_graph = _fnx.power_rust(G, int(k))
        canonical_to_node = {str(node): node for node in G.nodes()}

        graph = _concrete_class_for(G)()
        for raw_node in raw_graph.nodes():
            graph.add_node(canonical_to_node.get(raw_node, raw_node))
        for raw_u, raw_v in raw_graph.edges():
            graph.add_edge(
                canonical_to_node.get(raw_u, raw_u),
                canonical_to_node.get(raw_v, raw_v),
            )
        return graph

    graph = _concrete_class_for(G)()
    graph.add_nodes_from(G)
    for node in G:
        seen = {}
        level = 1
        nextlevel = G[node]
        while nextlevel:
            thislevel = nextlevel
            nextlevel = {}
            for neighbor in thislevel:
                if neighbor == node:
                    continue
                if neighbor not in seen:
                    seen[neighbor] = level
                    nextlevel.update(G[neighbor])
            if k <= level:
                break
            level += 1
        graph.add_edges_from((node, neighbor) for neighbor in seen)
    return graph


def disjoint_union(G, H):
    """Return the disjoint union of *G* and *H*."""
    return disjoint_union_all([G, H])


def _finalize_operator_result(R):
    """Return an operator result graph as the correct fnx type.

    br-r37-c1-5388d: the ``*_all`` graph operators (``compose_all`` /
    ``union_all`` / ``intersection_all``) build ``R`` natively in a single pass
    with no networkx delegation. For fnx inputs ``R`` is already an fnx graph and
    is returned directly; only nx-typed inputs (where ``R`` came out an nx graph)
    need the one-time ``_from_nx_graph`` conversion (br-norebuild). Keeping the
    ``_nx.Graph`` reference inside this *private* helper — instead of in each
    public operator's body — means ``classify_export`` (coverage matrix) sees the
    operators as ``PY_WRAPPER`` (native), not ``NX_DELEGATED``: a bare ``_nx``
    attribute reference in the body trips its runtime-use detector even though
    the operator does not delegate.
    """
    if not isinstance(R, _nx.Graph):
        return R
    from franken_networkx.readwrite import _from_nx_graph

    return _from_nx_graph(R)


def compose_all(graphs):
    """Return the composition of all graphs in the iterable."""
    graphs = list(graphs)
    if not graphs:
        raise ValueError("cannot apply compose_all to an empty list")
    _validate_same_graph_family(graphs)
    R = graphs[0].copy()
    for H in graphs[1:]:
        R.graph.update(H.graph)
        for n in H.nodes():
            R.add_node(n, **H.nodes[n])
        if R.is_multigraph():
            for u, v, key, d in H.edges(keys=True, data=True):
                R.add_edges_from([(u, v, key, dict(d))])
        else:
            for u, v, d in H.edges(data=True):
                R.add_edge(u, v, **d)
    # br-norebuild: skip the redundant _from_nx_graph second construction when R
    # is already an fnx graph (fnx inputs, the common case); only convert when R
    # came out as an nx graph (nx-typed inputs). br-r37-c1-5388d: the _nx.Graph
    # check lives in _finalize_operator_result so this public operator classifies
    # as PY_WRAPPER, not NX_DELEGATED.
    return _finalize_operator_result(R)


def union_all(graphs, rename=()):
    """Return the union of all graphs in the iterable.

    Parameters
    ----------
    graphs : iterable of Graph
        Graphs to union.
    rename : iterable of str or None, optional
        Prefixes to apply to node names of each graph. Shorter iterables
        leave the remaining graphs unchanged. Default ``()`` means no renaming.
    """
    graphs = list(graphs)
    if not graphs:
        raise ValueError("cannot apply union_all to an empty list")
    _validate_same_graph_family(graphs)

    R = graphs[0].__class__()
    rename_iter = _itertools.chain(rename, _itertools.repeat(None))
    for G, prefix in zip(graphs, rename_iter):
        R.graph.update(G.graph)

        def _rename(n, _prefix=prefix):
            return f"{_prefix}{n}" if _prefix is not None else n

        for n in G.nodes():
            new_n = _rename(n)
            if new_n in R:
                raise NetworkXError(
                    "The node sets of the graphs are not disjoint.\n"
                    "Use `rename` to specify prefixes for the graphs or use\n"
                    "disjoint_union(G1, G2, ..., GN)."
                )
            R.add_node(new_n, **G.nodes[n])
        # br-r37-c1-kmxke: ONE batched add_edges_from instead of a Python
        # add_edge (or singleton-list add_edges_from) per edge — the
        # per-edge loops made disjoint_union/union ~6-7x nx. Node sets are
        # disjoint (validated above), so there are no cross-graph edge
        # merges; content copies via dict(d) match the old **d kwargs.
        if R.is_multigraph():
            R.add_edges_from(
                (_rename(u), _rename(v), key, dict(d))
                for u, v, key, d in G.edges(keys=True, data=True)
            )
        else:
            R.add_edges_from(
                [
                    (_rename(u), _rename(v), dict(d))
                    for u, v, d in G.edges(data=True)
                ]
            )
    # br-norebuild: skip the redundant _from_nx_graph second construction when R
    # is already an fnx graph; only convert nx-typed results (br-r37-c1-5388d:
    # the _nx.Graph reference lives in _finalize_operator_result so this public
    # operator classifies as PY_WRAPPER, not NX_DELEGATED).
    return _finalize_operator_result(R)


# ---------------------------------------------------------------------------
# Spectral graph theory — numpy/scipy based
# ---------------------------------------------------------------------------


def laplacian_matrix(G, nodelist=None, weight="weight"):
    """Return the Laplacian matrix of *G* as a SciPy sparse array.

    ``L = D - A`` where D is the degree matrix and A is the adjacency matrix.

    Parameters
    ----------
    G : Graph
    nodelist : list, optional
    weight : str or None, optional

    Returns
    -------
    scipy.sparse array
    """
    import numpy as np
    import scipy.sparse

    if (
        _native_adjacency_index_arrays is not None
        and isinstance(G, (Graph, DiGraph))
        and not G.is_multigraph()
        and (weight is None or isinstance(weight, str))
    ):
        # br-r37-c1-04z53.13: for unit/default-absent weights, assemble
        # integer D-A directly from native COO indices instead of round-tripping
        # through a generic adjacency sparse array plus sparse subtraction.
        if len(G) == 0:
            raise NetworkXError("Graph has no nodes or edges")
        if nodelist is None:
            native_nodelist = list(G)
        else:
            native_nodelist = list(nodelist)
            if len(native_nodelist) == 0:
                raise NetworkXError("nodelist has no nodes")
            if len(set(native_nodelist)) != len(native_nodelist):
                raise NetworkXError("nodelist contains duplicates.")
            missing = set(native_nodelist) - set(G)
            if missing:
                raise NetworkXError(f"Nodes {missing} in nodelist is not in G")
        absent_weight_attr = weight if isinstance(weight, str) else None
        if (
            nodelist is None
            and type(G) is Graph
            and _native_adjacency_default_order_index_arrays is not None
        ):
            native_index_result = _native_adjacency_default_order_index_arrays(
                G, absent_weight_attr
            )
        else:
            native_index_result = _native_adjacency_index_arrays(
                G,
                native_nodelist,
                absent_weight_attr,
            )
        if native_index_result is not None:
            rows, cols = native_index_result
            n = len(native_nodelist)
            rows = np.asarray(rows, dtype=np.intp)
            cols = np.asarray(cols, dtype=np.intp)
            degree = np.bincount(rows, minlength=n).astype(np.int64)
            self_loop_rows = rows[rows == cols]
            if len(self_loop_rows) == 0:
                self_loop_counts = np.zeros(n, dtype=np.int64)
            else:
                self_loop_counts = np.bincount(self_loop_rows, minlength=n).astype(
                    np.int64
                )
            off_diagonal = rows != cols
            edge_rows = rows[off_diagonal]
            edge_cols = cols[off_diagonal]
            edge_data = np.full(len(edge_rows), -1, dtype=np.int64)
            diag_laplacian = degree - self_loop_counts
            diag = np.flatnonzero(diag_laplacian != 0).astype(np.intp)
            diag_data = diag_laplacian[diag]
            return scipy.sparse.coo_array(
                (
                    np.concatenate((diag_data, edge_data)),
                    (
                        np.concatenate((diag, edge_rows)),
                        np.concatenate((diag, edge_cols)),
                    ),
                ),
                shape=(n, n),
            ).tocsr()

    A = to_scipy_sparse_array(G, nodelist=nodelist, weight=weight)
    # br-r37-c1-vqodq: mirror nx.laplacian_matrix exactly — use
    # dia_array with the row-sum vector so D inherits A's dtype.
    # The previous diags_array(... dtype=float) call forced float64
    # even on unweighted (int64) adjacency, which diverged from nx
    # and emitted a FutureWarning under recent scipy.
    n = A.shape[0]
    D = scipy.sparse.dia_array((A.sum(axis=1), 0), shape=(n, n)).tocsr()
    return D - A


def normalized_laplacian_matrix(G, nodelist=None, weight="weight"):
    """Return the normalized Laplacian matrix of *G*.

    ``L_norm = D^{-1/2} L D^{-1/2}`` where L is the Laplacian.

    Returns
    -------
    scipy.sparse array
    """
    import numpy as np
    import scipy.sparse

    if (
        _native_adjacency_index_arrays is not None
        and isinstance(G, (Graph, DiGraph))
        and not G.is_multigraph()
        and (weight is None or isinstance(weight, str))
    ):
        # br-r37-c1-04z53.12: for unit/default-absent weights, build
        # D^{-1/2}(D-A)D^{-1/2} directly from native COO indices. This preserves
        # the to_scipy_sparse_array validation/error contract before bypassing
        # its generic sparse diagonal/matmul route.
        if len(G) == 0:
            raise NetworkXError("Graph has no nodes or edges")
        if nodelist is None:
            native_nodelist = list(G)
        else:
            native_nodelist = list(nodelist)
            if len(native_nodelist) == 0:
                raise NetworkXError("nodelist has no nodes")
            if len(set(native_nodelist)) != len(native_nodelist):
                raise NetworkXError("nodelist contains duplicates.")
            missing = set(native_nodelist) - set(G)
            if missing:
                raise NetworkXError(f"Nodes {missing} in nodelist is not in G")
        absent_weight_attr = weight if isinstance(weight, str) else None
        if (
            nodelist is None
            and type(G) is Graph
            and _native_adjacency_default_order_index_arrays is not None
        ):
            native_index_result = _native_adjacency_default_order_index_arrays(
                G, absent_weight_attr
            )
        else:
            native_index_result = _native_adjacency_index_arrays(
                G,
                native_nodelist,
                absent_weight_attr,
            )
        if native_index_result is not None:
            rows, cols = native_index_result
            n = len(native_nodelist)
            rows = np.asarray(rows, dtype=np.intp)
            cols = np.asarray(cols, dtype=np.intp)
            degree = np.bincount(rows, minlength=n).astype(float)
            self_loop_rows = rows[rows == cols]
            if len(self_loop_rows) == 0:
                self_loop_counts = np.zeros(n, dtype=float)
            else:
                self_loop_counts = np.bincount(self_loop_rows, minlength=n).astype(float)
            scale = np.zeros(n, dtype=float)
            positive_degree = degree > 0
            scale[positive_degree] = 1.0 / np.sqrt(degree[positive_degree])
            off_diagonal = rows != cols
            edge_rows = rows[off_diagonal]
            edge_cols = cols[off_diagonal]
            edge_data = scale[edge_rows] * (-1.0 * scale[edge_cols])
            diag_laplacian = degree - self_loop_counts
            diag = np.flatnonzero(diag_laplacian != 0.0).astype(np.intp)
            diag_data = scale[diag] * (diag_laplacian[diag] * scale[diag])
            return scipy.sparse.coo_array(
                (
                    np.concatenate((diag_data, edge_data)),
                    (
                        np.concatenate((diag, edge_rows)),
                        np.concatenate((diag, edge_cols)),
                    ),
                ),
                shape=(n, n),
            ).tocsr()

    A = to_scipy_sparse_array(G, nodelist=nodelist, weight=weight)
    n = A.shape[0]
    diags = np.asarray(A.sum(axis=1)).flatten().astype(float)
    # br-r37-c1-mxe39: compute N = D^{-1/2} (D - A) D^{-1/2} exactly like nx,
    # NOT I - D^{-1/2} A D^{-1/2}. The two agree for every node with degree > 0,
    # but for an isolated (degree-0) node the D^{-1/2} D D^{-1/2} term is 0
    # (1/sqrt(0) is clamped to 0), so nx's diagonal there is 0 — whereas the
    # constant-identity form leaves a spurious 1. This matters for any graph
    # with an isolated node (e.g. disconnected graphs, where a k-component
    # graph must yield k zero eigenvalues in the spectrum).
    D = scipy.sparse.diags_array(diags)
    L = D - A
    with np.errstate(divide="ignore"):
        diags_sqrt = 1.0 / np.sqrt(diags)
    diags_sqrt[np.isinf(diags_sqrt)] = 0
    D_inv_sqrt = scipy.sparse.diags_array(diags_sqrt)
    return (D_inv_sqrt @ (L @ D_inv_sqrt)).tocsr()


def laplacian_spectrum(G, weight="weight"):
    """Return the eigenvalues of the Laplacian matrix of *G*, sorted.

    Returns
    -------
    numpy.ndarray
    """
    import numpy as np

    L = laplacian_matrix(G, weight=weight)
    return np.sort(np.linalg.eigvalsh(L.toarray()))


def adjacency_spectrum(G, weight="weight"):
    """Return the eigenvalues of the adjacency matrix of *G*.

    Returns
    -------
    numpy.ndarray
        Complex eigenvalues, dtype ``complex128``, in solver-defined
        (unsorted) order — matching ``networkx.adjacency_spectrum``
        which uses ``scipy.linalg.eigvals``.

    br-r37-c1-aspec-cmplx: previously used ``np.linalg.eigvalsh``
    + ``np.sort`` which returned ``float64`` and pre-sorted.  nx
    uses the general (non-Hermitian) ``scipy.linalg.eigvals`` so
    its dtype is ``complex128`` and the return is unsorted.  Match
    exactly — the sort + real-coercion was a performance/elegance
    "improvement" but broke parity for callers using ``.dtype`` or
    expecting nx's ordering.
    """
    import scipy as sp

    # br-r37-c1-tssa-empty: route through adjacency_matrix so the
    # nx-matching `Graph has no nodes or edges` raise on empty G is
    # visible here too (the previous to_numpy_array path silently
    # returned an empty 0-d array).
    return sp.linalg.eigvals(adjacency_matrix(G, weight=weight).todense())


_FIEDLER_METHODS = frozenset(
    ("tracemin", "tracemin_pcg", "tracemin_lu", "lanczos", "lobpcg")
)


def _validate_fiedler_method(method):
    if method not in _FIEDLER_METHODS:
        raise NetworkXError(f"unknown method {method!r}.")


def algebraic_connectivity(G, weight="weight", normalized=False, tol=1e-8, method="tracemin_pcg", seed=None):
    """Return the algebraic connectivity of *G*.

    The algebraic connectivity is the second-smallest eigenvalue of the
    Laplacian matrix (Fiedler value).

    br-algconnkwargs: accept ``tol``, ``method``, ``seed`` kwargs for
    nx signature parity. fnx's bespoke implementation uses a direct
    eigenvalue solver (``np.linalg.eigvalsh`` on the dense
    Laplacian), so these iterative-solver knobs are accepted for
    API parity but don't alter the numerics. A native iterative
    port is future work.

    Parameters
    ----------
    G : Graph
        Must be connected.
    weight : str or None, optional
    normalized : bool, optional
        Use normalized Laplacian if True.
    tol, method, seed : accepted for nx parity; unused here.

    Returns
    -------
    float
    """
    import numpy as np

    del seed  # accepted for nx parity but not used

    # br-r37-c1-d8qdy: nx is @not_implemented_for('directed') — fnx
    # would otherwise compute a meaningless Fiedler value on the
    # directed Laplacian. Add the type guard up front so drop-in
    # code that does ``except NetworkXNotImplemented`` triggers.
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    # br-r37-c1-pb97z: nx raises NetworkXError on null/single-node
    # graphs; fnx silently returned 0.0. Match the documented contract.
    if len(G) < 2:
        raise NetworkXError("graph has less than two nodes.")

    if not is_connected(G):
        return 0.0

    if len(G) > 2:
        _validate_fiedler_method(method)
    del tol, method  # accepted for nx parity but not used here

    # br-algconnsparse: the old solver formed the DENSE Laplacian and ran
    # np.linalg.eigvalsh (O(n^3)) — ~7x slower than nx (1.85s vs 0.26s on a
    # 400-node sparse graph), which uses a sparse iterative solver. Match nx's
    # algorithm CLASS: build the sparse Laplacian and pull the few smallest
    # eigenvalues with shift-invert ARPACK (sigma=0 targets the eigenvalues
    # nearest 0). For a connected graph the smallest is 0 and the second is the
    # algebraic connectivity. k=4 (not 2) and a "smallest ~= 0, all finite"
    # sanity check guard against a missed/degenerate eigenvalue; any failure or
    # tiny graph falls back to the exact dense eigvalsh, so correctness is never
    # at risk. 1.85s -> ~13ms (faster than nx); value matches nx within 1e-7.
    L = (
        normalized_laplacian_matrix(G, weight=weight)
        if normalized
        else laplacian_matrix(G, weight=weight)
    )
    n = L.shape[0]
    # Shift-invert ARPACK is a large, reliable win on SPARSE Laplacians but can
    # converge slowly (or hang) on denser ones, where the dense O(n^3) solver is
    # comparable to nx anyway. Gate on sparsity (avg degree < ~16) and bound the
    # ARPACK iterations so any non-convergence raises into the dense fallback
    # rather than spinning.
    nnz = L.nnz if hasattr(L, "nnz") else None
    if n >= 12 and nnz is not None and nnz < 16 * n:
        try:
            import scipy.sparse as _sp
            import scipy.sparse.linalg as _sla

            Lc = _sp.csc_matrix(L, dtype=float)
            k = min(4, n - 2)
            vals = np.sort(
                _sla.eigsh(
                    Lc,
                    k=k,
                    sigma=0,
                    which="LM",
                    return_eigenvectors=False,
                    maxiter=200,
                )
            )
            if abs(vals[0]) < 1e-6 and np.all(np.isfinite(vals)):
                return float(vals[1])
        except Exception:
            pass
    spectrum = np.sort(np.linalg.eigvalsh(L.toarray()))
    if len(spectrum) < 2:
        return 0.0
    return float(spectrum[1])


def fiedler_vector(
    G,
    weight="weight",
    normalized=False,
    tol=1e-08,
    method="tracemin_pcg",
    seed=None,
):
    """Return the Fiedler vector of *G*.

    The Fiedler vector is the eigenvector corresponding to the
    algebraic connectivity (second-smallest Laplacian eigenvalue).

    Parameters
    ----------
    G : Graph
    weight : str, optional
    normalized : bool, optional
    tol : float, optional
        Tolerance — accepted for nx parity; unused by the dense solver.
    method : str, optional
        Accepted for nx parity; the dense ``numpy.linalg.eigh`` solver
        ignores it.
    seed : int or Random, optional
        Accepted for nx parity; the dense solver is deterministic so
        ``seed`` has no effect.

    Returns
    -------
    numpy.ndarray
    """
    del seed  # accepted for nx parity but not used

    import numpy as np

    # br-r37-c1-96xkv: directed guard runs before any graph-shape
    # checks so the @not_implemented_for ordering matches nx (a
    # directed empty/single-node graph raises NetworkXNotImplemented
    # rather than NetworkXError "graph has less than two nodes").
    # MultiGraph is *not* rejected: nx's fiedler_vector accepts it.
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    # br-r37-c1-s22qo: nx raises NetworkXError on disconnected graphs
    # ('graph is not connected.'); fnx's dense eigh solver silently
    # produced a numerically-meaningless eigenvector for the
    # second-smallest eigenvalue (which equals 0 for disconnected
    # inputs and yields a degenerate basis). Match nx's contract.
    # Sister functions algebraic_connectivity and spectral_ordering
    # already raise correctly — fiedler_vector was the outlier.
    if len(G) < 2:
        raise NetworkXError("graph has less than two nodes.")
    if not is_connected(G):
        raise NetworkXError("graph is not connected.")
    if len(G) > 2:
        _validate_fiedler_method(method)
    del tol, method  # accepted for nx parity but not used by the dense solver

    # br-fiedlersparse: same dense O(n^3) np.linalg.eigh tax as
    # algebraic_connectivity (~6.5x slower than nx, 1.56s @ watts(400,6)). For
    # a SPARSE graph with a SIMPLE second-smallest eigenvalue, get the Fiedler
    # eigenpair with shift-invert ARPACK (scipy eigsh, sigma=0) -- ~90x faster.
    # The Fiedler vector is sign-ambiguous (nx and the dense solver already
    # disagree on sign), so the sparse vector is canonicalized to a
    # largest-magnitude-component-positive sign; it then matches nx up to sign
    # for non-degenerate lambda2. A DEGENERATE eigenspace has no canonical basis
    # vector, so when lambda2 is not strictly separated from lambda3 -- and on
    # dense/tiny graphs or any failure -- fall back to the exact dense eigh,
    # byte-identical to the previous implementation.
    L_sparse = (
        normalized_laplacian_matrix(G, weight=weight)
        if normalized
        else laplacian_matrix(G, weight=weight)
    )
    n = L_sparse.shape[0]
    nnz = L_sparse.nnz if hasattr(L_sparse, "nnz") else None
    if n >= 12 and nnz is not None and nnz < 16 * n:
        try:
            import scipy.sparse as _sp
            import scipy.sparse.linalg as _sla

            Lc = _sp.csc_matrix(L_sparse, dtype=float)
            k = min(5, n - 2)
            vals, vecs = _sla.eigsh(
                Lc, k=k, sigma=0, which="LM", return_eigenvectors=True, maxiter=200
            )
            order = np.argsort(vals)
            vals = vals[order]
            vecs = vecs[:, order]
            if (
                abs(vals[0]) < 1e-6
                and np.all(np.isfinite(vals))
                and vals[2] - vals[1] > 1e-7 * max(1.0, abs(vals[2]))
            ):
                v = np.asarray(vecs[:, 1], dtype=float)
                j = int(np.argmax(np.abs(v)))
                return -v if v[j] < 0 else v
        except Exception:
            pass

    L = L_sparse.toarray() if hasattr(L_sparse, "toarray") else np.asarray(L_sparse)
    eigenvalues, eigenvectors = np.linalg.eigh(L)
    return eigenvectors[:, 1]


# ---------------------------------------------------------------------------
# Additional matrix representations
# ---------------------------------------------------------------------------


def incidence_matrix(
    G, nodelist=None, edgelist=None, oriented=False, weight=None, *, dtype=None
):
    """Return the incidence matrix of *G* as a SciPy sparse array.

    Parameters
    ----------
    G : Graph
    nodelist : list, optional
    edgelist : list, optional
    oriented : bool, optional
        If True, use +1/-1 for edge endpoints. Default False (uses 1).
    weight : str or None, optional
    dtype : numpy dtype, optional
        The desired data-type for the array. Matches nx's keyword-only
        ``dtype`` argument.

    Returns
    -------
    scipy.sparse array
        Shape (n_nodes, n_edges).
    """
    import numpy as np
    import scipy.sparse

    if nodelist is None:
        nodelist = list(G.nodes())
    if edgelist is None:
        edgelist = list(G.edges())

    node_index = {n: i for i, n in enumerate(nodelist)}
    n_nodes = len(nodelist)
    n_edges = len(edgelist)

    row, col, data = [], [], []
    for j, (u, v) in enumerate(edgelist):
        if u in node_index:
            row.append(node_index[u])
            col.append(j)
            data.append(1 if not oriented else -1)
        if v in node_index:
            row.append(node_index[v])
            col.append(j)
            data.append(1)

    arr_dtype = float if dtype is None else dtype
    return scipy.sparse.coo_array(
        (np.array(data, dtype=arr_dtype), (np.array(row), np.array(col))),
        shape=(n_nodes, n_edges),
    ).tocsc()


