def dijkstra_predecessor_and_distance(G, source, cutoff=None, weight="weight"):
    """Return predecessors and distances from Dijkstra's algorithm.

    Parameters
    ----------
    G : Graph
    source : node
    cutoff : float, optional
        Maximum distance threshold.
    weight : str, optional

    Returns
    -------
    (pred, dist) : tuple of dicts

    br-r37-c1-0l76i: nx populates the predecessor dict in
    edge-relaxation insertion order during traversal (so pred[v]
    appears in the dict at the moment a tentative shortest path is
    found, not when the distance is finalized). The previous local
    implementation built ``pred = {node: predecessors[node] for
    node in distances}`` which forced pred-key order to match
    distances-iteration order, drifting from nx (e.g. nx's pred for
    weighted graph [(a,b,1),(b,c,2),(c,d,1),(a,d,5),(b,d,3)] is
    {a:[], b:[a], d:[b,c], c:[b]} — d lands before c because (b,d)
    is relaxed before c is popped). Delegate to nx so pred-dict
    iteration matches nx's algorithm-discovery contract.
    """
    return _call_networkx_for_parity(
        "dijkstra_predecessor_and_distance",
        G, source, cutoff=cutoff, weight=weight,
    )


def multi_source_dijkstra(G, sources, target=None, cutoff=None, weight="weight"):
    """Return shortest path lengths and paths from any source in *sources*."""
    if not sources:
        raise ValueError("sources must not be empty")
    # br-r37-c1-gr1ct: materialize SubgraphView first (view family).
    G = _coerce_arg_to_fnx_graph(G)
    # br-dijkignoreweight: the Rust multi_source_dijkstra inherits the
    # same weight-ignoring bug as single_source_dijkstra. Delegate any
    # weighted input to nx for correctness.
    if (
        callable(weight)
        or _should_delegate_dijkstra_to_networkx(G, weight)
        or _graph_has_nonunit_weight(G, weight)
    ):
        return _call_networkx_for_parity(
            "multi_source_dijkstra",
            G,
            sources,
            target=target,
            cutoff=cutoff,
            weight=weight,
        )
    # br-r37-c1-k4pod: pre-check membership for nx's exact wording
    # ('Node X not found in graph') — Rust binding emits a quoted-repr
    # variant that breaks message-matching code.
    for s in sources:
        if s not in G:
            raise NodeNotFound(f"Node {s} not found in graph")
    dists, paths = _raw_multi_source_dijkstra(G, sources, weight=weight)
    # br-r37-c1-msd-cutnan: nx Dijkstra's cutoff check is
    # ``if d > cutoff: continue`` so ``cutoff=NaN`` and
    # ``cutoff=+inf`` both behave as unbounded (comparison
    # always False → never skips).  fnx's inverse predicate
    # ``distance <= cutoff`` is ALSO always False for NaN →
    # filters out everything (sister of the single-source fix
    # br-r37-c1-djk-cutnan).  Short-circuit before the filter.
    if cutoff is not None:
        if not (isinstance(cutoff, float) and (_math.isnan(cutoff) or cutoff == _math.inf)):
            # nx always retains the source nodes even when
            # ``cutoff < 0`` (sources have d=0 and the filter
            # ``d <= cutoff`` would drop them; nx's loop adds
            # them before applying the cutoff via the priority
            # queue's pop order).
            source_set = set(sources)
            dists = {
                node: distance for node, distance in dists.items()
                if distance <= cutoff or node in source_set
            }
            paths = {node: path for node, path in paths.items() if node in dists}
    # br-r37-c1-msd-intfloat: nx preserves int distances when
    # every edge weight is int (path graph default = unit
    # weight).  fnx's Rust binding casts to f64.  Mirror nx's
    # int/float parity (sister of br-ssintfloat for single-
    # source).
    if _sp_edge_weights_all_int(G, weight):
        dists = _sp_coerce_dist_to_int(dists)
    # br-r37-c1-msd-order: nx's Dijkstra emits nodes in pop
    # order from the priority queue → ascending distance.  fnx's
    # Rust binding returns a dict in adjacency-walk order.
    # Reorder by distance to match nx's iteration contract
    # (dict order is observable in py3.7+).  Sister of the
    # br-r37-c1-62jy2 single-source reorder.
    order = _reorder_by_distance(dists)
    dists = {k: dists[k] for k in order}
    paths = {k: paths[k] for k in order if k in paths}
    if target is not None:
        if target not in dists:
            raise NetworkXNoPath(f"No path to {target}.")
        return dists[target], paths[target]
    return dists, paths


def multi_source_dijkstra_path(G, sources, cutoff=None, weight="weight"):
    """Return shortest paths from any source to all reachable nodes.

    Parameters
    ----------
    G : Graph
    sources : iterable of nodes
    weight : str, optional

    Returns
    -------
    dict
        ``{target: path}`` where path starts from the nearest source.
    """
    _, paths = multi_source_dijkstra(G, sources, cutoff=cutoff, weight=weight)
    return paths


def multi_source_dijkstra_path_length(G, sources, cutoff=None, weight="weight"):
    """Return shortest path lengths from any source to all reachable nodes.

    Parameters
    ----------
    G : Graph
    sources : iterable of nodes
    weight : str, optional

    Returns
    -------
    dict
        ``{target: length}``
    """
    dists, _ = multi_source_dijkstra(G, sources, cutoff=cutoff, weight=weight)
    return dists


def single_source_all_shortest_paths(G, source, weight=None, method="dijkstra"):
    """Yield all shortest paths from source to every reachable target.

    Parameters
    ----------
    G : Graph
    source : node
    weight : str or callable or None, optional
    method : str, optional

    Yields
    ------
    (target, paths)
        ``paths`` is the list of all shortest paths from source to target.
    """
    yield from _call_networkx_for_parity(
        "single_source_all_shortest_paths",
        G,
        source,
        weight=weight,
        method=method,
    )


def all_pairs_all_shortest_paths(G, weight=None, method="dijkstra"):
    """Yield all shortest paths between all pairs.

    Parameters
    ----------
    G : Graph
    weight : str or None, optional
    method : str, optional

    Yields
    ------
    (source, paths_dict)
        Where paths_dict maps target -> list of shortest paths.
    """
    if weight is not None:
        yield from _call_networkx_for_parity(
            "all_pairs_all_shortest_paths", G, weight=weight, method=method
        )
        return
    result = _fnx.all_pairs_all_shortest_paths_rust(G)
    for source in G.nodes():
        paths_dict = {source: [[source]]}
        paths_dict.update(result.get(source, {}))
        yield (source, paths_dict)


def reconstruct_path(source, target, predecessors):
    """Reconstruct a path from *source* to *target*.

    Matches networkx's public signature
    ``reconstruct_path(source, target, predecessors)`` where
    ``predecessors`` is either the nested
    ``floyd_warshall_predecessor_and_distance`` dict
    (``predecessors[src][tgt] -> predecessor``) or a flat dict of
    ``{node: predecessor_list}`` (dijkstra-style output).
    """
    # br-r37-c1-recon-keyerr: nx raises KeyError(node) when the
    # source / target is not present in the predecessor dict.  fnx
    # previously fell through to a dijkstra-style fallback that
    # walked through dict-typed inner predecessor maps, raising
    # ``TypeError: unhashable type: 'dict'`` on bad-source or
    # silently returning ``[]`` on bad-target.

    # Floyd-Warshall style: predecessors is {src: {tgt: pred}}
    is_floyd = (
        isinstance(predecessors, dict)
        and any(isinstance(v, dict) for v in predecessors.values())
    )
    if is_floyd:
        if source not in predecessors:
            raise KeyError(source)
        table = predecessors[source]
        if source == target:
            return []
        if target not in table:
            raise KeyError(target)
        path = [target]
        current = target
        while current != source:
            current = table[current]
            path.append(current)
        path.reverse()
        return path

    # Dijkstra-style: predecessors is {node: [pred1, ...]}
    if source == target:
        return [source]
    path = [target]
    current = target
    while current != source:
        preds = predecessors.get(current, [])
        if not preds:
            return []
        current = preds[0] if isinstance(preds, (list, tuple)) else preds
        path.append(current)
    path.reverse()
    return path


def generate_random_paths(
    G,
    sample_size,
    path_length=5,
    index_map=None,
    weight="weight",
    seed=None,
    *,
    source=None,
):
    """Generate random paths by weighted random walks.

    Parameters
    ----------
    G : Graph
    sample_size : int
        Number of paths to generate.
    path_length : int, optional
        Maximum length of each path. Default 5.
    weight : str or None, optional
        Edge attribute used as the transition weight. Default
        ``"weight"`` to match networkx (br-r37-c1-rygbm follow-up:
        the previous fnx default of ``None`` silently dropped edge
        weights and produced a uniform random walk where nx produces
        a weighted one). Pass ``weight=None`` for the legacy uniform
        behaviour.
    seed : int or None, optional
    source : node or None, optional (keyword-only)
        Fixed starting node for every sampled walk. When ``None``
        (default), each walk starts from a uniformly random node.

    Yields
    ------
    list
        Each yield is a random walk path.
    """
    # NetworkX uses the numpy random-state decorator and samples from a
    # transition-probability matrix.  The Panther helper below implements that
    # contract exactly and also populates ``index_map`` with the same path ids.
    yield from _panther_generate_random_paths(
        G,
        sample_size,
        path_length=path_length,
        index_map=index_map,
        weight=weight,
        seed=seed,
        source=source,
    )


def johnson(G, weight="weight"):
    """All-pairs shortest paths using Johnson's algorithm.

    Johnson's algorithm handles graphs with negative edges (but no
    negative cycles) by reweighting edges via Bellman-Ford, then
    running Dijkstra from each node.

    Parameters
    ----------
    G : Graph or DiGraph
    weight : str, optional

    Returns
    -------
    dict of dicts
        ``result[u][v]`` is the shortest path from u to v.

    br-r37-c1-9l73c: the local
    ``dict(all_pairs_bellman_ford_path(...))`` short-circuit
    produced inner-dict keys in BF-tree-discovery order, which
    differed from nx's johnson algorithm-specific Dijkstra-from-
    node iteration order (e.g. inner[a] keys ['a','b','d','c'] vs
    nx ['a','b','c','d']). Delegate to nx so the inner-dict
    iteration order matches its contract exactly.
    """
    return _call_networkx_for_parity("johnson", G, weight=weight)


# ---------------------------------------------------------------------------
# Spectral & Matrix (numpy/scipy) — br-ulw
# ---------------------------------------------------------------------------


def bethe_hessian_matrix(G, r=None, nodelist=None):
    """Return the Bethe Hessian matrix: H(r) = (r^2-1)*I - r*A + D.

    br-bethedef: nx's default regularizer is
    ``r = sum(d_i^2)/sum(d_i) - 1`` (Le & Levina 2015). fnx used
    ``max(sqrt(mean(degree)), 1.0)`` which produced a different matrix
    whenever the default was requested — on path(5) fnx's r was
    ~1.265 (giving diag entry 2.6) vs nx's r=0.75 (giving diag 1.5625).
    Match nx's formula exactly.

    br-r37-c1-tqimg: nx is @not_implemented_for('directed',
    'multigraph') — reject MG/DiGraph inputs.
    """
    import numpy as np
    import scipy.sparse

    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    # nx's bethe_hessian_matrix mixes weighted and unweighted quantities:
    # A and D come from the weighted adjacency (weight='weight'), but the
    # default regularizer r is computed from unweighted node degrees via
    # nx.degree(G). Match that mix exactly.
    if nodelist is None:
        nodelist = list(G.nodes())
    A = to_scipy_sparse_array(G, nodelist=nodelist, format="csr")
    n = A.shape[0]
    d = np.asarray(A.sum(axis=1)).flatten()
    # Use sparse *arrays* throughout (not legacy matrices) so the final
    # product preserves nx's csr_array return type.
    D = scipy.sparse.diags_array(d, dtype=float)
    if r is None:
        # br-r37-c1-smetricdegcache: dict(G.degree()) once instead of
        # per-node G.degree(v) PyO3 calls.
        deg_dict = dict(G.degree())
        unweighted_degs = [deg_dict[v] for v in nodelist]
        deg_sum = sum(unweighted_degs)
        if deg_sum > 0:
            r = sum(x * x for x in unweighted_degs) / deg_sum - 1
        else:
            r = 1.0
    I = scipy.sparse.eye_array(n)
    return ((r**2 - 1) * I - r * A + D).tocsr()


def bethe_hessian_spectrum(G, r=None):
    """Return sorted eigenvalues of the Bethe Hessian matrix."""
    import numpy as np

    H = bethe_hessian_matrix(G, r=r)
    return np.sort(np.linalg.eigvalsh(H.toarray()))


def google_matrix(
    G,
    alpha=0.85,
    personalization=None,
    nodelist=None,
    weight="weight",
    dangling=None,
):
    """Return the Google PageRank matrix: alpha*S + (1-alpha)*v*e^T.

    br-matsig: adds the ``dangling`` parameter nx exposes (weights used
    to redistribute mass from dangling nodes instead of the uniform
    teleport). Previously fnx rejected ``dangling=`` with a TypeError.
    """
    import numpy as np

    if nodelist is None:
        nodelist = list(G.nodes())
    n = len(nodelist)
    if n == 0:
        return np.array([[]])
    A = to_numpy_array(G, nodelist=nodelist, weight=weight)
    row_sums = A.sum(axis=1)

    if dangling is None:
        dangling_row = None
    else:
        dangling_row = np.array(
            [dangling.get(node, 0) for node in nodelist], dtype=float
        )
        total = dangling_row.sum()
        if total > 0:
            dangling_row = dangling_row / total

    S = np.zeros_like(A)
    for i in range(n):
        if row_sums[i] > 0:
            S[i, :] = A[i, :] / row_sums[i]
        elif dangling_row is not None:
            S[i, :] = dangling_row
        else:
            S[i, :] = 1.0 / n
    if personalization is None:
        v = np.ones(n) / n
    else:
        v = np.array([personalization.get(node, 0) for node in nodelist], dtype=float)
        s = v.sum()
        v = v / s if s > 0 else np.ones(n) / n
    return alpha * S + (1 - alpha) * np.outer(np.ones(n), v)


def normalized_laplacian_spectrum(G, weight="weight"):
    """Return sorted eigenvalues of the normalized Laplacian."""
    import numpy as np

    NL = normalized_laplacian_matrix(G, weight=weight)
    return np.sort(np.linalg.eigvalsh(NL.toarray()))


def directed_laplacian_matrix(
    G, nodelist=None, weight="weight", walk_type=None, alpha=0.95
):
    """Return the directed Laplacian matrix of G.

    br-dirlap: delegates to nx for numerical correctness and signature
    parity. The previous bespoke implementation (a) was missing the
    ``walk_type`` kwarg entirely and (b) always used the pagerank walk
    matrix regardless of the graph's strong connectivity, producing
    outputs that diverged from nx by ~16% on simple strongly-connected
    3-cycles. nx's implementation dispatches on ``walk_type`` —
    ``random`` / ``lazy`` / ``pagerank`` — with the default chosen from
    graph structure (random for strongly connected, pagerank otherwise).
    Reproducing this table in pure Python without drift is brittle;
    delegation is the right default.
    """
    return _call_networkx_for_parity(
        "directed_laplacian_matrix",
        G,
        nodelist=nodelist,
        weight=weight,
        walk_type=walk_type,
        alpha=alpha,
    )


def directed_combinatorial_laplacian_matrix(
    G, nodelist=None, weight="weight", walk_type=None, alpha=0.95
):
    """Return the directed combinatorial Laplacian: Phi*(I - P).

    br-dirlap: see ``directed_laplacian_matrix`` — same delegation
    rationale (missing walk_type kwarg + wrong stationary distribution
    on strongly-connected graphs).
    """
    return _call_networkx_for_parity(
        "directed_combinatorial_laplacian_matrix",
        G,
        nodelist=nodelist,
        weight=weight,
        walk_type=walk_type,
        alpha=alpha,
    )


def attr_matrix(
    G,
    edge_attr=None,
    node_attr=None,
    normalized=False,
    rc_order=None,
    dtype=None,
    order=None,
):
    """Construct a matrix from edge attributes.

    When *node_attr* is given, nodes are grouped by attribute value and the
    matrix has size ``len(unique_attr_values)`` with entries summed over
    nodes sharing the same attribute.  *rc_order* then specifies the
    ordering of attribute values, not nodes.

    br-r37-c1-attrmtx: nx requires the named ``edge_attr`` / ``node_attr``
    to be present on every edge / node and raises ``KeyError`` when
    missing.  fnx previously used ``.get(attr, default)`` which silently
    swallowed missing attrs and returned a default-1 / node-as-label
    matrix — masking caller bugs.  Mirror nx's exact subscript pattern
    (``data[edge_attr]`` / ``G.nodes[u][node_attr]``) and support
    callable values too.
    """
    import numpy as np

    # br-r37-c1-attrmtx: build edge / node value resolvers matching nx.
    # ``None`` -> default semantics; ``callable`` -> user-supplied;
    # ``str`` -> direct subscript that raises KeyError on missing.
    # nx special-cases ``edge_attr == "weight"`` with a default of 1
    # (so unweighted graphs still work when the canonical "weight"
    # name is asked for); other named attrs MUST exist on every edge.
    if edge_attr is None:
        if G.is_multigraph():
            def edge_value(u, v):
                return len(G[u][v])
        else:
            def edge_value(u, v):
                return 1
    elif callable(edge_attr):
        edge_value = edge_attr
    elif edge_attr == "weight":
        if G.is_multigraph():
            def edge_value(u, v):
                return sum(d.get("weight", 1) for d in G[u][v].values())
        else:
            def edge_value(u, v):
                return G[u][v].get("weight", 1)
    else:
        if G.is_multigraph():
            def edge_value(u, v):
                return sum(d[edge_attr] for d in G[u][v].values())
        else:
            def edge_value(u, v):
                return G[u][v][edge_attr]

    if node_attr is None:
        def node_value(u):
            return u
    elif callable(node_attr):
        node_value = node_attr
    else:
        def node_value(u):
            return G.nodes[u][node_attr]

    if rc_order is None:
        ordering = list({node_value(n) for n in G.nodes()})
    else:
        ordering = list(rc_order)
    N = len(ordering)
    undirected = not G.is_directed()
    index = dict(zip(ordering, range(N)))
    M = np.zeros((N, N), dtype=dtype, order=order)

    # br-r37-c1-amdsnap: G.adjacency() is ~12× slower than G._adj.items()
    # because of AdjacencyView wrapping.  Same yield shape.
    if node_attr is None and type(G) in (Graph, DiGraph):
        edgelist = _fnx.to_edgelist_simple(G)
        if edgelist is not None:
            for u, v, attrs in edgelist:
                try:
                    i, j = index[u], index[v]
                except KeyError:
                    continue
                if edge_attr is None:
                    value = 1
                elif callable(edge_attr):
                    value = edge_attr(u, v)
                elif edge_attr == "weight":
                    value = attrs.get("weight", 1)
                else:
                    value = attrs[edge_attr]
                M[i, j] += value
                if undirected:
                    M[j, i] = M[i, j]
            if normalized:
                rs = M.sum(axis=1)
                rs[rs == 0] = 1
                M = M / rs[:, np.newaxis]

            if rc_order is None:
                return M, ordering
            return M

    seen = set()
    for u, nbrdict in G._adj.items():
        for v in nbrdict:
            try:
                i, j = index[node_value(u)], index[node_value(v)]
            except KeyError:
                continue
            if v not in seen:
                M[i, j] += edge_value(u, v)
                if undirected:
                    M[j, i] = M[i, j]
        if undirected:
            seen.add(u)

    if normalized:
        rs = M.sum(axis=1)
        rs[rs == 0] = 1
        M = M / rs[:, np.newaxis]

    if rc_order is None:
        return M, ordering
    return M


# ---------------------------------------------------------------------------
# Min-cost flow algorithms (br-hp3)
# ---------------------------------------------------------------------------


def cost_of_flow(G, flowDict, weight="weight"):
    """Compute the cost of a given flow.

    Parameters
    ----------
    G : DiGraph
        Network with edge attribute *weight* as cost per unit flow.
    flowDict : dict of dicts
        ``flowDict[u][v]`` is the flow on edge (u, v).
    weight : str, optional
        Edge attribute name for cost. Default ``'weight'``.

    Returns
    -------
    float
        Total cost of the flow.
    """
    # br-costint: nx.cost_of_flow uses sum(G[u][v][weight]*flow[u][v])
    # which preserves int when all factors are int. fnx initialized
    # total=0.0 and cast weights via float(), always widening the
    # result. Keep nx's int-preservation by initializing total=0 and
    # using the raw weight value (with a 0 default) without float cast.
    total = 0
    for u in flowDict:
        for v, flow in flowDict[u].items():
            if flow > 0:
                data = G.get_edge_data(u, v)
                if isinstance(data, dict):
                    cost = data.get(weight, 0)
                else:
                    cost = 0
                total = total + flow * cost
    return total


def _mcf_inputs_all_integral(G, demand, capacity, weight):
    """br-mcfint: nx.min_cost_flow and nx.network_simplex preserve int
    flow values when every demand, capacity, and weight on the graph
    is an integer. fnx's Python implementation widens via ``float(...)``
    casts, so the flow dict comes back with float values. Detect the
    all-int-input case so callers can coerce the flow dict back to
    int for exact nx parity.
    """
    import numbers as _numbers
    for node in G.nodes():
        attrs = G.nodes[node] if hasattr(G.nodes, "__getitem__") else {}
        if isinstance(attrs, dict):
            d = attrs.get(demand, 0)
            if not isinstance(d, _numbers.Integral) or isinstance(d, bool):
                return False
    for _, _, attrs in G.edges(data=True):
        if not isinstance(attrs, dict):
            continue
        cap = attrs.get(capacity, 1)
        if not isinstance(cap, _numbers.Integral) or isinstance(cap, bool):
            # float('inf') is infinity; nx still produces int in that case
            # when capacities are effectively unbounded integrals elsewhere.
            # Treat +inf as non-integer only if it's not matched by other ints.
            return False
        w = attrs.get(weight, 0)
        if not isinstance(w, _numbers.Integral) or isinstance(w, bool):
            return False
    return True


def _coerce_flow_dict_to_int(flow_dict):
    """Coerce a dict-of-dicts flow to int values (used when _mcf_inputs_all_integral)."""
    out = {}
    for u, inner in flow_dict.items():
        out[u] = {v: (int(f) if isinstance(f, float) and f.is_integer() else f)
                  for v, f in inner.items()}
    return out


def min_cost_flow(G, demand="demand", capacity="capacity", weight="weight"):
    """Find minimum cost flow satisfying node demands.

    Uses the successive shortest paths algorithm with Bellman-Ford.

    Each node may have a ``demand`` attribute:
    - Negative demand = supply (source, has excess flow to send)
    - Positive demand = demand (sink, needs flow)
    - Zero or missing = transshipment node

    Parameters
    ----------
    G : DiGraph
    demand : str, optional
        Node attribute for supply/demand. Default ``'demand'``.
    capacity : str, optional
        Edge attribute for capacity. Default ``'capacity'``.
    weight : str, optional
        Edge attribute for cost per unit flow. Default ``'weight'``.

    Returns
    -------
    dict of dicts
        ``flowDict[u][v]`` is the optimal flow on edge (u, v).

    Raises
    ------
    NetworkXUnfeasible
        If no feasible flow exists.
    """
    # br-r37-c1-3qt4m: nx's @not_implemented_for('undirected')
    # decorator raises NetworkXNotImplemented, not NetworkXError.
    # min_cost_flow_cost and capacity_scaling both call this so the
    # fix propagates to the whole family.
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")

    nodes = list(G.nodes())
    n = len(nodes)
    if n == 0:
        # br-r37-c1-mcfempty: nx's network_simplex raises
        # NetworkXError("graph has no nodes") on empty input via the
        # validation block in _validate_network_simplex_inputs; fnx's
        # SSP path silently returned {}.  Match nx's contract.  The
        # downstream min_cost_flow_cost / max_flow_min_cost both
        # route here so the empty-graph contract propagates.
        raise NetworkXError("graph has no nodes")

    # br-r37-c1-mcf-negcap: the SSP solver below silently treats
    # negative capacities as 0, masking nx's NetworkXUnfeasible
    # contract.  network_simplex (sibling) already validates via
    # _validate_network_simplex_inputs and matches nx exactly; the
    # SSP path was the gap, which propagated through min_cost_flow_
    # cost and max_flow_min_cost (both route here).
    for u, v, edge_attrs in G.edges(data=True):
        if isinstance(edge_attrs, dict):
            edge_capacity = float(edge_attrs.get(capacity, float("inf")))
            if edge_capacity < 0:
                raise NetworkXUnfeasible(
                    f"edge {(u, v)!r} has negative capacity"
                )

    # Extract demands
    node_demand = {}
    for node in nodes:
        attrs = G.nodes[node] if hasattr(G.nodes, "__getitem__") else {}
        if isinstance(attrs, dict):
            node_demand[node] = float(attrs.get(demand, 0))
        else:
            node_demand[node] = 0.0

    # br-r37-c1-74xas: nx raises NetworkXError("node X has infinite
    # demand") at this stage (not NetworkXUnfeasible). Detect inf
    # demand explicitly so the exception type + message match nx.
    for node, d in node_demand.items():
        if _math.isinf(d):
            raise NetworkXError(f"node {node!r} has infinite demand")

    # Check feasibility: sum of demands must be zero
    # br-r37-c1-74xas: nx's exact wording is "total node demand is not
    # zero" — match it (still NetworkXUnfeasible).
    total_demand = sum(node_demand.values())
    if abs(total_demand) > 1e-10:
        raise NetworkXUnfeasible("total node demand is not zero")

    # Initialize flow dict
    flow = {u: {} for u in nodes}
    for u, v in G.edges():
        flow.setdefault(u, {})[v] = 0

    # Build residual graph and run successive shortest paths
    # NetworkX convention: negative demand = supply, positive = demand
    sources = [n for n in nodes if node_demand[n] < 0]
    sinks = [n for n in nodes if node_demand[n] > 0]
    remaining_supply = {n: -node_demand[n] for n in sources}
    remaining_demand = {n: node_demand[n] for n in sinks}

    # Successive shortest paths: augment along shortest cost path
    for _ in range(n * n):  # upper bound on iterations
        # Find shortest path from any source with remaining supply
        # to any sink with remaining demand using Bellman-Ford on residual
        best_path = None
        best_cost = float("inf")
        best_source = None
        best_sink = None

        for source in sources:
            if remaining_supply.get(source, 0) <= 1e-10:
                continue

            # BFS/Bellman-Ford on residual graph
            dist = {source: 0.0}
            pred = {source: None}
            # Relaxation
            for _ in range(n):
                updated = False
                for u in nodes:
                    if u not in dist:
                        continue
                    # Forward edges
                    if hasattr(G, "successors"):
                        succs = list(G.successors(u))
                    else:
                        succs = list(G.neighbors(u))
                    for v in succs:
                        data = G.get_edge_data(u, v)
                        if not isinstance(data, dict):
                            continue
                        cap = float(data.get(capacity, float("inf")))
                        current_flow = flow.get(u, {}).get(v, 0)
                        residual_cap = cap - current_flow
                        if residual_cap > 1e-10:
                            edge_cost = float(data.get(weight, 0))
                            new_dist = dist[u] + edge_cost
                            if v not in dist or new_dist < dist[v] - 1e-10:
                                dist[v] = new_dist
                                pred[v] = (u, "forward")
                                updated = True
                    # Backward edges (reverse flow)
                    if hasattr(G, "predecessors"):
                        preds_list = list(G.predecessors(u))
                    else:
                        preds_list = []
                    for v in preds_list:
                        current_flow = flow.get(v, {}).get(u, 0)
                        if current_flow > 1e-10:
                            data = G.get_edge_data(v, u)
                            edge_cost = (
                                -float(data.get(weight, 0))
                                if isinstance(data, dict)
                                else 0.0
                            )
                            new_dist = dist[u] + edge_cost
                            if v not in dist or new_dist < dist[v] - 1e-10:
                                dist[v] = new_dist
                                pred[v] = (u, "backward")
                                updated = True
                if not updated:
                    break

            # Check reachable sinks
            for sink in sinks:
                if sink in dist and remaining_demand.get(sink, 0) > 1e-10:
                    if dist[sink] < best_cost:
                        best_cost = dist[sink]
                        best_path = pred
                        best_source = source
                        best_sink = sink

        if best_path is None:
            break

        # Find bottleneck along the path
        path_nodes = []
        current = best_sink
        while current is not None:
            path_nodes.append(current)
            p = best_path.get(current)
            if p is None:
                break
            current = p[0] if p else None
        path_nodes.reverse()

        bottleneck = min(remaining_supply[best_source], remaining_demand[best_sink])
        # Also check edge capacities along path
        for i in range(len(path_nodes) - 1):
            u, v = path_nodes[i], path_nodes[i + 1]
            info = best_path.get(v)
            if info and info[1] == "forward":
                data = G.get_edge_data(u, v)
                cap = (
                    float(data.get(capacity, float("inf")))
                    if isinstance(data, dict)
                    else float("inf")
                )
                residual = cap - flow.get(u, {}).get(v, 0)
                bottleneck = min(bottleneck, residual)
            elif info and info[1] == "backward":
                bottleneck = min(bottleneck, flow.get(v, {}).get(u, 0))

        if bottleneck <= 1e-10:
            break

        # Augment flow along path
        for i in range(len(path_nodes) - 1):
            u, v = path_nodes[i], path_nodes[i + 1]
            info = best_path.get(v)
            if info and info[1] == "forward":
                flow.setdefault(u, {})[v] = flow.get(u, {}).get(v, 0) + bottleneck
            elif info and info[1] == "backward":
                flow.setdefault(v, {})[u] = flow.get(v, {}).get(u, 0) - bottleneck

        remaining_supply[best_source] -= bottleneck
        remaining_demand[best_sink] -= bottleneck

    # Check if all demands are satisfied
    for source in sources:
        if remaining_supply.get(source, 0) > 1e-10:
            raise NetworkXUnfeasible("no flow satisfies all node demands")
    for sink in sinks:
        if remaining_demand.get(sink, 0) > 1e-10:
            raise NetworkXUnfeasible("no flow satisfies all node demands")

    # br-mcfint: preserve int flow values when every input is int
    # (nx contract).
    if _mcf_inputs_all_integral(G, demand, capacity, weight):
        flow = _coerce_flow_dict_to_int(flow)
    return flow


def min_cost_flow_cost(G, demand="demand", capacity="capacity", weight="weight"):
    """Return the cost of the minimum cost flow.

    Parameters
    ----------
    G : DiGraph
    demand, capacity, weight : str, optional

    Returns
    -------
    float
    """
    flow = min_cost_flow(G, demand=demand, capacity=capacity, weight=weight)
    return cost_of_flow(G, flow, weight=weight)


def max_flow_min_cost(G, s, t, capacity="capacity", weight="weight"):
    """Find a maximum flow of minimum cost from *s* to *t*.

    First finds maximum flow value, then finds the min-cost flow
    achieving that value.

    Parameters
    ----------
    G : DiGraph
    s, t : node
        Source and sink.
    capacity, weight : str, optional

    Returns
    -------
    dict of dicts
        Flow dictionary.

    br-mfmcsign: by nx convention, a negative demand means the node
    *supplies* that much flow. A source thus has ``demand=-maxFlow``
    and a sink has ``demand=+maxFlow``. The previous implementation
    used the reversed signs (``{s: max_val, t: -max_val}``), which
    inverted supply/demand — the solver then tried to push flow from
    t to s and raised NetworkXUnfeasible on every valid input.
    """
    # Get max flow value
    max_val = maximum_flow_value(G, s, t, capacity=capacity)

    # _Set up demands per nx convention: source supplies (negative),
    # sink consumes (positive).
    H = G.copy()
    set_node_attributes(H, {s: -max_val, t: max_val}, name="demand")
    # _Set demand=0 for all other nodes that don't already have one.
    for n in H.nodes():
        if n != s and n != t:
            attrs = H.nodes[n] if hasattr(H.nodes, "__getitem__") else {}
            if isinstance(attrs, dict) and "demand" not in attrs:
                attrs["demand"] = 0

    return min_cost_flow(H, capacity=capacity, weight=weight)


def capacity_scaling(
    G,
    demand="demand",
    capacity="capacity",
    weight="weight",
    heap=_BINARY_HEAP_DEFAULT,
):
    """Find minimum cost flow using capacity scaling.

    This is an alias for ``min_cost_flow`` — the successive shortest
    paths implementation provides the same optimality guarantees.

    Parameters
    ----------
    G : DiGraph
    demand, capacity, weight : str, optional
    heap : class, optional
        Heap class. Default ``networkx.utils.heaps.BinaryHeap`` so the
        introspectable signature matches nx exactly. The fnx
        implementation manages its own heap; the kwarg is accepted
        for API drop-in compatibility.

    Returns
    -------
    tuple
        ``(flowCost, flowDict)`` matching NetworkX's return signature.
    """
    # br-r37-c1-3qt4m: nx's @not_implemented_for('undirected') on
    # capacity_scaling raises NetworkXNotImplemented before the
    # network_simplex empty-graph check.  Match the ordering.
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")
    # br-r37-c1-kpaki: nx's capacity_scaling uses its own path that
    # returns (0, {}) on empty input — it does NOT raise the
    # network_simplex "graph has no nodes" error min_cost_flow now
    # surfaces.  Match nx by short-circuiting before delegating.
    if len(G) == 0:
        return 0, {}
    try:
        flow = min_cost_flow(G, demand=demand, capacity=capacity, weight=weight)
    except NetworkXUnfeasible as exc:
        # br-r37-c1-8lsax: nx's capacity_scaling and network_simplex
        # raise NetworkXUnfeasible with DIFFERENT wording — capacity_
        # scaling uses "No flow satisfying all demands." (cap+period),
        # network_simplex uses "no flow satisfies all node demands".
        # min_cost_flow shares the network_simplex wording; translate
        # at this boundary so caller message-matching code aligns.
        msg = str(exc)
        if msg == "no flow satisfies all node demands":
            raise NetworkXUnfeasible("No flow satisfying all demands.") from None
        raise
    cost = cost_of_flow(G, flow, weight=weight)
    return cost, flow


def _validate_network_simplex_inputs(G, demand, capacity, weight):
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")

    if len(G) == 0:
        raise NetworkXError("graph has no nodes")

    total_demand = 0.0
    for node in G:
        node_attrs = G.nodes[node] if hasattr(G.nodes, "__getitem__") else {}
        if not isinstance(node_attrs, dict):
            continue
        node_demand = float(node_attrs.get(demand, 0))
        if _math.isinf(node_demand):
            raise NetworkXError(f"node {node!r} has infinite demand")
        total_demand += node_demand

    for u, v, edge_attrs in G.edges(data=True):
        if not isinstance(edge_attrs, dict):
            continue
        edge_weight = float(edge_attrs.get(weight, 0))
        if _math.isinf(edge_weight):
            raise NetworkXError(f"edge {(u, v)!r} has infinite weight")

        edge_capacity = float(edge_attrs.get(capacity, float("inf")))
        if edge_capacity < 0:
            raise NetworkXUnfeasible(f"edge {(u, v)!r} has negative capacity")

    if abs(total_demand) > 1e-10:
        raise NetworkXUnfeasible("total node demand is not zero")


def network_simplex(G, demand="demand", capacity="capacity", weight="weight"):
    """Find minimum cost flow using the network simplex algorithm.

    Returns both the cost and the flow dictionary.

    Parameters
    ----------
    G : DiGraph
    demand, capacity, weight : str, optional

    Returns
    -------
    (cost, flowDict) : tuple
    """
    _validate_network_simplex_inputs(G, demand, capacity, weight)
    flow = min_cost_flow(G, demand=demand, capacity=capacity, weight=weight)
    cost = cost_of_flow(G, flow, weight=weight)
    return (cost, flow)


def flow_hierarchy(G, weight=None):
    """Return the flow hierarchy of a directed graph.

    The flow hierarchy is the fraction of edges not in a cycle.

    Parameters
    ----------
    G : DiGraph
    weight : str or None, optional

    Returns
    -------
    float
        Value in [0, 1]. 1 means no edges are in cycles (DAG).
    """
    if G.number_of_edges() == 0:
        raise NetworkXError("flow_hierarchy not applicable to empty graphs")
    if not G.is_directed():
        # br-r37-c1-4elbw: nx raises NetworkXError with the exact text
        # "G must be a digraph in flow_hierarchy". The Rust binding
        # raised "flow_hierarchy requires a DiGraph", which broke
        # drop-in code matching nx's wording.
        raise NetworkXError("G must be a digraph in flow_hierarchy")
    if weight is not None:
        return _call_networkx_for_parity("flow_hierarchy", G, weight=weight)
    return _fnx.flow_hierarchy_rust(G)


