# br-r37-c1-methodqualname: align ``method.__qualname__`` (and
# ``__name__``) on the wrapped Graph methods with nx's canonical
# ``Graph.method`` form so:
# (a) ``inspect.signature(method)`` and ``method.__qualname__``
#     introspection looks the same as nx (debug repr, test fixtures,
#     drop-in libraries that branch on qualname)
# (b) Python's auto-generated TypeError on duplicate kwargs uses the
#     nx wording ``Graph.method() got multiple values for ...``
#     instead of leaking the fnx-private wrapper closure name.
#
# Same shape as cycle 173 br-r37-c1-updatename on Graph.update and
# the DegreeView / EdgeView class-name renames in cycles 157 / 166.
def _rename_method(method, name, qualname):
    try:
        method.__name__ = name
        method.__qualname__ = qualname
    except (AttributeError, TypeError):
        pass


# For each (class, method) combination, rename the directly-defined
# method to ``ClassName.method``.  Iteration order Graph -> DiGraph
# -> MultiGraph -> MultiDiGraph means shared function objects (eg.
# ``copy`` is shared across all 4 classes) get the qualname of the
# FIRST class that uses them — matching nx's "Graph.copy"
# convention for the inherited case.  fnx splits most other methods
# (add_edge, remove_edge, has_node, size, etc.) into per-class
# functions, so each class gets its own ``Class.method`` qualname
# matching nx exactly.
_METHOD_NAMES = (
    "add_edge", "remove_edge", "add_edges_from", "remove_edges_from",
    "add_node", "add_nodes_from", "remove_node", "remove_nodes_from",
    "has_node", "has_edge", "number_of_edges", "size", "copy",
    "edge_subgraph", "predecessors", "successors", "reverse",
)
_rename_seen = set()
for _cls in (Graph, DiGraph, MultiGraph, MultiDiGraph):
    for _meth_name in _METHOD_NAMES:
        # Only consider methods directly defined on this class
        # (not inherited via MRO).  Methods inherited from a base
        # already had their qualname set when the base was processed.
        _meth = vars(_cls).get(_meth_name)
        if _meth is None or id(_meth) in _rename_seen:
            continue
        _rename_seen.add(id(_meth))
        _rename_method(
            _meth, _meth_name, f"{_cls.__name__}.{_meth_name}",
        )
del _cls, _meth_name, _meth, _rename_seen, _METHOD_NAMES


class _ConversionNodeView(_Mapping):
    def __init__(self, view):
        self._view = view

    def __iter__(self):
        return iter(self._view)

    def __len__(self):
        return len(self._view)

    def __getitem__(self, node):
        return self._view._graph.nodes[node]

    def _data_rows(self, data=False, default=None):
        if data is False:
            return list(self)
        if data is True:
            return [(node, self[node]) for node in self]
        return [(node, self[node].get(data, default)) for node in self]

    def __call__(self, data=False, default=None):
        return self._data_rows(data=data, default=default)

    def data(self, data=True, default=None):
        return self._data_rows(data=data, default=default)

    def __and__(self, other):
        return set(self) & set(other)

    def __rand__(self, other):
        return set(other) & set(self)

    def __or__(self, other):
        return set(self) | set(other)

    def __ror__(self, other):
        return set(other) | set(self)

    def __sub__(self, other):
        return set(self) - set(other)

    def __rsub__(self, other):
        return set(other) - set(self)

    def __xor__(self, other):
        return set(self) ^ set(other)

    def __rxor__(self, other):
        return set(other) ^ set(self)


class _ConversionMultiEdgeQuery:
    """View-backed edge-query result for multigraph conversion views.

    Returned by ``view.edges(...)`` on multigraph conversion live views so
    callers see a lazy, set-like, view-backed object rather than a plain
    list (matches upstream OutMultiEdgeView / MultiEdgeView surface for
    keyed multiedge queries).
    """

    def __init__(self, view, *, nbunch=None, data=False, keys=False, default=None):
        self._view = view
        self._nbunch = nbunch
        self._data = data
        self._keys = keys
        self._default = default

    def _materialise(self):
        return self._view._edges(
            nbunch=self._nbunch,
            data=self._data,
            keys=self._keys,
        )

    def __iter__(self):
        return iter(self._materialise())

    def __len__(self):
        return len(self._materialise())

    def __contains__(self, item):
        return item in self._materialise()

    def __eq__(self, other):
        if isinstance(other, _ConversionMultiEdgeQuery):
            other = other._materialise()
        if isinstance(other, set):
            return set(self._materialise()) == other
        try:
            return list(self._materialise()) == list(other)
        except TypeError:
            return NotImplemented

    def __ne__(self, other):
        result = self.__eq__(other)
        if result is NotImplemented:
            return result
        return not result

    def __hash__(self):
        return None  # Mutable view, intentionally unhashable.

    def __repr__(self):
        return repr(self._materialise())

    def __getitem__(self, idx):
        return self._materialise()[idx]

    def __and__(self, other):
        return set(self._materialise()) & set(other)

    def __rand__(self, other):
        return set(other) & set(self._materialise())

    def __or__(self, other):
        return set(self._materialise()) | set(other)

    def __ror__(self, other):
        return set(other) | set(self._materialise())

    def __sub__(self, other):
        return set(self._materialise()) - set(other)

    def __rsub__(self, other):
        return set(other) - set(self._materialise())

    def __xor__(self, other):
        return set(self._materialise()) ^ set(other)

    def __rxor__(self, other):
        return set(other) ^ set(self._materialise())


class _ConversionEdgeView:
    def __init__(self, view):
        self._view = view

    def __iter__(self):
        # br-r37-c1-cev-mditer: nx's MultiEdgeView/InMultiEdgeView
        # default `keys=True` for __iter__ but `keys=False` for
        # __call__ (asymmetric). Match that on conversion views too.
        if self._view.is_multigraph():
            return iter(self(keys=True))
        return iter(self())

    def __len__(self):
        return len(self())

    def __contains__(self, edge):
        try:
            u, v = edge[:2]
        except (TypeError, ValueError):
            return False
        if u not in self._view._graph:
            return False
        return v in self._view.adj[u]

    def __getitem__(self, edge):
        u, v = edge
        if u not in self._view._graph or v not in self._view.adj[u]:
            raise KeyError(edge)
        return self._view.adj[u][v]

    def __call__(self, nbunch=None, data=False, keys=False, default=None):
        if isinstance(data, str):
            base = self._view._edges(nbunch=nbunch, data=True, keys=keys)
            if keys:
                return [
                    (u, v, k, attrs.get(data, default))
                    for u, v, k, attrs in base
                ]
            return [
                (u, v, attrs.get(data, default)) for u, v, attrs in base
            ]
        if data is None:
            base = self._view._edges(nbunch=nbunch, data=False, keys=keys)
            if keys:
                return [(u, v, k, default) for u, v, k in base]
            return [(u, v, default) for u, v in base]
        if self._view.is_multigraph():
            return _ConversionMultiEdgeQuery(
                self._view, nbunch=nbunch, data=data, keys=keys
            )
        return self._view._edges(nbunch=nbunch, data=data, keys=keys)

    def data(self, data=True, default=None, nbunch=None, keys=False):
        return self(nbunch=nbunch, data=data, keys=keys, default=default)

    def __and__(self, other):
        return set(self) & set(other)

    def __rand__(self, other):
        return set(other) & set(self)

    def __or__(self, other):
        return set(self) | set(other)

    def __ror__(self, other):
        return set(other) | set(self)

    def __sub__(self, other):
        return set(self) - set(other)

    def __rsub__(self, other):
        return set(other) - set(self)

    def __xor__(self, other):
        return set(self) ^ set(other)

    def __rxor__(self, other):
        return set(other) ^ set(self)

    # br-r37-c1-cev-setops: nx's converted-view EdgeView inherits from
    # _Set; the wrapper had |/&/-/^ but missing <=/</>=/>/isdisjoint
    # and __eq__. Same defect family as br-r37-c1-{fbtk0, s89yr};
    # identical fix shape on a different wrapper class.
    def __le__(self, other):
        return set(self) <= set(other) if hasattr(other, "__iter__") else NotImplemented

    def __lt__(self, other):
        return set(self) < set(other) if hasattr(other, "__iter__") else NotImplemented

    def __ge__(self, other):
        return set(self) >= set(other) if hasattr(other, "__iter__") else NotImplemented

    def __gt__(self, other):
        return set(self) > set(other) if hasattr(other, "__iter__") else NotImplemented

    def isdisjoint(self, other):
        return set(self).isdisjoint(other)

    def __eq__(self, other):
        from collections.abc import Set as _Set
        if isinstance(other, _ConversionEdgeView):
            return set(self) == set(other)
        if isinstance(other, _Set):
            return set(self) == set(other)
        return NotImplemented

    def __ne__(self, other):
        eq = self.__eq__(other)
        if eq is NotImplemented:
            return NotImplemented
        return not eq

    __hash__ = None

    get = _adjacency_view_get
    keys = _adjacency_view_keys
    items = _adjacency_view_items
    values = _adjacency_view_values


class _UnionKeyAtlas(_Mapping):
    def __init__(self, primary, secondary):
        self._primary = primary
        self._secondary = secondary

    def __iter__(self):
        yielded = set()
        for key in self._primary:
            yielded.add(key)
            yield key
        for key in self._secondary:
            if key not in yielded:
                yield key

    def __len__(self):
        return sum(1 for _ in self)

    def __getitem__(self, key):
        if key in self._primary:
            return self._primary[key]
        return self._secondary[key]


class _ConversionNeighborMap(_Mapping):
    def __init__(self, view, node, *, reverse=False):
        self._view = view
        self._node = node
        self._reverse = reverse

    def __iter__(self):
        if self._reverse:
            yield from self._view._pred_neighbors(self._node)
        else:
            yield from self._view._adj_neighbors(self._node)

    def __len__(self):
        return sum(1 for _ in self)

    def __getitem__(self, neighbor):
        if self._reverse:
            return self._view._pred_neighbor_value(self._node, neighbor)
        return self._view._adj_neighbor_value(self._node, neighbor)


class _ConversionAdjacencyView(_Mapping):
    def __init__(self, view, *, reverse=False):
        self._view = view
        self._reverse = reverse

    def __iter__(self):
        return iter(self._view)

    def __len__(self):
        return len(self._view)

    def __getitem__(self, node):
        if node not in self._view._graph:
            raise KeyError(f"Key {node} not found")
        return _ConversionNeighborMap(self._view, node, reverse=self._reverse)


class _ConversionGraphViewBase:
    _directed = False
    _multigraph = False
    adjlist_inner_dict_factory = dict
    adjlist_outer_dict_factory = dict
    edge_attr_dict_factory = dict
    graph_attr_dict_factory = dict
    node_attr_dict_factory = dict
    node_dict_factory = dict

    def __new__(cls, graph=None, *args, **kwargs):
        # br-r37-c1-y2b8t: build an EMPTY Rust base. The conversion-view classes
        # mix this in with the canonical PyO3 Graph/DiGraph (for isinstance
        # parity), whose __new__ eagerly copies the parent graph's entire node +
        # edge set into the view's own Rust storage on every to_directed() /
        # to_undirected() call — O(|V|+|E|). That storage is dead weight: every
        # query method below (nodes/edges/adj/succ/pred/neighbors/number_of_*/
        # size/degree/has_edge/adjacency/copy/__iter__/__len__/__contains__) is
        # overridden to answer through self._graph. super().__new__(cls) (cls's
        # MRO routes to the Graph/DiGraph base) allocates an empty graph in O(1);
        # __init__ wires up the live conversion view. Same fix as
        # _FilteredGraphView.__new__ (br-r37-c1-pgfd2).
        return super().__new__(cls)

    def __init__(self, graph):
        self.__dict__["_graph"] = graph
        self.__dict__["frozen"] = True
        self.__dict__["_nodes_view"] = _ConversionNodeView(self)
        self.__dict__["_edges_view"] = _ConversionEdgeView(self)
        self.__dict__["_adj_view"] = _ConversionAdjacencyView(self)
        if self.is_directed():
            self.__dict__["_succ_view"] = self._adj_view
            self.__dict__["_pred_view"] = _ConversionAdjacencyView(self, reverse=True)

    # br-r37-c1-cvempty: these must test the cached view for *presence*,
    # not truthiness.  The view objects define ``__len__``, so an empty
    # conversion view (0 nodes / 0 edges) is falsy — ``X or super().Y``
    # then fell through to the inherited canonical accessor, which on
    # the synthetic view recursed (number_of_edges -> edges -> empty,
    # falsy -> super().edges -> EdgesView.__len__ -> number_of_edges)
    # and blew the stack.  ``is not None`` resolves the cached view
    # regardless of emptiness; the ``super()`` branch survives only for
    # succ/pred on undirected views (where the view is never cached).
    @property
    def nodes(self):
        view = self.__dict__.get("_nodes_view")
        return view if view is not None else super().nodes

    @property
    def edges(self):
        view = self.__dict__.get("_edges_view")
        return view if view is not None else super().edges

    @property
    def adj(self):
        view = self.__dict__.get("_adj_view")
        return view if view is not None else super().adj

    @property
    def succ(self):
        view = self.__dict__.get("_succ_view")
        return view if view is not None else super().succ

    @property
    def pred(self):
        view = self.__dict__.get("_pred_view")
        return view if view is not None else super().pred

    @property
    def graph(self):
        # br-r37-c1-9ut0c: the fnx Graph base class exposes ``graph`` as a
        # ``_GraphAttrsDescriptor`` (a data descriptor), so an instance
        # ``__dict__`` entry cannot shadow it.  Surface the source graph's
        # attribute dict directly — a conversion view shares structure
        # with its source, so ``to_directed``/``to_undirected`` must
        # preserve graph-level attributes (parity with networkx).
        return self._graph.graph

    def __iter__(self):
        return iter(self._graph)

    def __len__(self):
        return len(self._graph)

    def __contains__(self, node):
        return node in self._graph

    def __getitem__(self, node):
        return self.adj[node]

    def __getattr__(self, name):
        if name in _FILTERED_VIEW_MUTATORS:
            return _frozen
        return getattr(self.copy(), name)

    # br-r37-c1-cvfrz: a conversion view's class is built with the
    # canonical Graph type as a second base (for isinstance parity), so
    # the inherited Rust mutators (add_node, add_edge, update, ...) sit
    # in the MRO ahead of ``__getattr__`` — exactly the defect fixed for
    # _FilteredGraphView in br-r37-c1-fgvfrz.  Calling them on the view
    # mutated its uninitialised Rust state as a silent no-op instead of
    # raising NetworkXError("Frozen graph can't be modified").  Shadow
    # every mutator on the base so it is resolved before the inherited
    # canonical method.
    add_node = _frozen
    add_nodes_from = _frozen
    remove_node = _frozen
    remove_nodes_from = _frozen
    add_edge = _frozen
    add_edges_from = _frozen
    add_weighted_edges_from = _frozen
    remove_edge = _frozen
    remove_edges_from = _frozen
    clear = _frozen
    clear_edges = _frozen
    update = _frozen

    def is_directed(self):
        return self._directed

    def is_multigraph(self):
        return self._multigraph

    def _nbunch(self, nbunch):
        if nbunch is None:
            return list(self)
        if nbunch in self._graph:
            return [nbunch]
        try:
            return [node for node in nbunch if node in self._graph]
        except TypeError:
            return []

    def _adj_neighbors(self, node):
        raise NotImplementedError

    def _adj_neighbor_value(self, node, neighbor):
        raise NotImplementedError

    def _pred_neighbors(self, node):
        yield from self._adj_neighbors(node)

    def _pred_neighbor_value(self, node, neighbor):
        return self._adj_neighbor_value(node, neighbor)

    def _edges(self, nbunch=None, data=False, keys=False):
        nodes = self._nbunch(nbunch)
        result = []
        if self.is_directed():
            for source in nodes:
                for target in self.adj[source]:
                    if self.is_multigraph():
                        for key, attrs in self.adj[source][target].items():
                            if data and keys:
                                result.append((source, target, key, attrs))
                            elif data:
                                result.append((source, target, attrs))
                            elif keys:
                                result.append((source, target, key))
                            else:
                                result.append((source, target))
                    else:
                        attrs = self.adj[source][target]
                        if data:
                            result.append((source, target, attrs))
                        else:
                            result.append((source, target))
            return result

        seen = set()
        for source in nodes:
            for target in self.adj[source]:
                if self.is_multigraph():
                    for key, attrs in self.adj[source][target].items():
                        marker = (frozenset((source, target)), key)
                        if marker in seen:
                            continue
                        seen.add(marker)
                        if data and keys:
                            result.append((source, target, key, attrs))
                        elif data:
                            result.append((source, target, attrs))
                        elif keys:
                            result.append((source, target, key))
                        else:
                            result.append((source, target))
                else:
                    marker = frozenset((source, target))
                    if marker in seen:
                        continue
                    seen.add(marker)
                    attrs = self.adj[source][target]
                    if data:
                        result.append((source, target, attrs))
                    else:
                        result.append((source, target))
