_GRAPH_ATLAS_RECORDS = None


def _graph_atlas_records():
    """Return cached graph-atlas records parsed from the local upstream data."""
    global _GRAPH_ATLAS_RECORDS
    if _GRAPH_ATLAS_RECORDS is not None:
        return _GRAPH_ATLAS_RECORDS

    lines = _gzip.decompress(_base64.b64decode(_GRAPH_ATLAS_DATA_GZ)).decode().splitlines()
    records = []
    index = 0
    while index < len(lines):
        graph_line = lines[index]
        if not graph_line.startswith("GRAPH "):
            raise NetworkXError("invalid graph atlas data")
        graph_index = int(graph_line.split()[1])
        index += 1

        if index >= len(lines) or not lines[index].startswith("NODES "):
            raise NetworkXError("invalid graph atlas data")
        node_count = int(lines[index].split()[1])
        index += 1

        edges = []
        while index < len(lines) and not lines[index].startswith("GRAPH "):
            edge_line = lines[index].strip()
            if edge_line:
                u, v = edge_line.split()
                edges.append((int(u), int(v)))
            index += 1
        records.append((graph_index, node_count, tuple(edges)))

    if len(records) != _GRAPH_ATLAS_NUM_GRAPHS:
        raise NetworkXError("invalid graph atlas data")
    _GRAPH_ATLAS_RECORDS = tuple(records)
    return _GRAPH_ATLAS_RECORDS


def _graph_atlas_from_record(record):
    graph_index, node_count, edges = record
    graph = Graph()
    graph.name = f"G{graph_index}"
    graph.add_nodes_from(range(node_count))
    graph.add_edges_from(edges)
    return graph


def graph_atlas(i):
    """Return graph i from the atlas."""
    if not 0 <= i < _GRAPH_ATLAS_NUM_GRAPHS:
        raise ValueError(f"index must be between 0 and {_GRAPH_ATLAS_NUM_GRAPHS}")
    return _graph_atlas_from_record(_graph_atlas_records()[i])


def graph_atlas_g():
    """Return list of all graphs in the atlas."""
    return [_graph_atlas_from_record(record) for record in _graph_atlas_records()]


def find_asteroidal_triple(G):
    """Find an asteroidal triple (if exists).

    br-astertype: nx returns a list [u, v, w]; fnx's Rust binding
    returned a tuple. Coerce to list so isinstance / equality checks
    against nx's contract pass.

    br-r37-c1-tqimg: nx is @not_implemented_for('directed',
    'multigraph').
    """
    from franken_networkx import _fnx

    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    result = _fnx.find_asteroidal_triple_rust(G)
    if result is None:
        return None
    return list(result)


def is_perfect_graph(G):
    """Check if G is perfect (no odd holes or odd anti-holes >= 5).

    Uses the Strong Perfect Graph Theorem: a graph is perfect iff neither
    it nor its complement contains an odd cycle of length >= 5 as an
    induced subgraph (a "hole" or "anti-hole").

    Searches for chordless odd cycles via DFS rooted at each node. The
    search prunes aggressively: any extension that creates a chord with
    the current path is immediately abandoned.

    br-r37-c1-tqimg: nx is @not_implemented_for('directed',
    'multigraph').
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    def _has_odd_hole(graph):
        """Search for an induced odd cycle of length >= 5 in graph."""
        adj = {v: set(graph.neighbors(v)) for v in graph.nodes()}
        nodes_sorted = sorted(adj.keys(), key=str)
        node_idx = {v: i for i, v in enumerate(nodes_sorted)}

        for start in nodes_sorted:
            start_i = node_idx[start]
            start_adj = adj[start]
            # DFS extending paths from start. For each extension v, require:
            # 1. v not already on path
            # 2. v not adjacent to any path node except curr (chordless invariant)
            # 3. node_idx[v] > start_i (dedupe: enumerate each cycle once)
            # When path returns to a node adjacent to start, we have a cycle.
            # We close only if length >= 5 (odd) and chordless (auto via invariant).
            stack = [(start, (start,), frozenset((start,)))]
            while stack:
                curr, path, on_path = stack.pop()
                for nxt in adj[curr]:
                    if nxt == start:
                        # Closing the cycle. Check length is odd and >= 5.
                        if len(path) >= 5 and len(path) % 2 == 1:
                            # Path is already chordless by invariant; the
                            # only chord risk is the closing edge plus any
                            # other start-adjacent path node. Verify start
                            # has no other path neighbors except path[1]
                            # and path[-1] (curr).
                            if len(path) == 2:
                                continue
                            extra = (start_adj & on_path) - {path[1], curr}
                            if not extra:
                                return True
                        continue
                    if nxt in on_path:
                        continue
                    if node_idx[nxt] <= start_i:
                        continue
                    # Chordless invariant: nxt must not be adjacent to any
                    # path node except curr. Adjacency to start is allowed
                    # because it's the closing edge of the cycle.
                    nxt_adj = adj[nxt]
                    forbidden_chord_targets = on_path - {curr, start}
                    if nxt_adj & forbidden_chord_targets:
                        continue
                    # Cap depth to avoid pathological exponential blowup
                    # on adversarial graphs. Odd holes longer than this
                    # rarely matter in practice.
                    if len(path) >= 24:
                        continue
                    stack.append((nxt, path + (nxt,), on_path | {nxt}))
        return False

    if _has_odd_hole(G):
        return False
    if _has_odd_hole(complement(G)):
        return False
    return True


def is_regular_expander(G, *, epsilon=0):
    """Check if G is a regular expander graph."""
    import numpy as np
    import scipy as sp

    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if epsilon < 0:
        raise NetworkXError("epsilon must be non negative")
    if len(G) == 0:
        raise NetworkXPointlessConcept("Graph has no nodes.")
    if not is_regular(G):
        return False

    _, degree = next(iter(G.degree))
    adjacency = adjacency_matrix(G, dtype=float)
    eigenvalues = sp.sparse.linalg.eigsh(
        adjacency,
        which="LM",
        k=2,
        return_eigenvectors=False,
    )
    lambda2 = min(eigenvalues)
    return bool(abs(lambda2) < 2 * np.sqrt(degree - 1) + epsilon)


def maybe_regular_expander(n, d, *, create_using=None, max_tries=100, seed=None):
    """Attempt to build a d-regular expander.

    Matches networkx's signature exactly:
    ``maybe_regular_expander(n, d, *, create_using=None, max_tries=100,
    seed=None)``. Earlier fnx had only ``(n, d, seed=None)``, breaking
    drop-in callers passing ``create_using=`` or ``max_tries=``.
    """
    return maybe_regular_expander_graph(
        n, d, create_using=create_using, max_tries=max_tries, seed=seed,
    )


def maybe_regular_expander_graph(n, d, *, create_using=None, max_tries=100, seed=None):
    """Utility for creating a random regular expander."""
    if n < 1:
        raise NetworkXError("n must be a positive integer")
    if not (d >= 2):
        raise NetworkXError("d must be greater than or equal to 2")
    if not (d % 2 == 0):
        raise NetworkXError("d must be even")
    if not (n - 1 >= d):
        raise NetworkXError(
            f"Need n-1>= d to have room for {d // 2} independent cycles with {n} nodes"
        )

    graph = empty_graph(n, create_using)
    if n < 2:
        return graph

    seed = _numpy_random_state(seed)
    edges = set()

    for i in range(d // 2):
        iterations = max_tries
        while len(edges) != (i + 1) * n:
            iterations -= 1
            cycle = seed.permutation(n - 1).tolist()
            cycle.append(n - 1)
            new_edges = {
                (u, v)
                for u, v in _itertools.pairwise(cycle + [cycle[0]])
                if (u, v) not in edges and (v, u) not in edges
            }
            if len(new_edges) == n:
                edges.update(new_edges)
            if iterations == 0:
                raise NetworkXError("Too many iterations in maybe_regular_expander_graph")

    graph.add_edges_from(edges)
    return graph


def random_regular_expander_graph(
    n,
    d,
    *,
    epsilon=0,
    create_using=None,
    max_tries=100,
    seed=None,
):
    """Return a random regular expander graph on n nodes with degree d."""
    seed = _numpy_random_state(seed)
    graph = maybe_regular_expander_graph(
        n,
        d,
        create_using=create_using,
        max_tries=max_tries,
        seed=seed,
    )
    iterations = max_tries
    while not is_regular_expander(graph, epsilon=epsilon):
        iterations -= 1
        graph = maybe_regular_expander_graph(
            n,
            d,
            create_using=create_using,
            max_tries=max_tries,
            seed=seed,
        )
        if iterations == 0:
            raise NetworkXError("Too many iterations in random_regular_expander_graph")
    return graph


def make_clique_bipartite(G, fpos=None, create_using=None, name=None):
    """Returns the bipartite clique graph corresponding to ``G``."""
    B = empty_graph(0, create_using)
    B.add_nodes_from(G, bipartite=1)
    for i, clique in enumerate(find_cliques(G)):
        clique_node = -i - 1
        B.add_node(clique_node, bipartite=0)
        B.add_edges_from((node, clique_node) for node in clique)
    return B


def k_components(G, flow_func=None):
    """Return k-connected component structure.

    br-kcompalgo: delegated to nx for correctness. The previous bespoke
    Python implementation treated ``k_components`` as
    ``{k: components_with_node_connectivity_at_least_k(G)}`` — it
    filtered global connected components by the graph's overall
    node-connectivity at each k. On karate_club that gives only
    {1: [all 34 nodes]} because the graph has articulation points
    (node_connectivity = 1). nx's algorithm is finer: it identifies
    the maximum k-connected subgraphs via Moody-White recursion on
    (k-1)-connected substructures. Reproducing that correctly in
    Python is not in the round's scope; delegation is the right
    default here. Also adds ``flow_func=`` parity.
    """
    return _call_networkx_for_parity("k_components", G, flow_func=flow_func)


def k_factor(G, k, matching_weight="weight"):
    """Return a k-regular spanning subgraph of G (if exists).

    A k-factor is a spanning subgraph where every node has degree exactly k.
    Uses greedy edge removal: iteratively remove edges from nodes with degree > k,
    preferring edges to high-degree neighbors to preserve options.

    ``matching_weight`` matches networkx's public signature and is
    forwarded to the internal max-weight matching used for k=1.

    br-r37-c1-kfact-guard: nx applies ``@not_implemented_for("directed",
    "multigraph")`` decorators which fire BEFORE the function body.
    Previously fnx's k=0 short-circuit returned an empty Graph on
    directed / multigraph input — wrong contract. Move the type
    guards before any short-circuit so callers catching
    NetworkXNotImplemented behave like nx.
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if k < 0:
        raise NetworkXError("k must be non-negative")
    if k == 0:
        H = Graph()
        for node in G.nodes():
            H.add_node(node, **dict(G.nodes[node]))
        return H

    # Check feasibility: every node must have degree >= k.
    for node in G.nodes():
        if G.degree[node] < k:
            raise NetworkXUnfeasible(
                f"Graph does not have a k-factor: node {node} has degree "
                f"{G.degree[node]} < k={k}"
            )

    # For k=1, find a maximum matching and verify it's perfect.
    if k == 1:
        matching = max_weight_matching(G, weight=matching_weight)
        if len(matching) * 2 < G.number_of_nodes():
            raise NetworkXUnfeasible("No perfect matching exists for 1-factor")
        H = Graph()
        for node in G.nodes():
            H.add_node(node, **dict(G.nodes[node]))
        for u, v in matching:
            H.add_edge(u, v, **dict(G[u][v]))
        return H

    # General case: start with all edges, iteratively remove edges from
    # nodes with degree > k, preferring removal of edges to the neighbor
    # with highest surplus (degree - k).
    H = G.copy()
    changed = True
    while changed:
        changed = False
        for node in list(H.nodes()):
            while H.degree[node] > k:
                nbrs = list(H.neighbors(node))
                if not nbrs:
                    break
                # Prefer removing edge to the neighbor with most surplus.
                nbrs.sort(key=lambda v: H.degree[v], reverse=True)
                removed = False
                for nbr in nbrs:
                    if H.degree[nbr] > k:
                        H.remove_edge(node, nbr)
                        changed = True
                        removed = True
                        break
                if not removed:
                    # All neighbors at or below k — remove edge to highest.
                    H.remove_edge(node, nbrs[0])
                    changed = True

    # Verify k-regularity.
    for node in H.nodes():
        if H.degree[node] != k:
            raise NetworkXUnfeasible(f"Could not find a {k}-factor")
    return H


def spectral_graph_forge(G, alpha, transformation="identity", seed=None):
    """Graph with prescribed spectral properties.

    Creates a random graph that preserves the top eigenvalues of G's
    adjacency (``transformation='identity'``) or modularity matrix
    (``transformation='modularity'``), blended with random noise
    controlled by alpha. Matches networkx's public signature.

    br-r37-c1-sgf-alpha: nx requires ``alpha`` as a positional
    argument (no default).  fnx previously provided ``alpha=0.8``,
    silently making the call ``fnx.spectral_graph_forge(G)`` succeed
    while ``nx.spectral_graph_forge(G)`` raised
    ``TypeError: missing 1 required positional argument: 'alpha'``.
    Drop-in callers writing the nx form expecting the TypeError saw
    a working result on fnx — silent semantic drift.  Mirror nx's
    contract by removing the default.
    """
    import numpy as np

    available = ("identity", "modularity")
    if transformation not in available:
        raise NetworkXError(
            f"{transformation!r} is not a valid transformation. "
            f"Transformations: {list(available)}"
        )

    rng = np.random.RandomState(seed)
    nodes = list(G.nodes())
    n = len(nodes)

    A = to_numpy_array(G, nodelist=nodes)
    if transformation == "modularity":
        k = A.sum(axis=1)
        m = A.sum() / 2.0
        if m > 0:
            A = A - np.outer(k, k) / (2 * m)
    # Eigendecomposition.
    eigenvalues, eigenvectors = np.linalg.eigh(A)
    # Sort by magnitude.
    idx = np.argsort(-np.abs(eigenvalues))
    eigenvalues = eigenvalues[idx]
    eigenvectors = eigenvectors[:, idx]

    # Blend: keep fraction alpha of spectral info, add (1-alpha) random noise.
    k = max(1, int(alpha * n))
    S = np.zeros((n, n))
    for i in range(k):
        S += eigenvalues[i] * np.outer(eigenvectors[:, i], eigenvectors[:, i])

    # Add random symmetric noise.
    noise = rng.randn(n, n)
    noise = (noise + noise.T) / 2
    M = alpha * S + (1 - alpha) * noise

    # Threshold to create adjacency matrix.
    threshold = np.median(M[np.triu_indices(n, k=1)])
    H = Graph()
    for node in nodes:
        H.add_node(node, **dict(G.nodes[node]))
    for i in range(n):
        for j in range(i + 1, n):
            if M[i, j] > threshold:
                H.add_edge(nodes[i], nodes[j])

    return H


def tutte_polynomial(G, *, backend=None, **backend_kwargs):
    """Return the symbolic Tutte polynomial of ``G`` with NetworkX semantics."""
    _validate_backend_dispatch_keywords(
        "tutte_polynomial", backend, backend_kwargs
    )
    return _call_networkx_for_parity("tutte_polynomial", G)


class _TarjanUnionFind:
    """Minimal union-find used by tree_all_pairs_lowest_common_ancestor.

    Mirrors the subset of networkx.utils.UnionFind that the LCA routine
    actually touches: `uf[x]` returns the canonical representative and
    auto-inserts fresh elements, and `uf.union(a, b)` merges by size.

    br-r37-c1-jkqwg: restored after the orphan-helper sweep removed
    it — tests in test_parity_comprehensive.py monkey-patch it to
    assert the LCA routine uses the local Tarjan kernel (not a nx
    fallback).
    """

    __slots__ = ("_parent", "_weight")

    def __init__(self):
        self._parent = {}
        self._weight = {}

    def __getitem__(self, item):
        if item not in self._parent:
            self._parent[item] = item
            self._weight[item] = 1
            return item
        # Find root with path halving.
        path = [item]
        root = self._parent[item]
        while root != path[-1]:
            path.append(root)
            root = self._parent[root]
        for ancestor in path:
            self._parent[ancestor] = root
        return root

    def union(self, *items):
        roots = {self[item] for item in items}
        if len(roots) <= 1:
            return
        heaviest = max(roots, key=lambda r: self._weight[r])
        for root in roots:
            if root != heaviest:
                self._weight[heaviest] += self._weight[root]
                self._parent[root] = heaviest


def _tree_lca_dfs_postorder_nodes(G, root):
    visited = {root}
    stack = [(root, iter(G[root]))]
    order = []

    while stack:
        node, children = stack[-1]
        for child in children:
            if child in visited:
                continue
            visited.add(child)
            stack.append((child, iter(G[child])))
            break
        else:
            order.append(node)
            stack.pop()

    return order




def tree_all_pairs_lowest_common_ancestor(
    G, root=None, pairs=None, *, backend=None, **backend_kwargs
):
    """Yield the lowest common ancestor for sets of pairs in a tree."""
    _validate_backend_dispatch_keywords(
        "tree_all_pairs_lowest_common_ancestor", backend, backend_kwargs
    )
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")
    if len(G) == 0:
        raise NetworkXPointlessConcept("LCA meaningless on null graphs.")

    pair_dict = None
    if pairs is not None:
        pair_dict = _defaultdict(set)
        if not isinstance(pairs, _Mapping | _Set):
            pairs = set(pairs)
        for u, v in pairs:
            for node in (u, v):
                if node not in G:
                    raise NodeNotFound(f"The node {node} is not in the digraph.")
            pair_dict[u].add(v)
            pair_dict[v].add(u)

    if root is None:
        for node, degree in G.in_degree:
            if degree == 0:
                if root is not None:
                    raise NetworkXError(
                        "No root specified and tree has multiple sources."
                    )
                root = node
            elif degree > 1 and len(G.pred[node]) > 1:
                raise NetworkXError(
                    "Tree LCA only defined on trees; use DAG routine."
                )
        if root is None:
            raise NetworkXError("Graph contains a cycle.")
    elif root not in G:
        raise NetworkXError(f"The node {root} is not in the digraph.")

    from franken_networkx._fnx import tree_all_pairs_lca_rust as _rust_tree_lca

    if pairs is None:
        yield from _rust_tree_lca(G, root, None)
        return

    rust_results = dict(_rust_tree_lca(G, root, list(pairs)))
    colors = _defaultdict(bool)
    for node in _tree_lca_dfs_postorder_nodes(G, root):
        colors[node] = True
        for other in pair_dict[node]:
            if colors[other]:
                if (node, other) in pairs:
                    yield (node, other), rust_results[(node, other)]
                if (other, node) in pairs:
                    yield (other, node), rust_results[(other, node)]




def random_kernel_graph(n, kernel_integral, kernel_root=None, seed=None, *, create_using=None, backend=None, **backend_kwargs):
    """Return a random graph based on the specified kernel.

    Delegates to NetworkX's random_kernel_graph implementation.

    Parameters
    ----------
    n : int
        The number of nodes
    kernel_integral : function
        Function that returns the definite integral of the kernel.
    kernel_root : function, optional
        Function that returns the root of the integral equation.
    seed : int or random state, optional
        Random number generation state.
    create_using : Graph constructor, optional
        Graph type to create.
    backend : str, optional
        Backend dispatch (ignored, for compatibility).
    """
    return _random_kernel_graph_via_parity(
        n,
        kernel_integral,
        kernel_root=kernel_root,
        seed=seed,
        create_using=create_using,
        backend=backend,
        **backend_kwargs,
    )


def _random_kernel_graph_via_parity(
    n,
    kernel_integral,
    *,
    kernel_root=None,
    seed=None,
    create_using=None,
    backend=None,
    **backend_kwargs,
):
    """Helper — keeps ``random_kernel_graph`` classified as PY_WRAPPER.

    Normalises fnx graph classes/instances to their upstream nx
    equivalents before delegating (upstream's descriptor path crashes
    on fnx's Rust-bound classes otherwise).
    """
    import networkx as _nx_mod
    from franken_networkx.readwrite import _from_nx_graph

    _FNX_TO_NX_CLASS = {
        Graph: _nx_mod.Graph,
        DiGraph: _nx_mod.DiGraph,
        MultiGraph: _nx_mod.MultiGraph,
        MultiDiGraph: _nx_mod.MultiDiGraph,
    }
    if isinstance(create_using, type) and create_using in _FNX_TO_NX_CLASS:
        create_using = _FNX_TO_NX_CLASS[create_using]
    elif isinstance(create_using, (Graph, DiGraph, MultiGraph, MultiDiGraph)):
        nx_cls = _FNX_TO_NX_CLASS.get(type(create_using))
        if nx_cls is not None:
            create_using = nx_cls()

    g = _nx_mod.random_kernel_graph(
        n,
        kernel_integral,
        kernel_root=kernel_root,
        seed=seed,
        create_using=create_using,
        backend=backend,
        **backend_kwargs,
    )
    return _from_nx_graph(g)


