def relabel_nodes(G, mapping, copy=True):
    """Relabel the nodes of the graph G.

    Parameters
    ----------
    G : Graph or DiGraph
        The input graph.
    mapping : dict or callable
        Either a dictionary mapping old labels to new labels, or a callable
        that takes a node and returns a new label.
    copy : bool, optional (default=True)
        If True, return a new graph. If False, relabel in place.

    Returns
    -------
    H : Graph or DiGraph
        The relabeled graph. If ``copy=False``, this is the same object as G.
    """
    if callable(mapping):
        _map = {n: mapping(n) for n in G.nodes()}
    else:
        _map = mapping

    if copy:
        # br-r37-c1-k7dct: SubgraphView's class is _FilteredGraphView,
        # whose __init__ requires a ``graph`` arg — bare ``cls()`` fails.
        # Route through the canonical-class resolver.
        H = _concrete_class_for(G)()
        H.graph.update(G.graph)
        for n in G.nodes():
            new_n = _map.get(n, n)
            H.add_node(new_n, **G.nodes[n])
        if G.is_multigraph():
            # 4-tuple form avoids `key=key, **d` collision when d contains
            # a 'key' attribute (franken_networkx-uphdr).
            new_edges = [
                (_map.get(u, u), _map.get(v, v), key, dict(d))
                for u, v, key, d in G.edges(keys=True, data=True)
            ]
            undirected = not G.is_directed()
            seen_edges = set()
            for index, (source, target, key, data) in enumerate(new_edges):
                while (source, target, key) in seen_edges:
                    if not isinstance(key, int | float):
                        key = 0
                    key += 1
                seen_edges.add((source, target, key))
                if undirected:
                    seen_edges.add((target, source, key))
                new_edges[index] = (source, target, key, data)
            H.add_edges_from(new_edges)
        else:
            # br-r37-c1-kmxke: batched (see union_all). Node-MERGING
            # relabels can collapse multiple old edges onto one new pair —
            # the batch path merges attrs in iteration order, identical to
            # the per-edge add_edge sequence it replaces.
            H.add_edges_from(
                [
                    (_map.get(u, u), _map.get(v, v), dict(d))
                    for u, v, d in G.edges(data=True)
                ]
            )
        # br-norebuild: H was built via _concrete_class_for(G)(), which always
        # returns the canonical fnx type, so the previous _from_nx_graph(H) was a
        # redundant SECOND full construction of an already-correct fnx graph
        # (verified node/edge/adjacency order + attrs identical to networkx).
        return H
    else:
        mapping_keys = set(_map)
        mapping_values = set(_map.values())
        if mapping_keys & mapping_values:
            dependency_nodes = []
            dependency_seen = set()
            dependency_edges = {}
            indegree = {}

            def add_dependency_node(node):
                if node in dependency_seen:
                    return
                dependency_seen.add(node)
                dependency_nodes.append(node)
                dependency_edges[node] = []
                indegree[node] = indegree.get(node, 0)

            for old, new in _map.items():
                add_dependency_node(old)
                add_dependency_node(new)
                if old == new:
                    continue
                if new not in dependency_edges[old]:
                    dependency_edges[old].append(new)
                    indegree[new] = indegree.get(new, 0) + 1

            queue = _deque(node for node in dependency_nodes if indegree[node] == 0)
            topo_order = []
            while queue:
                node = queue.popleft()
                topo_order.append(node)
                for neighbor in dependency_edges[node]:
                    indegree[neighbor] -= 1
                    if indegree[neighbor] == 0:
                        queue.append(neighbor)

            if len(topo_order) != len(dependency_nodes):
                raise NetworkXUnfeasible(
                    "The node label sets are overlapping and no ordering can "
                    "resolve the mapping. Use copy=True."
                )

            nodes = list(reversed(topo_order))
        else:
            nodes = [n for n in G if n in _map]

        multigraph = G.is_multigraph()
        directed = G.is_directed()

        for old in nodes:
            try:
                new = _map[old]
                G.add_node(new, **dict(G.nodes[old]))
            except KeyError:
                continue

            if new == old:
                continue

            if multigraph:
                new_edges = [
                    (new, new if old == target else target, key, dict(data))
                    for target, keyed_data in G[old].items()
                    for key, data in keyed_data.items()
                ]
                if directed:
                    new_edges += [
                        (new if old == source else source, new, key, dict(data))
                        for source, keyed_data in G.pred[old].items()
                        for key, data in keyed_data.items()
                    ]

                seen = set()
                for index, (source, target, key, data) in enumerate(new_edges):
                    if target in G[source] and key in G[source][target]:
                        new_key = key if isinstance(key, (int, float)) else 0
                        while new_key in G[source][target] or (target, new_key) in seen:
                            new_key += 1
                        new_edges[index] = (source, target, new_key, data)
                        seen.add((target, new_key))
            else:
                new_edges = [
                    (new, new if old == target else target, dict(data))
                    for target, data in G[old].items()
                ]
                if directed:
                    new_edges += [
                        (new if old == source else source, new, dict(data))
                        for source, data in G.pred[old].items()
                    ]

            G.remove_node(old)
            G.add_edges_from(new_edges)
        return G


def to_dict_of_lists(G, nodelist=None):
    """Return adjacency representation as a dictionary of lists.

    Parameters
    ----------
    G : Graph or DiGraph
        The input graph.
    nodelist : list, optional
        Use only nodes in *nodelist*. Default: all nodes.

    Returns
    -------
    d : dict
        ``d[u]`` is the list of neighbors of node u.
    """
    # br-r37-c1-6o3wi/br-r37-c1-nocb2: native fast path for exact simple
    # Graph/DiGraph with no nodelist. Builds {u: [v,...]} in Rust with
    # adjacency/successor-order neighbor lists, bypassing the slow per-node
    # G.neighbors() wrapper iteration.
    if nodelist is None and (type(G) is Graph or type(G) is DiGraph):
        _fast = _fnx.to_dict_of_lists_undirected(G)
        if _fast is not None:
            return _fast
    if nodelist is None:
        nodelist = G
    return {n: [nb for nb in G.neighbors(n) if nb in nodelist] for n in nodelist}


def _empty_graph_from_create_using(create_using, default=Graph):
    """Normalize NetworkX-style ``create_using`` inputs to an empty graph."""
    if create_using is None:
        return default()

    if isinstance(create_using, type):
        return create_using()

    G = create_using
    if hasattr(G, "clear"):
        G.clear()
    return G


class _LiveMultiEdgeDataView(dict):
    def __init__(self, graph, u, v):
        super().__init__()
        self._graph = graph
        self._u = u
        self._v = v

    def _current(self):
        return self._graph[self._u][self._v]

    def __iter__(self):
        return iter(self._current())

    def __len__(self):
        return len(self._current())

    def __contains__(self, key):
        return key in self._current()

    def __getitem__(self, key):
        return self._current()[key]

    def items(self):
        return self._current().items()

    def keys(self):
        return self._current().keys()

    def values(self):
        return self._current().values()

    def get(self, key, default=None):
        return self._current().get(key, default)

    def copy(self):
        return dict(self._current())

    def __eq__(self, other):
        return dict(self.items()) == other

    def __repr__(self):
        return repr(dict(self.items()))

    # br-r37-c1-lmev-mutate: dict-subclass inheritance from br-r37-c1-etbv4
    # made `isinstance(view, dict)` True (good — restores nx parity for
    # type-checks), but inherited dict.__setitem__/clear/update etc.
    # silently mutated the inherited (always-empty) dict storage rather
    # than the live graph or the user-visible view. Net effect: the
    # assignment vanished — `view['k'] = v` returned without error,
    # then iterating the view didn't show 'k', and the underlying graph
    # was never updated. nx's AtlasView raises TypeError on the same
    # operations; match that contract so silent data-loss can't happen.
    def _readonly(self, *args, **kwargs):
        raise TypeError(
            f"'{type(self).__name__}' object does not support item assignment"
        )

    __setitem__ = _readonly
    __delitem__ = _readonly
    clear = _readonly
    pop = _readonly
    popitem = _readonly
    setdefault = _readonly
    update = _readonly
    __ior__ = _readonly

    def __reduce__(self):
        # br-r37-c1-lmev-pickle: dict-subclass pickle protocol calls
        # __setitem__ on the new instance to repopulate it. The
        # _readonly mutation guards (br-r37-c1-vuauj) made every read
        # path raise during unpickling, so pickle.loads on any
        # to_dict_of_dicts(MultiGraph) output crashed. Snapshot to a
        # plain dict at pickle time — the view's liveness depends on
        # the graph reference, which can't survive pickling anyway.
        return (dict, (dict(self.items()),))


def _checked_create_using(create_using=None, *, directed=None, multigraph=None, default=Graph):
    """Validate and clear ``create_using`` using NetworkX's contract."""
    default_graph_type = _classic_default_graph_type(default)
    probe = create_using if create_using is not None else default_graph_type
    if isinstance(probe, type):
        probe = probe()

    if not all(hasattr(probe, attr) for attr in ("clear", "is_directed", "is_multigraph")):
        raise TypeError("create_using is not a valid NetworkX graph type or instance")

    if directed is not None:
        if directed and not probe.is_directed():
            raise NetworkXError("create_using must be directed")
        if not directed and probe.is_directed():
            raise NetworkXError("create_using must not be directed")

    if multigraph is not None:
        if multigraph and not probe.is_multigraph():
            raise NetworkXError("create_using must be a multi-graph")
        if not multigraph and probe.is_multigraph():
            raise NetworkXError("create_using must not be a multi-graph")

    return _empty_graph_from_create_using(create_using, default=default_graph_type)


def _copy_graph_into(source, target):
    """Populate ``target`` with the nodes, edges, and graph attrs from ``source``."""
    target.graph.update(dict(source.graph))
    for node, attrs in source.nodes(data=True):
        target.add_node(node, **dict(attrs))

    if source.is_multigraph():
        for u, v, key, attrs in source.edges(keys=True, data=True):
            target.add_edges_from([(u, v, key, dict(attrs))])
    else:
        for u, v, attrs in source.edges(data=True):
            target.add_edge(u, v, **dict(attrs))

    return target


def _checked_directed_create_using(create_using=None, *, default=DiGraph):
    """Validate ``create_using`` for directed-growth generators."""
    default_graph_type = _classic_default_graph_type(default)
    probe = create_using if create_using is not None else default_graph_type
    if isinstance(probe, type):
        probe = probe()

    if not all(hasattr(probe, attr) for attr in ("clear", "is_directed", "is_multigraph")):
        raise TypeError("create_using is not a valid NetworkX graph type or instance")
    if not probe.is_directed():
        raise NetworkXError("create_using must indicate a Directed Graph")

    return _empty_graph_from_create_using(create_using, default=default_graph_type)


def _nodes_or_number_local(value):
    """Return ``(value, nodes)`` following NetworkX ``nodes_or_number`` rules."""
    try:
        nodes = list(range(value))
    except TypeError:
        nodes = tuple(value)
    else:
        if value < 0:
            raise NetworkXError(f"Negative number of nodes not valid: {value}")
    return value, nodes


def _tree_edges_local(n, r):
    """Yield rooted r-ary tree edges in NetworkX insertion order."""
    if n == 0:
        return

    # br-treedeque: use a deque (O(1) popleft) instead of a list with pop(0)
    # (O(n) front-shift). The list version was O(n^2) for the edge generation
    # alone -- ~42x slower at n=300k (2.7s -> 67ms) -- which the construction
    # tax masked on small trees. FIFO order is unchanged, so the yielded edge
    # sequence is byte-identical.
    nodes = iter(range(n))
    parents = _deque([next(nodes)])
    while parents:
        source = parents.popleft()
        for _ in range(r):
            try:
                target = next(nodes)
            except StopIteration:
                break
            parents.append(target)
            yield source, target


def _classic_default_graph_type(default):
    """Map a default graph constructor or instance to the Franken graph surface."""
    if default is None:
        return Graph
    if default in (Graph, DiGraph, MultiGraph, MultiDiGraph):
        return default

    probe = default() if isinstance(default, type) else default
    if probe.is_multigraph():
        return MultiDiGraph if probe.is_directed() else MultiGraph
    return DiGraph if probe.is_directed() else Graph


def _classic_graph_from_create_using(create_using=None, default=Graph):
    """Create an empty graph for classic generator wrappers without NetworkX."""
    if create_using is None:
        return default()

    if isinstance(create_using, type):
        return create_using()

    if not hasattr(create_using, "clear"):
        raise TypeError("create_using is not a valid NetworkX graph type or instance")

    create_using.clear()
    return create_using


def _add_nodes_in_order(graph, nodes):
    """Add nodes one-by-one to preserve NetworkX insertion-order semantics."""
    for node in nodes:
        graph.add_node(node)


def _classic_named_graph_from_adjlist(
    adjacency, create_using=None, name=None, directed_error="Directed Graph not supported in create_using"
):
    """Build a named undirected graph from an adjacency dict with NetworkX parity."""
    graph = _classic_graph_from_create_using(create_using)
    if graph.is_directed():
        raise NetworkXError(directed_error)

    _add_nodes_in_order(graph, adjacency)
    if graph.is_multigraph():
        seen = {}
        for node, neighbors in adjacency.items():
            for neighbor in neighbors:
                if neighbor not in seen:
                    graph.add_edge(node, neighbor)
            seen[node] = 1
    else:
        graph.add_edges_from(
            (node, neighbor) for node, neighbors in adjacency.items() for neighbor in neighbors
        )

    if name is not None:
        graph.graph["name"] = name
    return graph


def _copy_graph_shallow(G):
    """Return a shallow graph copy preserving graph, node, and edge attrs."""
    # br-r37-c1-s8w2p: SubgraphView class can't be empty-constructed.
    H = _concrete_class_for(G)()
    H.graph.update(dict(G.graph))
    for node, attrs in G.nodes(data=True):
        H.add_node(node, **dict(attrs))
    if G.is_multigraph():
        for u, v, key, attrs in G.edges(keys=True, data=True):
            H.add_edges_from([(u, v, key, dict(attrs))])
    else:
        for u, v, attrs in G.edges(data=True):
            H.add_edge(u, v, **dict(attrs))
    return H


def _validate_same_graph_family(graphs):
    """Raise on mixed directedness or multigraph-ness, matching NetworkX."""
    if not graphs:
        return

    first = graphs[0]
    directed = first.is_directed()
    multigraph = first.is_multigraph()
    for G in graphs[1:]:
        if G.is_directed() != directed:
            raise NetworkXError("All graphs must be directed or undirected.")
        if G.is_multigraph() != multigraph:
            raise NetworkXError("All graphs must be graphs or multigraphs.")


def _graph_has_edge_attribute(G, name):
    """Return True when any edge carries attribute ``name``."""
    if G.is_multigraph():
        return any(name in attrs for _, _, _, attrs in G.edges(keys=True, data=True))
    return any(name in attrs for _, _, attrs in G.edges(data=True))


def from_dict_of_lists(d, create_using=None):
    """Return a graph from a dictionary of lists.

    Parameters
    ----------
    d : dict of lists
        ``d[u]`` is the list of neighbors of node u.
    create_using : Graph constructor, optional
        Graph type to create. Default ``Graph()``.

    Returns
    -------
    G : Graph or DiGraph
    """
    G = _empty_graph_from_create_using(create_using)
    _add_nodes_in_order(G, d)
    if G.is_multigraph() and not G.is_directed():
        seen = {}
        for node, neighbors in d.items():
            for nb in neighbors:
                if nb not in seen:
                    G.add_edge(node, nb)
            seen[node] = 1
    else:
        G.add_edges_from((node, nb) for node, neighbors in d.items() for nb in neighbors)
    return G


def to_edgelist(G, nodelist=None):
    """Return a list of edges in the graph.

    Parameters
    ----------
    G : Graph or DiGraph
        The input graph.
    nodelist : list, optional
        Use only edges with both endpoints in *nodelist*.

    Returns
    -------
    edges : EdgeDataView (or similar iterable)
        _Iterable of ``(u, v, data_dict)``.

    br-r37-c1-rsvst / br-r37-c1-qwan6: nx returns ``G.edges(data=True)``
    directly — a live ``EdgeDataView``, not a materialized list. Mirror nx by
    returning the view itself so ``type(to_edgelist(G)).__name__`` matches nx
    ("EdgeDataView") for drop-in type/isinstance checks. The former
    ``_fnx.to_edgelist_simple`` fast path materialized the edges into an
    ``_EdgeListWithSetAlgebra`` — which broke the type name AND was slower than
    the lazy view (3611us vs 1.7us to construct, 5103us vs 4290us to fully
    iterate on a 5k-edge graph), so it is removed.
    """
    if nodelist is not None:
        return G.edges(nodelist, data=True)
    return G.edges(data=True)


def convert_node_labels_to_integers(
    G, first_label=0, ordering="default", label_attribute=None
):
    """Return a copy of G with nodes relabeled as consecutive integers.

    Parameters
    ----------
    G : Graph or DiGraph
        The input graph.
    first_label : int, optional
        Starting integer label. Default ``0``.
    ordering : str, optional
        Node ordering strategy. Default ``'default'`` (uses ``G.nodes()``
        iteration order).  Also supports ``'sorted'``, ``'increasing degree'``,
        and ``'decreasing degree'``.
    label_attribute : str or None, optional
        If given, store old label under this node attribute name.

    Returns
    -------
    H : Graph or DiGraph
        A new graph with integer node labels.
    """
    # br-cnlti-tiebreak: nx breaks degree ties by node value (it sorts
    # (degree, node) tuples); fnx's key=lambda n: G.degree[n] was a
    # stable-by-degree sort that preserved the original iteration
    # order on ties. That produced a different int mapping on graphs
    # where nodes share the same degree (every graph except a
    # strictly-heterogeneous-degree one). Match nx's tuple-sort so
    # increasing/decreasing degree ordering yields the identical
    # integer mapping.
    if ordering == "default":
        nodes = list(G.nodes())
    elif ordering == "sorted":
        nodes = sorted(G.nodes())
    elif ordering == "increasing degree":
        dv_pairs = [(d, n) for (n, d) in G.degree()]
        dv_pairs.sort()
        nodes = [n for _, n in dv_pairs]
    elif ordering == "decreasing degree":
        dv_pairs = [(d, n) for (n, d) in G.degree()]
        dv_pairs.sort()
        dv_pairs.reverse()
        nodes = [n for _, n in dv_pairs]
    else:
        raise NetworkXError(f"Unknown node ordering: {ordering}")

    mapping = {old: first_label + i for i, old in enumerate(nodes)}
    H = relabel_nodes(G, mapping, copy=True)

    if label_attribute is not None:
        for old, new in mapping.items():
            H.nodes[new][label_attribute] = old

    return H


def to_pandas_edgelist(
    G, source="source", target="target", nodelist=None, dtype=None, edge_key=None
):
    """Return the graph edge list as a Pandas DataFrame.

    Parameters
    ----------
    G : Graph or DiGraph
        The input graph.
    source : str, optional
        Column name for source nodes. Default ``'source'``.
    target : str, optional
        Column name for target nodes. Default ``'target'``.
    nodelist : list, optional
        Use only edges with both endpoints in *nodelist*.
    dtype : dict, optional
        Column dtypes passed to DataFrame constructor.
    edge_key : str, optional
        Column name for edge keys on multigraph inputs. If ``None``,
        edge keys are omitted.

    Returns
    -------
    df : pandas.DataFrame
    """
    import pandas as pd

    if G.is_multigraph():
        if nodelist is None:
            edgelist = list(G.edges(keys=True, data=True))
        else:
            edgelist = list(G.edges(nodelist, keys=True, data=True))
        all_attrs = set().union(
            *(edge_attrs.keys() for _, _, _, edge_attrs in edgelist)
        )
        if source in all_attrs:
            raise NetworkXError(f"Source name {source!r} is an edge attr name")
        if target in all_attrs:
            raise NetworkXError(f"Target name {target!r} is an edge attr name")
        payload = {
            source: [u for u, _, _, _ in edgelist],
            target: [v for _, v, _, _ in edgelist],
        }
        if edge_key is not None:
            if edge_key in all_attrs:
                raise NetworkXError(f"Edge key name {edge_key!r} is an edge attr name")
            payload[edge_key] = [k for _, _, k, _ in edgelist]
        nan = float("nan")
        payload.update(
            {
                attr: [edge_attrs.get(attr, nan) for _, _, _, edge_attrs in edgelist]
                for attr in all_attrs
            }
        )
        return pd.DataFrame(payload, dtype=dtype)

    if nodelist is None:
        # br-tpenative: native edge materializer for exact simple Graph /
        # DiGraph avoids the per-edge EdgeView Python tax. to_edgelist_simple
        # returns (u, v, attr_dict) tuples (live Python attr dicts, read-only
        # here) in nx G.edges() order; None for multigraph / unsupported.
        edgelist = None
        if type(G) in (Graph, DiGraph):
            edgelist = _fnx.to_edgelist_simple(G)
        if edgelist is None:
            edgelist = list(G.edges(data=True))
    else:
        edgelist = list(G.edges(nodelist, data=True))
    all_attrs = set().union(*(edge_attrs.keys() for _, _, edge_attrs in edgelist))
    if source in all_attrs:
        raise NetworkXError(f"Source name {source!r} is an edge attr name")
    if target in all_attrs:
        raise NetworkXError(f"Target name {target!r} is an edge attr name")
    nan = float("nan")
    payload = {
        source: [u for u, _, _ in edgelist],
        target: [v for _, v, _ in edgelist],
    }
    payload.update(
        {
            attr: [edge_attrs.get(attr, nan) for _, _, edge_attrs in edgelist]
            for attr in all_attrs
        }
    )
    return pd.DataFrame(payload, dtype=dtype)


def from_pandas_edgelist(
    df,
    source="source",
    target="target",
    edge_attr=None,
    create_using=None,
    edge_key=None,
    *,
    backend=None,
    **backend_kwargs,
):
    """Return a graph from a Pandas DataFrame of edges.

    Parameters
    ----------
    df : pandas.DataFrame
        DataFrame with at least two columns for source and target nodes.
    source : str, optional
        Column name for source nodes. Default ``'source'``.
    target : str, optional
        Column name for target nodes. Default ``'target'``.
    edge_attr : str, list of str, True, or None, optional
        Edge attributes to include. ``True`` means all columns except source
        and target. ``None`` means no attributes.
    create_using : Graph constructor, optional
        Graph type to create. Default ``Graph()``.

    Returns
    -------
    G : Graph or DiGraph
    """
    _validate_backend_dispatch_keywords("from_pandas_edgelist", backend, backend_kwargs)
    graph = _empty_graph_from_create_using(create_using)

    if edge_attr is None:
        if graph.is_multigraph() and edge_key is not None:
            for u, v, edge_key_value in zip(df[source], df[target], df[edge_key]):
                _add_json_multiedge(graph, u, v, edge_key_value, {})
        else:
            graph.add_edges_from(zip(df[source], df[target]))
        return graph

    reserved_columns = [source, target]
    if graph.is_multigraph() and edge_key is not None:
        reserved_columns.append(edge_key)

    if isinstance(edge_attr, bool) and edge_attr:
        attr_col_headings = [column for column in df.columns if column not in reserved_columns]
    elif isinstance(edge_attr, list | tuple):
        attr_col_headings = edge_attr
    else:
        attr_col_headings = [edge_attr]
    if len(attr_col_headings) == 0:
        raise NetworkXError(
            f"Invalid edge_attr argument: No columns found with name: {attr_col_headings}"
        )

    try:
        attribute_data = zip(*[df[column] for column in attr_col_headings])
    except (KeyError, TypeError) as err:
        msg = f"Invalid edge_attr argument: {edge_attr}"
        raise NetworkXError(msg) from err

    if graph.is_multigraph():
        if edge_key is not None:
            try:
                attribute_data = zip(attribute_data, df[edge_key])
            except (KeyError, TypeError) as err:
                msg = f"Invalid edge_key argument: {edge_key}"
                raise NetworkXError(msg) from err

        for source_node, target_node, attrs in zip(df[source], df[target], attribute_data):
            if edge_key is not None:
                attrs, edge_key_value = attrs
                _add_json_multiedge(
                    graph,
                    source_node,
                    target_node,
                    edge_key_value,
                    dict(zip(attr_col_headings, attrs)),
                )
            else:
                actual_key = graph.add_edge(source_node, target_node)
                graph[source_node][target_node][actual_key].update(zip(attr_col_headings, attrs))
    else:
        for source_node, target_node, attrs in zip(df[source], df[target], attribute_data):
            graph.add_edge(source_node, target_node)
            graph[source_node][target_node].update(zip(attr_col_headings, attrs))

    return graph


def to_numpy_array(
    G,
    nodelist=None,
    dtype=None,
    order=None,
    multigraph_weight=sum,
    weight="weight",
    nonedge=0.0,
):
    """Return the adjacency matrix of G as a NumPy array.

    Parameters
    ----------
    G : Graph or DiGraph
        The input graph.
    nodelist : list, optional
        Rows and columns are ordered according to the nodes in *nodelist*.
        If ``None``, the ordering is produced by ``G.nodes()``.
    dtype : NumPy dtype, optional
        The NumPy data type of the array. Default ``numpy.float64``.
    order : {'C', 'F'}, optional
        Memory layout passed to ``numpy.full``.
    multigraph_weight : callable, optional
        Aggregation function used to combine parallel edge weights for
        multigraph inputs.
    weight : str or None, optional
        Edge attribute key used as weight. If ``None``, every edge has
        weight 1. Default ``'weight'``.
    nonedge : float, optional
        Value used for non-edges. Default ``0.0``.

    Returns
    -------
    A : numpy.ndarray
        Adjacency matrix as a 2-D NumPy array.
    """
    import numpy as np

    if nodelist is None:
        nodelist = list(G)
    else:
        nodelist = list(nodelist)
        if len(set(nodelist)) != len(nodelist):
            raise NetworkXError("nodelist contains duplicates.")
        missing = set(nodelist) - set(G)
        if missing:
            raise NetworkXError(f"Nodes {missing} in nodelist is not in G")

    matrix = np.full(
        (len(nodelist), len(nodelist)),
        nonedge,
        dtype=dtype,
        order=order,
    )

    # br-r37-c1-lqlx2: native Rust COO builder, same fast path as
    # to_scipy_sparse_array.  Scatter (rows, cols, data) into the
    # pre-allocated dense matrix.
    if (
        _native_adjacency_arrays is not None
        and not G.is_multigraph()
        and isinstance(G, (Graph, DiGraph))
        and (weight is None or isinstance(weight, str))
    ):
        # br-r37-c1-hits-bipartite-svds-degenerate-xjar9: use the native
        # helper only when no edge attrs are read. Python-visible mutations
        # like ``G[u][v]["weight"] = 7`` can otherwise be stale in Rust
        # storage, while the fallback reads the live Python attr dicts.
        #
        # br-tnaweighted: extend the native COO builder to the weighted case
        # (string ``weight`` key). Unlike ``to_scipy_sparse_array`` we never
        # need native int-vs-float dtype inference here: the matrix dtype is
        # already fixed by ``np.full(..., nonedge, dtype=...)`` above (float64
        # for the default ``nonedge=0.0``), so the f64-returning native helper
        # scatters into it exactly as the Python ``G._adj`` loop would assign
        # ``edge_attrs.get(weight, 1)``. Direct ``G[u][v][k]=v`` mutations can
        # be stale in Rust storage, so push them into ``inner`` before reading.
        if weight is not None:
            _sync_rust_edge_attrs(G, edge_only=True)
        native_result = _native_adjacency_arrays(
            G, nodelist, weight if weight is not None else None, 1.0
        )
        if native_result is not None:
            rows, cols, data = native_result
            if rows:
                rows_arr = np.asarray(rows)
                cols_arr = np.asarray(cols)
                data_arr = np.asarray(data, dtype=matrix.dtype)
                matrix[rows_arr, cols_arr] = data_arr
            return matrix

    index = {node: i for i, node in enumerate(nodelist)}
    if G.is_multigraph():
        edge_values = {}
        for u, v, _, edge_attrs in G.edges(keys=True, data=True):
            if u not in index or v not in index:
                continue
            edge_value = 1 if weight is None else edge_attrs.get(weight, 1)
            edge_values.setdefault((u, v), []).append(edge_value)
            if not G.is_directed() and u != v:
                edge_values.setdefault((v, u), []).append(edge_value)
        for (u, v), values in edge_values.items():
            matrix[index[u], index[v]] = multigraph_weight(values)
        return matrix

    # br-r37-c1-tnaperf: G.edges(data=True) materialises ``(u, v, attrs)``
    # tuples one-at-a-time through PyO3 (~3.5ms for 1000 edges).
    # G._adj.items() iterates the adjacency map directly and yields
    # ``(u, dict_of_v_to_attrs)`` — ~25% faster on a 100-node digraph.
    # For undirected graphs, every edge appears twice in _adj (from
    # both endpoints), so we let the natural visit-from-each-side
    # populate matrix[u, v] and matrix[v, u] without the explicit
    # symmetric write (an overwrite of the same value is harmless,
    # but doubles work on a write-heavy path).
    is_directed = G.is_directed()
    weight_is_none = weight is None
    for u, nbrs in G._adj.items():
        ui = index.get(u)
        if ui is None:
            continue
        for v, edge_attrs in nbrs.items():
            vi = index.get(v)
            if vi is None:
                continue
            edge_value = 1 if weight_is_none else edge_attrs.get(weight, 1)
            matrix[ui, vi] = edge_value
    return matrix


def from_numpy_array(
    A,
    parallel_edges=False,
    create_using=None,
    edge_attr="weight",
    *,
    nodelist=None,
):
    """Return a graph from a 2-D NumPy adjacency matrix.

    Parameters
    ----------
    A : numpy.ndarray
        A 2-D NumPy array interpreted as an adjacency matrix.
    parallel_edges : bool, optional
        If ``True`` and ``create_using`` is a multigraph, integer array
        entries create that many parallel edges.
    create_using : Graph constructor, optional
        Graph type to create. Default ``Graph()``.

    Returns
    -------
    G : Graph or DiGraph
        The constructed graph.
    """
    kind_to_python_type = {
        "f": float,
        "i": int,
        "u": int,
        "b": bool,
        "c": complex,
        "S": str,
        "U": str,
        "V": "void",
    }
    graph = _empty_graph_from_create_using(create_using)
    if A.ndim != 2:
        raise NetworkXError(f"Input array must be 2D, not {A.ndim}")
    n, m = A.shape
    if n != m:
        raise NetworkXError(f"Adjacency matrix not square: nx,ny={A.shape}")
    dtype = A.dtype
    try:
        python_type = kind_to_python_type[dtype.kind]
    except Exception as err:
        raise TypeError(f"Unknown numpy data type: {dtype}") from err

    default_nodes = nodelist is None
    if default_nodes:
        nodelist = range(n)
    else:
        if len(nodelist) != n:
            raise ValueError("nodelist must have the same length as A.shape[0]")

    graph.add_nodes_from(nodelist)
    edges = ((int(u), int(v)) for u, v in zip(*A.nonzero()))
    if python_type == "void":
        fields = sorted((offset, field_dtype, name) for name, (field_dtype, offset) in dtype.fields.items())
        triples = (
            (
                u,
                v,
                {}
                if edge_attr in [False, None]
                else {
                    name: kind_to_python_type[field_dtype.kind](value)
                    for (_, field_dtype, name), value in zip(fields, A[u, v])
                },
            )
            for u, v in edges
        )
    elif python_type is int and graph.is_multigraph() and parallel_edges:
        chain = _itertools.chain.from_iterable
        if edge_attr in [False, None]:
            triples = chain(((u, v, {}) for _ in range(A[u, v])) for (u, v) in edges)
        else:
            triples = chain(
                ((u, v, {edge_attr: 1}) for _ in range(A[u, v])) for (u, v) in edges
            )
    else:
        if edge_attr in [False, None]:
            triples = ((u, v, {}) for u, v in edges)
        else:
            triples = ((u, v, {edge_attr: python_type(A[u, v])}) for u, v in edges)

    if graph.is_multigraph() and not graph.is_directed():
        triples = ((u, v, attrs) for u, v, attrs in triples if u <= v)
    if not default_nodes:
        idx_to_node = dict(enumerate(nodelist))
        triples = ((idx_to_node[u], idx_to_node[v], attrs) for u, v, attrs in triples)

    graph.add_edges_from(triples)
    return graph


def to_scipy_sparse_array(G, nodelist=None, dtype=None, weight="weight", format="csr"):
    """Return the adjacency matrix of G as a SciPy sparse array.

    Parameters
    ----------
    G : Graph or DiGraph
        The input graph.
    nodelist : list, optional
        Rows and columns are ordered according to *nodelist*.
        If ``None``, the ordering is produced by ``G.nodes()``.
    dtype : NumPy dtype, optional
        Data type of the matrix entries. Default ``numpy.float64``.
    weight : str or None, optional
        Edge attribute key used as weight. ``None`` means weight 1.
        Default ``'weight'``.
    format : {'csr', 'csc', 'coo', 'lil', 'dok', 'bsr'}, optional
        Sparse matrix format. Default ``'csr'``.

    Returns
    -------
    A : scipy.sparse array
        Adjacency matrix in the requested sparse format.
    """
    import scipy.sparse

    # br-r37-c1-tssa-empty: nx.to_scipy_sparse_array raises NetworkXError
    # on len(G)==0 BEFORE consulting nodelist. Previously fnx returned
    # an empty 0×0 sparse array, which then cascaded into adjacency_matrix,
    # laplacian_matrix, normalized_laplacian_matrix, and the three
    # *_spectrum wrappers all silently returning [] on empty graphs
    # (nx raises on every one of those entry points).
    if len(G) == 0:
        raise NetworkXError("Graph has no nodes or edges")

    default_nodelist = nodelist is None
    if default_nodelist:
        nodelist = list(G)
    else:
        nodelist = list(nodelist)
        # br-r37-c1-tssa-nlist0: empty user-supplied nodelist on a
        # non-empty graph silently returned a 0×0 sparse matrix;
        # nx raises NetworkXError("nodelist has no nodes"). Order
        # the check BEFORE the duplicate / missing checks so the
        # message matches nx exactly when nlen == 0.
        if len(nodelist) == 0:
            raise NetworkXError("nodelist has no nodes")
        if len(set(nodelist)) != len(nodelist):
            raise NetworkXError("nodelist contains duplicates.")
        missing = set(nodelist) - set(G)
        if missing:
            raise NetworkXError(f"Nodes {missing} in nodelist is not in G")

    is_directed = G.is_directed()
    weight_is_none = weight is None
    # br-r37-c1-lqlx2: native Rust COO builder for non-multigraph.
    # Iterates the IndexMap directly (~0.1ms for 1000 edges) instead
    # of Python's G._adj.items() loop (~3ms).  Returns None for
    # multigraph; we keep the dedup-by-sum Python path for those.
    # Requires sync because mutations via G[u][v][k]=v live in the
    # Python attrs view until pushed back to Rust storage.  Skip the
    # native path when caller passes an explicit ``dtype`` we'd have
    # to coerce in Python anyway (the dtype arg is preserved by the
    # scipy COO constructor when given to ``coo_array(..., dtype=)``).
    # br-r37-c1-wqtfe: also take the native COO builder for a string weight
    # key when the caller pins ``dtype`` (hits, kemeny, laplacian/spectral all
    # pass ``dtype=float``). The native helper reads the Rust ``inner`` AttrMap,
    # which can be stale after ``G[u][v][k]=v`` mutations, so sync first. We
    # only enable this when ``dtype`` is given because for ``dtype=None`` nx
    # infers int-vs-float from the original Python value types, which the
    # f64-returning native helper cannot reproduce; a pinned dtype removes that
    # ambiguity. The matrix is byte-identical to the Python path (COO -> CSR
    # canonicalises duplicate/ordering, and the (row, col, data) set matches).
    _use_native_weighted = isinstance(weight, str) and dtype is not None
    _probe_native_missing_default_weight = (
        isinstance(weight, str)
        and dtype is None
        and _native_adjacency_index_arrays is not None
        and not G.is_multigraph()
        and isinstance(G, (Graph, DiGraph))
    )
    if (
        _native_adjacency_arrays is not None
        and not G.is_multigraph()
        and isinstance(G, (Graph, DiGraph))
        and (weight is None or _use_native_weighted or _probe_native_missing_default_weight)
    ):
        # br-r37-c1-hits-bipartite-svds-degenerate-xjar9: weighted
        # matrix exports must read Python-visible attr dicts because
        # direct adjacency mutations can be stale in Rust storage —
        # push them into ``inner`` before the native read.
        if _use_native_weighted:
            _sync_rust_edge_attrs(G, edge_only=True)
        native_weight = weight if _use_native_weighted else None
        native_index_result = None
        if native_weight is None and _native_adjacency_index_arrays is not None:
            absent_weight_attr = weight if _probe_native_missing_default_weight else None
            if (
                default_nodelist
                and format == "csr"
                and type(G) is Graph
                and _native_adjacency_default_order_index_arrays is not None
            ):
                native_index_result = _native_adjacency_default_order_index_arrays(
                    G, absent_weight_attr
                )
            else:
                native_index_result = _native_adjacency_index_arrays(
                    G, nodelist, absent_weight_attr
                )
            if native_index_result is not None:
                rows, cols = native_index_result
                import numpy as _np
                unit_dtype = _np.int64 if dtype is None else dtype
                data = _np.ones(len(rows), dtype=unit_dtype)
                matrix = scipy.sparse.coo_array(
                    (data, (rows, cols)),
                    shape=(len(nodelist), len(nodelist)),
                    dtype=dtype,
                )
                return matrix.asformat(format)
            if _probe_native_missing_default_weight:
                native_weight = None
            else:
                native_weight = weight if _use_native_weighted else None
        if (
            _probe_native_missing_default_weight
            and native_index_result is None
            and default_nodelist
            and format == "csr"
            and type(G) is Graph
            and _native_adjacency_default_order_typed_arrays is not None
        ):
            # br-r37-c1-04z53.20: dtype=None with present string weights used
            # to fall back to Python edge iteration solely to preserve nx dtype
            # inference. The typed native helper returns conservative dtype
            # metadata; unsupported value kinds still return None and use the
            # exact Python fallback below.
            _sync_rust_edge_attrs(G, edge_only=True)
            typed_native_result = _native_adjacency_default_order_typed_arrays(
                G, weight, 1.0
            )
            if typed_native_result is not None:
                rows, cols, data, needs_float_dtype = typed_native_result
                import numpy as _np
                data_dtype = _np.float64 if needs_float_dtype else _np.int64
                matrix = scipy.sparse.coo_array(
                    (
                        _np.asarray(data, dtype=data_dtype),
                        (
                            _np.asarray(rows, dtype=_np.intp),
                            _np.asarray(cols, dtype=_np.intp),
                        ),
                    ),
                    shape=(len(nodelist), len(nodelist)),
                )
                return matrix.asformat(format)

        if _probe_native_missing_default_weight and native_index_result is None:
            native_result = None
        elif (
            _use_native_weighted
            and default_nodelist
            and format == "csr"
            and type(G) is Graph
            and _native_adjacency_default_order_arrays is not None
        ):
            native_result = _native_adjacency_default_order_arrays(
                G, native_weight, 1.0
            )
        else:
            native_result = _native_adjacency_arrays(G, nodelist, native_weight, 1.0)
        if native_result is not None:
            rows, cols, data = native_result
            # br-r37-c1-tssadtype: nx preserves int dtype when every
            # edge weight is an integer (literal int 1 for weight=None;
            # or integer-valued ``weight=`` attrs).  Native helper
            # returns Vec<f64> uniformly; vectorize the integer-check
            # via numpy (~5× faster than the Python ``all()`` loop on
            # a 50k-edge graph).  Float values get a short-circuit
            # early-exit when ``all()`` discovers the first non-int.
            import numpy as _np
            if dtype is None and data:
                data_arr = _np.asarray(data)
                if _np.array_equal(data_arr, data_arr.astype(_np.int64)):
                    matrix = scipy.sparse.coo_array(
                        (data_arr.astype(_np.int64), (rows, cols)),
                        shape=(len(nodelist), len(nodelist)),
                    )
                else:
                    matrix = scipy.sparse.coo_array(
                        (data_arr, (rows, cols)),
                        shape=(len(nodelist), len(nodelist)),
                    )
            else:
                if _use_native_weighted:
                    rows = _np.asarray(rows, dtype=_np.intp)
                    cols = _np.asarray(cols, dtype=_np.intp)
                    data = _np.asarray(data, dtype=dtype)
                matrix = scipy.sparse.coo_array(
                    (data, (rows, cols)),
                    shape=(len(nodelist), len(nodelist)),
                    dtype=dtype,
                )
            return matrix.asformat(format)

    # br-r37-c1-tssaperf: Python fallback path — multigraph (which
    # needs parallel-edge sum dedup), non-string weight key, or
    # non-fnx graph input (subclass).  Iterate G._adj.items()
    # directly instead of G.edges(data=True) — yields (u, {v: attrs})
    # without per-edge tuple alloc across PyO3.
    index = {node: i for i, node in enumerate(nodelist)}
    rows = []
    cols = []
    data = []
    if G.is_multigraph():
        accum = {}
        for u, v, _, edge_attrs in G.edges(keys=True, data=True):
            ui = index.get(u)
            vi = index.get(v)
            if ui is None or vi is None:
                continue
            edge_value = 1 if weight_is_none else edge_attrs.get(weight, 1)
            accum[(ui, vi)] = accum.get((ui, vi), 0) + edge_value
            if not is_directed and u != v:
                accum[(vi, ui)] = accum.get((vi, ui), 0) + edge_value
        for (ui, vi), val in accum.items():
            rows.append(ui)
            cols.append(vi)
            data.append(val)
    else:
        # For undirected graphs, every edge appears twice in _adj
        # (once from each endpoint), so the natural iteration already
        # emits both (u, v) and (v, u) without an explicit symmetric
        # write.  Just emit one entry per visit.
        for u, nbrs in G._adj.items():
            ui = index.get(u)
            if ui is None:
                continue
            for v, edge_attrs in nbrs.items():
                vi = index.get(v)
                if vi is None:
                    continue
                edge_value = 1 if weight_is_none else edge_attrs.get(weight, 1)
                rows.append(ui)
                cols.append(vi)
                data.append(edge_value)

    matrix = scipy.sparse.coo_array(
        (data, (rows, cols)),
        shape=(len(nodelist), len(nodelist)),
        dtype=dtype,
    )
    return matrix.asformat(format)


def from_scipy_sparse_array(
    A, parallel_edges=False, create_using=None, edge_attribute="weight"
):
    """Return a graph from a SciPy sparse array.

    Parameters
    ----------
    A : scipy.sparse array or matrix
        An adjacency matrix representation of a graph.
    parallel_edges : bool, optional
        If ``True`` and ``create_using`` is a multigraph, integer sparse
        entries create that many parallel edges.
    create_using : Graph constructor, optional
        Graph type to create. Default ``Graph()``.
    edge_attribute : str, optional
        Name of the edge attribute to set from matrix values.
        Default ``'weight'``.

    Returns
    -------
    G : Graph or DiGraph
        The constructed graph.
    """
    kind_to_python_type = {
        "f": float,
        "i": int,
        "u": int,
        "b": bool,
        "c": complex,
    }
    graph = _empty_graph_from_create_using(create_using)
    n, m = A.shape
    if n != m:
        raise NetworkXError(f"Adjacency matrix not square: nx,ny={A.shape}")

    graph.add_nodes_from(range(n))
    coo = A.tocoo()
    python_type = kind_to_python_type.get(A.dtype.kind)
    triples = (
        (
            int(u),
            int(v),
            python_type(weight) if python_type is not None else weight,
        )
        for u, v, weight in zip(coo.row, coo.col, coo.data)
    )
    if A.dtype.kind in ("i", "u") and graph.is_multigraph() and parallel_edges:
        chain = _itertools.chain.from_iterable
        triples = chain(((u, v, 1) for _ in range(int(weight))) for (u, v, weight) in triples)
    if graph.is_multigraph() and not graph.is_directed():
        triples = ((u, v, weight) for u, v, weight in triples if u <= v)

    if edge_attribute is None:
        # br-r37-c1-oa0fs: nx accepts ``edge_attribute=None`` and uses
        # the literal ``None`` as the edge-attribute dict key. fnx's
        # ``add_weighted_edges_from`` *and* ``add_edges_from`` both
        # validate attr keys against ``str``, rejecting ``None``. Add
        # each edge first (no attrs), then set ``G[u][v][None] = w``
        # directly — the per-edge dict accepts arbitrary hashable keys.
        if graph.is_multigraph():
            for u, v, w in triples:
                key = graph.add_edge(u, v)
                graph[u][v][key][None] = w
        else:
            for u, v, w in triples:
                graph.add_edge(u, v)
                graph[u][v][None] = w
    else:
        graph.add_weighted_edges_from(triples, weight=edge_attribute)
    return graph


def from_dict_of_dicts(d, create_using=None, multigraph_input=False):
    """Return a graph from a dictionary of dictionaries."""
    graph = _empty_graph_from_create_using(create_using)
    graph.add_nodes_from(d)

    if multigraph_input:
        if graph.is_directed():
            if graph.is_multigraph():
                for u, nbrs in d.items():
                    for v, edge_map in nbrs.items():
                        for edge_key, edge_attrs in edge_map.items():
                            _add_json_multiedge(graph, u, v, edge_key, dict(edge_attrs))
            else:
                for u, nbrs in d.items():
                    for v, edge_map in nbrs.items():
                        for _, edge_attrs in edge_map.items():
                            graph.add_edge(u, v)
                            graph[u][v].update(edge_attrs)
        else:
            seen = set()
            if graph.is_multigraph():
                for u, nbrs in d.items():
                    for v, edge_map in nbrs.items():
                        if (u, v) in seen:
                            continue
                        for edge_key, edge_attrs in edge_map.items():
                            _add_json_multiedge(graph, u, v, edge_key, dict(edge_attrs))
                        seen.add((v, u))
            else:
                for u, nbrs in d.items():
                    for v, edge_map in nbrs.items():
                        if (u, v) in seen:
                            continue
                        for _, edge_attrs in edge_map.items():
                            graph.add_edge(u, v)
                            graph[u][v].update(edge_attrs)
                        seen.add((v, u))
        return graph

    if graph.is_multigraph():
        if graph.is_directed():
            for u, nbrs in d.items():
                for v, edge_attrs in nbrs.items():
                    _add_json_multiedge(graph, u, v, 0, dict(edge_attrs))
        else:
            seen = set()
            for u, nbrs in d.items():
                for v, edge_attrs in nbrs.items():
                    if (u, v) in seen:
                        continue
                    _add_json_multiedge(graph, u, v, 0, dict(edge_attrs))
                    seen.add((v, u))
    elif type(graph) is Graph:
        # br-r37-c1-nlanb: batch the whole edge set through add_edges_from
        # (nx does exactly this with a generator of (u, v, data) triples) so
        # the attributed batch path (br-r37-c1-pr8q6) commits it in one bulk
        # insertion instead of per-edge Python add_edge + two adjacency-view
        # __getitem__ + dict.update (~7.8x nx). Semantics are identical for
        # well-formed input; for a NON-dict attrs value this also corrects a
        # divergence: the old loop added the edge BEFORE update() raised,
        # while nx's add_edges_from leaves nodes-but-no-edge (datadict is
        # only linked into _adj after a successful update).
        graph.add_edges_from(
            [(u, v, edge_attrs) for u, nbrs in d.items() for v, edge_attrs in nbrs.items()]
        )
    else:
        # Subclasses / DiGraph keep the inline loop: their add_edges_from
        # raw paths have different malformed-input contracts.
        for u, nbrs in d.items():
            for v, edge_attrs in nbrs.items():
                graph.add_edge(u, v)
                graph[u][v].update(edge_attrs)

    return graph


def from_edgelist(edgelist, create_using=None):
    """Return a graph from a list of edges.

    Parameters
    ----------
    edgelist : iterable
        Each element is a tuple (u, v) or (u, v, d) where d is a dict of
        edge attributes.
    create_using : Graph constructor, optional
        Graph type to create. Default ``Graph()``.

    Returns
    -------
    G : Graph or DiGraph
    """
    G = _empty_graph_from_create_using(create_using)

    G.add_edges_from(edgelist)
    return G


def to_dict_of_dicts(G, nodelist=None, edge_data=None):
    """Return adjacency representation as a dictionary of dictionaries.

    Parameters
    ----------
    G : Graph or DiGraph
        The input graph.
    nodelist : list, optional
        Use only nodes in *nodelist*. Default: all nodes.
    edge_data : object, optional
        If provided, use this as the edge data instead of the edge
        attribute dict.

    Returns
    -------
    d : dict
        ``d[u][v]`` is the edge data for (u, v).
    """
    # br-r37-c1-yl59j/br-r37-c1-nocb2: native fast path for exact simple
    # Graph/DiGraph with no nodelist/edge_data override. Builds the nested dict
    # in Rust reusing live edge-attr dict objects (same refs as G[u][v]) in
    # adjacency/successor order.
    if nodelist is None and edge_data is None and (type(G) is Graph or type(G) is DiGraph):
        _fast = _fnx.to_dict_of_dicts_undirected(G)
        if _fast is not None:
            return _fast
    if nodelist is None:
        nodelist = list(G.nodes())
    nodeset = set(nodelist)

    d = {}
    is_multigraph = G.is_multigraph()
    for u in nodelist:
        d[u] = {}
        for v, data in G[u].items():
            if v in nodeset:
                if edge_data is not None:
                    d[u][v] = edge_data
                elif is_multigraph:
                    d[u][v] = _LiveMultiEdgeDataView(G, u, v)
                else:
                    d[u][v] = data
    return d


def cytoscape_data(G, name="name", ident="id"):
    """Export graph to Cytoscape.js JSON format."""
    if name == ident:
        raise NetworkXError("name and ident must be different.")

    payload = {
        "data": list(G.graph.items()),
        "directed": G.is_directed(),
        "multigraph": G.is_multigraph(),
        "elements": {"nodes": [], "edges": []},
    }
    for node, node_attrs in G.nodes(data=True):
        node_payload = {"data": dict(node_attrs)}
        node_payload["data"]["id"] = node_attrs.get(ident) or str(node)
        node_payload["data"]["value"] = node
        node_payload["data"]["name"] = node_attrs.get(name) or str(node)
        payload["elements"]["nodes"].append(node_payload)

    if G.is_multigraph():
        for u, v, edge_key, edge_attrs in G.edges(keys=True, data=True):
            edge_payload = {"data": dict(edge_attrs)}
            edge_payload["data"]["source"] = u
            edge_payload["data"]["target"] = v
            edge_payload["data"]["key"] = edge_key
            payload["elements"]["edges"].append(edge_payload)
    else:
        for u, v, edge_attrs in G.edges(data=True):
            edge_payload = {"data": dict(edge_attrs)}
            edge_payload["data"]["source"] = u
            edge_payload["data"]["target"] = v
            payload["elements"]["edges"].append(edge_payload)
    return payload


def cytoscape_graph(data, name="name", ident="id"):
    """Build graph from Cytoscape.js JSON format."""
    if name == ident:
        raise NetworkXError("name and ident must be different.")

    multigraph = data.get("multigraph")
    directed = data.get("directed")
    graph = _json_graph_from_flags(
        directed=bool(directed),
        multigraph=bool(multigraph),
    )
    graph.graph.update(dict(data.get("data")))

    for node_entry in data["elements"]["nodes"]:
        node_data = node_entry["data"].copy()
        node = node_entry["data"]["value"]

        if node_entry["data"].get(name):
            node_data[name] = node_entry["data"].get(name)
        if node_entry["data"].get(ident):
            node_data[ident] = node_entry["data"].get(ident)

        graph.add_node(node)
        graph.nodes[node].update(node_data)

    for edge_entry in data["elements"]["edges"]:
        edge_data = edge_entry["data"].copy()
        source = edge_entry["data"]["source"]
        target = edge_entry["data"]["target"]
        if multigraph:
            edge_key = edge_entry["data"].get("key", 0)
            _add_json_multiedge(graph, source, target, edge_key, edge_data)
        else:
            graph.add_edge(source, target)
            graph.edges[source, target].update(edge_data)
    return graph


def to_networkx_graph(data, create_using=None, multigraph_input=False):
    """Convert supported input data to a graph."""
    if hasattr(data, "adj"):
        try:
            result = from_dict_of_dicts(
                data.adj,
                create_using=create_using,
                multigraph_input=data.is_multigraph(),
            )
            result.graph.update(data.graph)
            for node, attrs in data.nodes(data=True):
                result.nodes[node].update(attrs)
            return result
        except Exception as err:
            raise NetworkXError("Input is not a correct NetworkX graph.") from err

    if isinstance(data, dict):
        try:
            return from_dict_of_dicts(
                data,
                create_using=create_using,
                multigraph_input=multigraph_input,
            )
        except Exception as err1:
            if isinstance(multigraph_input, bool) and multigraph_input:
                raise NetworkXError(
                    f"converting multigraph_input raised:\n{type(err1)}: {err1}"
                )
            try:
                return from_dict_of_lists(data, create_using=create_using)
            except Exception as err2:
                raise TypeError("Input is not known type.") from err2

    if isinstance(data, (list, tuple, _Iterator)):
        try:
            return from_edgelist(data, create_using=create_using)
        except Exception:
            pass

    try:
        import pandas as pd

        if isinstance(data, pd.DataFrame):
            if data.shape[0] == data.shape[1]:
                try:
                    return from_pandas_adjacency(data, create_using=create_using)
                except Exception as err:
                    msg = "Input is not a correct Pandas DataFrame adjacency matrix."
                    raise NetworkXError(msg) from err
            else:
                try:
                    return from_pandas_edgelist(
                        data,
                        edge_attr=True,
                        create_using=create_using,
                    )
                except Exception as err:
                    msg = "Input is not a correct Pandas DataFrame edge-list."
                    raise NetworkXError(msg) from err
    except ImportError:
        pass

    try:
        import numpy as np

        if isinstance(data, np.ndarray):
            try:
                return from_numpy_array(data, create_using=create_using)
            except Exception as err:
                raise NetworkXError("Failed to interpret array as an adjacency matrix.") from err
    except ImportError:
        pass

    try:
        if hasattr(data, "format"):
            return from_scipy_sparse_array(data, create_using=create_using)
    except Exception as err:
        raise NetworkXError("Input is not a correct scipy sparse array type.") from err

    if isinstance(data, (_Collection, _Generator, _Iterator)):
        try:
            return from_edgelist(data, create_using=create_using)
        except Exception as err:
            raise NetworkXError("Input is not a valid edge list") from err

    raise NetworkXError("Input is not a known data type for conversion.")


def prominent_group(
    G,
    k,
    weight=None,
    C=None,
    endpoints=False,
    normalized=True,
    greedy=False,
):
    """Return a prominent group of k nodes maximizing group betweenness.

    Uses a greedy approach: iteratively add the node that most increases
    the group betweenness centrality.
    """
    from itertools import combinations as _combinations

    nodes = list(G.nodes())
    n = len(nodes)

    if C is not None:
        candidates = list(C)
    else:
        candidates = nodes

    if k > len(candidates):
        raise NetworkXError(f"k={k} exceeds number of candidate nodes")

    if greedy or k > 5:
        # Greedy: start empty, add node that maximizes group betweenness.
        group = set()
        remaining = set(candidates)
        for _ in range(k):
            best_node = None
            best_score = -1
            for node in remaining:
                trial = group | {node}
                score = group_betweenness_centrality(
                    G, trial, normalized=normalized, weight=weight, endpoints=endpoints
                )
                if score > best_score:
                    best_score = score
                    best_node = node
            group.add(best_node)
            remaining.discard(best_node)
        score = group_betweenness_centrality(
            G, group, normalized=normalized, weight=weight, endpoints=endpoints
        )
        return float(f"{score:.2f}"), list(group)

    # Exact: enumerate all k-subsets (only practical for small k and n).
    best_group = None
    best_score = -1
    for combo in _combinations(candidates, k):
        score = group_betweenness_centrality(
            G, set(combo), normalized=normalized, weight=weight, endpoints=endpoints
        )
        if score > best_score:
            best_score = score
            best_group = set(combo)
    return float(f"{best_score:.2f}"), list(best_group) if best_group is not None else []


def within_inter_cluster(G, ebunch=None, delta=0.001, community="community"):
    """Compute within/inter-cluster common neighbor ratio (WIC measure).

    If u and v are in different communities, score is 0.
    Otherwise, score = |within| / (|inter| + delta) where within are common
    neighbors in the same community as u/v, and inter are those in different.

    br-r37-c1-fa5tf: nx is @not_implemented_for('directed',
    'multigraph'). Type guard fires eagerly (on call) so iteration
    never reaches the per-node community-attr check on multi/
    directed inputs.
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if delta <= 0:
        # br-r37-c1-fa5tf: nx raises NetworkXAlgorithmError (not
        # NetworkXError) for this precondition; match exactly.
        raise NetworkXAlgorithmError("Delta must be greater than zero")

    if ebunch is None:
        # Default: all non-existing edges.
        ebunch_iter = non_edges(G)
    else:
        ebunch_iter = ebunch

    def _community_of(node):
        # br-shcomm: nx raises NetworkXAlgorithmError, not NetworkXError,
        # with a specific message. Match the contract so callers catching
        # the algorithm-error base class don't diverge.
        attrs = G.nodes[node]
        try:
            return attrs[community]
        except (KeyError, TypeError) as err:
            raise NetworkXAlgorithmError(
                f"No community information available for Node {node}"
            ) from err

    def _generate():
        for u, v in ebunch_iter:
            cu = _community_of(u)
            cv = _community_of(v)
            if cu != cv:
                yield (u, v, 0)
                continue
            cnbors = set(common_neighbors(G, u, v))
            within = {w for w in cnbors if _community_of(w) == cu}
            inter = cnbors - within
            yield (u, v, len(within) / (len(inter) + delta))

    return _generate()


def gnc_graph(n, create_using=None, seed=None):
    """Return a growing network with copying (GNC) digraph."""
    from franken_networkx import _fnx

    # br-gnrempty: nx.gnc_graph(0) returns a 1-node DiGraph {0} (the seed
    # node before the growth loop); fnx's Rust-native path returned the
    # empty graph for n=0. The create_using branch already handled this,
    # but the default (fast-path) branch bypassed it.
    if n == 0:
        if create_using is None:
            return empty_graph(1, create_using=DiGraph(), default=DiGraph)
        graph = _checked_directed_create_using(create_using, default=DiGraph)
        return empty_graph(1, create_using=graph, default=DiGraph)

    if create_using is None:
        return _fnx.gnc_graph(n, seed=seed, create_using=None)

    graph = _checked_directed_create_using(create_using, default=DiGraph)
    return _copy_graph_into(_fnx.gnc_graph(n, seed=seed, create_using=None), graph)


def gnr_graph(n, p, create_using=None, seed=None):
    """Return a growing network with redirection (GNR) digraph."""
    from franken_networkx import _fnx

    # br-gnrempty: see gnc_graph above.
    if n == 0:
        if create_using is None:
            return empty_graph(1, create_using=DiGraph(), default=DiGraph)
        graph = _checked_directed_create_using(create_using, default=DiGraph)
        return empty_graph(1, create_using=graph, default=DiGraph)

    if create_using is None:
        return _fnx.gnr_graph(n, p, seed=seed, create_using=None)

    graph = _checked_directed_create_using(create_using, default=DiGraph)
    return _copy_graph_into(_fnx.gnr_graph(n, p, seed=seed, create_using=None), graph)


def dual_barabasi_albert_graph(
    n,
    m1,
    m2,
    p,
    seed=None,
    initial_graph=None,
    *,
    create_using=None,
    backend=None,
    **backend_kwargs,
):
    """Return a dual Barabasi-Albert preferential attachment graph."""
    _validate_backend_dispatch_keywords(
        "dual_barabasi_albert_graph", backend, backend_kwargs
    )
    import random as _random

    target = _empty_graph_from_create_using(create_using, default=Graph)
    if target.is_directed():
        raise NetworkXError("create_using must not be directed")
    if target.is_multigraph():
        raise NetworkXError("create_using must not be a multi-graph")

    if m1 < 1 or m1 >= n:
        raise NetworkXError(
            f"Dual Barabási–Albert must have m1 >= 1 and m1 < n, m1 = {m1}, n = {n}"
        )
    if m2 < 1 or m2 >= n:
        raise NetworkXError(
            f"Dual Barabási–Albert must have m2 >= 1 and m2 < n, m2 = {m2}, n = {n}"
        )
    if p < 0 or p > 1:
        raise NetworkXError(
            f"Dual Barabási–Albert network must have 0 <= p <= 1, p = {p}"
        )

    # br-r37-c1-rustseed (sister): NaN seed must surface nx's
    # ``ValueError("nan cannot be used to generate a random.Random
    # instance")`` rather than silently fall through ``random.Random(NaN)``.
    if isinstance(seed, float) and _math.isnan(seed):
        raise ValueError(
            "nan cannot be used to generate a random.Random instance"
        )

    if p == 1:
        return barabasi_albert_graph(
            n,
            m1,
            seed=seed,
            initial_graph=initial_graph,
            create_using=create_using,
        )
    if p == 0:
        return barabasi_albert_graph(
            n,
            m2,
            seed=seed,
            initial_graph=initial_graph,
            create_using=create_using,
        )

    if initial_graph is None:
        graph = star_graph(max(m1, m2))
    else:
        if len(initial_graph) < max(m1, m2) or len(initial_graph) > n:
            raise NetworkXError(
                f"Barabási–Albert initial graph must have between "
                f"max(m1, m2) = {max(m1, m2)} and n = {n} nodes"
            )
        graph = Graph()
        graph.graph.update(dict(initial_graph.graph))
        for node, attrs in initial_graph.nodes(data=True):
            graph.add_node(node, **dict(attrs))
        for u, v, attrs in initial_graph.edges(data=True):
            graph.add_edge(u, v, **dict(attrs))

    rng = _random.Random(seed)
    repeated_nodes = [
        node for node, degree_value in graph.degree for _ in range(degree_value)
    ]
    source = len(graph)
    while source < n:
        m = m1 if rng.random() < p else m2
        targets = set()
        while len(targets) < m:
            targets.add(rng.choice(repeated_nodes))
        graph.add_edges_from((source, target) for target in targets)
        repeated_nodes.extend(targets)
        repeated_nodes.extend([source] * m)
        source += 1

    if create_using is None:
        return graph

    target.graph.update(dict(graph.graph))
    for node, attrs in graph.nodes(data=True):
        target.add_node(node, **dict(attrs))
    for u, v, attrs in graph.edges(data=True):
        target.add_edge(u, v, **dict(attrs))
    return target


def extended_barabasi_albert_graph(
    n, m, p, q, seed=None, *, create_using=None, backend=None, **backend_kwargs
):
    """Return an extended Barabasi-Albert graph."""
    _validate_backend_dispatch_keywords(
        "extended_barabasi_albert_graph", backend, backend_kwargs
    )
    graph = _checked_create_using(create_using, directed=False, multigraph=False, default=Graph)
    if m < 1 or m >= n:
        raise NetworkXError(
            f"Extended Barabasi-Albert network needs m>=1 and m<n, m={m}, n={n}"
        )
    if p + q >= 1:
        raise NetworkXError(
            f"Extended Barabasi-Albert network needs p + q <= 1, p={p}, q={q}"
        )

    rng = _generator_random_state(seed)
    graph.add_nodes_from(range(m))
    attachment_preference = list(range(m))
    new_node = m

    def random_subset(population, _count):
        targets = set()
        while len(targets) < _count:
            targets.add(rng.choice(population))
        return targets

    while new_node < n:
        a_probability = rng.random()
        clique_degree = len(graph) - 1
        clique_size = (len(graph) * clique_degree) / 2

        if a_probability < p and graph.size() <= clique_size - m:
            eligible_nodes = [
                node for node, degree_value in graph.degree if degree_value < clique_degree
            ]
            for _ in range(m):
                src_node = rng.choice(eligible_nodes)
                prohibited_nodes = list(graph[src_node])
                prohibited_nodes.append(src_node)
                dest_node = rng.choice(
                    [node for node in attachment_preference if node not in prohibited_nodes]
                )
                graph.add_edge(src_node, dest_node)
                attachment_preference.append(src_node)
                attachment_preference.append(dest_node)

                if graph.degree[src_node] == clique_degree:
                    eligible_nodes.remove(src_node)
                if graph.degree[dest_node] == clique_degree and dest_node in eligible_nodes:
                    eligible_nodes.remove(dest_node)

        elif p <= a_probability < (p + q) and m <= graph.size() < clique_size:
            eligible_nodes = [
                node
                for node, degree_value in graph.degree
                if 0 < degree_value < clique_degree
            ]
            for _ in range(m):
                node = rng.choice(eligible_nodes)
                nbr_nodes = list(graph[node])
                src_node = rng.choice(nbr_nodes)
                nbr_nodes.append(node)
                dest_node = rng.choice(
                    [
                        candidate
                        for candidate in attachment_preference
                        if candidate not in nbr_nodes
                    ]
                )
                graph.remove_edge(node, src_node)
                graph.add_edge(node, dest_node)
                attachment_preference.remove(src_node)
                attachment_preference.append(dest_node)

                if graph.degree[src_node] == 0 and src_node in eligible_nodes:
                    eligible_nodes.remove(src_node)
                if dest_node in eligible_nodes:
                    if graph.degree[dest_node] == clique_degree:
                        eligible_nodes.remove(dest_node)
                elif graph.degree[dest_node] == 1:
                    eligible_nodes.append(dest_node)

        else:
            targets = random_subset(attachment_preference, m)
            graph.add_edges_from(zip([new_node] * m, targets))
            attachment_preference.extend(targets)
            attachment_preference.extend([new_node] * (m + 1))
            new_node += 1

    return graph


def scale_free_graph(
    n,
    alpha=0.41,
    beta=0.54,
    gamma=0.05,
    delta_in=0.2,
    delta_out=0,
    seed=None,
    initial_graph=None,
):
    """Return a directed scale-free MultiDiGraph."""
    # br-sfgval: validate with nx-shaped ValueError messages before the Rust
    # branch; without this, invalid params leak the Rust
    # `ValueError("FailClosed { ... }")` text instead of nx's terse wording.
    # Validation order and wording match networkx exactly so regex-matched
    # tests on the drop-in surface keep working.
    if alpha <= 0:
        raise ValueError("alpha must be > 0.")
    if beta <= 0:
        raise ValueError("beta must be > 0.")
    if gamma <= 0:
        raise ValueError("gamma must be > 0.")
    if abs(alpha + beta + gamma - 1.0) >= 1e-9:
        raise ValueError("alpha+beta+gamma must equal 1.")
    if delta_in < 0:
        raise ValueError("delta_in must be >= 0.")
    if delta_out < 0:
        raise ValueError("delta_out must be >= 0.")

    # Convert initial_graph to MultiDiGraph if needed for the Rust binding.
    if initial_graph is not None and not isinstance(initial_graph, MultiDiGraph):
        converted = MultiDiGraph()
        for node, attrs in initial_graph.nodes(data=True):
            converted.add_node(node, **attrs)
        for u, v, *rest in initial_graph.edges(data=True):
            data = rest[0] if rest else {}
            converted.add_edge(u, v, **data)
        initial_graph = converted

    return _fnx.scale_free_graph(
        n,
        alpha=alpha,
        beta=beta,
        gamma=gamma,
        delta_in=delta_in,
        delta_out=delta_out,
        seed=seed,
        initial_graph=initial_graph,
    )


def random_powerlaw_tree(n, gamma=3, seed=None, tries=100, *, create_using=None, backend=None, **backend_kwargs):
    """Return a random tree with a power-law degree distribution."""
    _validate_backend_dispatch_keywords("random_powerlaw_tree", backend, backend_kwargs)
    graph = _checked_create_using(
        create_using,
        directed=False,
        multigraph=False,
        default=Graph,
    )
    sequence = random_powerlaw_tree_sequence(n, gamma=gamma, seed=seed, tries=tries)
    return degree_sequence_tree(sequence, create_using=graph)


def random_powerlaw_tree_sequence(n, gamma=3, seed=None, tries=100):
    """Return a degree sequence suitable for a random power-law tree."""
    # br-r37-c1-rpts-neg: nx raises ValueError("empty range in
    # randrange(0, n)") leaked from internal rng.randint/randrange
    # for n <= 0; fnx previously silently returned ``[]`` (range(n)
    # yielded nothing and is_valid_tree_degree_sequence([]) returns
    # True).  Match nx's structural-error contract — same defect
    # family as br-r37-c1-{rgg-neg, pjf7g, srgg-neg, trgg-neg, 60f9n,
    # waxman-neg, gtg-neg, hszkp, 48hex}.
    if isinstance(n, int) and n <= 0:
        raise ValueError(f"empty range in randrange(0, {n})")
    rng = _generator_random_state(seed)
    zseq = [min(n, max(round(rng.paretovariate(gamma - 1)), 0)) for _ in range(n)]
    swap = [min(n, max(round(rng.paretovariate(gamma - 1)), 0)) for _ in range(tries)]

    def is_valid_tree_degree_sequence(sequence):
        if not sequence:
            return True
        if len(sequence) == 1:
            return sequence[0] == 0
        return all(degree >= 1 for degree in sequence) and sum(sequence) == 2 * (
            len(sequence) - 1
        )

    for _ in range(len(swap)):
        if is_valid_tree_degree_sequence(zseq):
            return zseq
        index = rng.randint(0, n - 1)
        zseq[index] = swap.pop()

    raise NetworkXError(f"Exceeded max ({tries}) attempts for a valid tree sequence.")


def gn_graph(n, kernel=None, create_using=None, seed=None):
    """Return a growing network (GN) digraph."""
    import bisect

    from franken_networkx import _fnx

    # NetworkX initializes the GN graph with edge (1, 0) for every
    # integral n <= 0.  The Rust fast path takes usize and either
    # returns the empty graph for 0 or rejects negative values before
    # the wrapper can preserve that observable seed-graph contract.
    if kernel is None and isinstance(n, _numbers.Integral) and n <= 0:
        graph = _checked_directed_create_using(create_using, default=DiGraph)
        graph = empty_graph(1, create_using=graph, default=DiGraph)
        graph.add_edge(1, 0)
        return graph

    if kernel is None and create_using is None:
        return _fnx.gn_graph(n, seed=seed, create_using=None)

    graph = _checked_directed_create_using(create_using, default=DiGraph)
    if kernel is None and n != 0:
        return _copy_graph_into(_fnx.gn_graph(n, seed=seed, create_using=None), graph)

    if kernel is None:

        def kernel(x):
            return x

    rng = _generator_random_state(seed)
    graph = empty_graph(1, create_using=graph, default=DiGraph)
    if n == 1:
        return graph

    graph.add_edge(1, 0)
    degree_sequence = [1, 1]

    for source in range(2, n):
        cumulative = [0.0]
        total = 0.0
        for degree in degree_sequence:
            total += kernel(degree)
            cumulative.append(total)
        cumulative = [value / total for value in cumulative]
        target = bisect.bisect_left(cumulative, rng.random()) - 1
        graph.add_edge(source, target)
        degree_sequence.append(1)
        degree_sequence[target] += 1
    return graph


def LCF_graph(n, shift_list, repeats, create_using=None):
    """Return the cubic Hamiltonian graph defined by Lederberg-Coxeter-Fruchte."""
    if n <= 0:
        return empty_graph(0, create_using)

    graph = cycle_graph(n, create_using=create_using)
    if graph.is_directed():
        raise NetworkXError("Directed Graph not supported")
    graph.graph["name"] = "LCF_graph"
    nodes = sorted(graph)

    n_extra_edges = repeats * len(shift_list)
    if n_extra_edges < 1:
        return graph

    for i in range(n_extra_edges):
        shift = shift_list[i % len(shift_list)]
        v1 = nodes[i % n]
        v2 = nodes[(i + shift) % n]
        graph.add_edge(v1, v2)
    return graph


def _lfr_zipf_rv(alpha, xmin, rng):
    if xmin < 1:
        raise ValueError("xmin < 1")
    if alpha <= 1:
        raise ValueError("a <= 1.0")
    alpha_minus_one = alpha - 1.0
    base = 2**alpha_minus_one
    while True:
        u = 1.0 - rng.random()
        v = rng.random()
        value = int(xmin * u ** -(1.0 / alpha_minus_one))
        threshold = (1.0 + (1.0 / value)) ** alpha_minus_one
        if v * value * (threshold - 1.0) / (base - 1.0) <= threshold / base:
            return value


def _lfr_zipf_rv_below(gamma, xmin, threshold, rng):
    value = _lfr_zipf_rv(gamma, xmin, rng)
    while value > threshold:
        value = _lfr_zipf_rv(gamma, xmin, rng)
    return value


def _lfr_powerlaw_sequence(gamma, low, high, condition, length, max_iters, rng):
    for _ in range(max_iters):
        sequence = []
        while not length(sequence):
            sequence.append(_lfr_zipf_rv_below(gamma, low, high, rng))
        if condition(sequence):
            return sequence
    raise NetworkXError("Could not create power law sequence")


def _lfr_hurwitz_zeta(x, q, tolerance):
    total = 0
    previous = -float("inf")
    k = 0
    while abs(total - previous) > tolerance:
        previous = total
        total += 1 / ((k + q) ** x)
        k += 1
    return total


def _lfr_generate_min_degree(gamma, average_degree, max_degree, tolerance, max_iters):
    try:
        from scipy.special import zeta
    except ImportError:

        def zeta(x, q):
            return _lfr_hurwitz_zeta(x, q, tolerance)

    min_degree_top = max_degree
    min_degree_bottom = 1
    min_degree_mid = (min_degree_top - min_degree_bottom) / 2 + min_degree_bottom
    iterations = 0
    mid_average_degree = 0
    while abs(mid_average_degree - average_degree) > tolerance:
        if iterations > max_iters:
            raise NetworkXError("Could not match average_degree")
        mid_average_degree = 0
        for x in range(int(min_degree_mid), max_degree + 1):
            mid_average_degree += (x ** (-gamma + 1)) / zeta(gamma, min_degree_mid)
        if mid_average_degree > average_degree:
            min_degree_top = min_degree_mid
            min_degree_mid = (min_degree_top - min_degree_bottom) / 2 + min_degree_bottom
        else:
            min_degree_bottom = min_degree_mid
            min_degree_mid = (min_degree_top - min_degree_bottom) / 2 + min_degree_bottom
        iterations += 1
    return round(min_degree_mid)


def _lfr_generate_communities(degree_sequence, community_sizes, mu, max_iters, rng):
    result = [set() for _ in community_sizes]
    free = list(range(len(degree_sequence)))
    for _ in range(max_iters):
        node = free.pop()
        community_index = rng.choice(range(len(community_sizes)))
        internal_degree = round(degree_sequence[node] * (1 - mu))
        if internal_degree < community_sizes[community_index]:
            result[community_index].add(node)
        else:
            free.append(node)
        if len(result[community_index]) > community_sizes[community_index]:
            free.append(result[community_index].pop())
        if not free:
            return result
    # br-r37-c1-lfr-emi: nx raises ExceededMaxIterations (subclass
    # of NetworkXException, NOT NetworkXError) when the community
    # assignment fails to converge.  Match nx's exact exception
    # class so callers using ``except nx.ExceededMaxIterations:``
    # catch the right error.
    from networkx import ExceededMaxIterations as _EMI
    raise _EMI(
        "Could not assign communities; try increasing min_community"
    )


def LFR_benchmark_graph(
    n,
    tau1,
    tau2,
    mu,
    average_degree=None,
    min_degree=None,
    max_degree=None,
    min_community=None,
    max_community=None,
    tol=1e-07,
    max_iters=500,
    seed=None,
):
    """Return an LFR benchmark graph."""
    if not tau1 > 1:
        raise NetworkXError("tau1 must be greater than one")
    if not tau2 > 1:
        raise NetworkXError("tau2 must be greater than one")
    if not 0 <= mu <= 1:
        raise NetworkXError("mu must be in the interval [0, 1]")

    if max_degree is None:
        max_degree = n
    elif not 0 < max_degree <= n:
        raise NetworkXError("max_degree must be in the interval (0, n]")
    if not ((min_degree is None) ^ (average_degree is None)):
        raise NetworkXError(
            "Must assign exactly one of min_degree and average_degree",
        )

    rng = _generator_random_state(seed)
    if min_degree is None:
        min_degree = _lfr_generate_min_degree(
            tau1,
            average_degree,
            max_degree,
            tol,
            max_iters,
        )

    degree_sequence = _lfr_powerlaw_sequence(
        tau1,
        min_degree,
        max_degree,
        lambda sequence: sum(sequence) % 2 == 0,
        lambda sequence: len(sequence) >= n,
        max_iters,
        rng,
    )

    if min_community is None:
        min_community = min(degree_sequence)
    if max_community is None:
        max_community = max(degree_sequence)

    community_sizes = _lfr_powerlaw_sequence(
        tau2,
        min_community,
        max_community,
        lambda sequence: sum(sequence) == n,
        lambda sequence: sum(sequence) >= n,
        max_iters,
        rng,
    )
    communities = _lfr_generate_communities(
        degree_sequence,
        community_sizes,
        mu,
        max_iters * 10 * n,
        rng,
    )

    graph = Graph()
    graph.add_nodes_from(range(n))
    for community in communities:
        community_nodes = list(community)
        for node in community:
            while graph.degree[node] < round(degree_sequence[node] * (1 - mu)):
                graph.add_edge(node, rng.choice(community_nodes))
            while graph.degree[node] < degree_sequence[node]:
                target = rng.choice(range(n))
                if target not in community:
                    graph.add_edge(node, target)
            graph.nodes[node]["community"] = community
    return graph


def hexagonal_lattice_graph(
    m,
    n,
    periodic=False,
    with_positions=True,
    create_using=None,
):
    """Return a hexagonal lattice graph."""
    graph = empty_graph(0, create_using)
    if m == 0 or n == 0:
        return graph
    if periodic and (n % 2 == 1 or m < 2 or n < 2):
        raise NetworkXError(
            "periodic hexagonal lattice needs m > 1, n > 1 and even n"
        )

    height = 2 * m
    rows = range(height + 2)
    cols = range(n + 1)

    col_edges = (
        ((i, j), (i, j + 1))
        for i in cols
        for j in rows[: height + 1]
    )
    row_edges = (
        ((i, j), (i + 1, j))
        for i in cols[:n]
        for j in rows
        if i % 2 == j % 2
    )
    graph.add_edges_from(col_edges)
    graph.add_edges_from(row_edges)
    graph.remove_node((0, height + 1))
    graph.remove_node((n, (height + 1) * (n % 2)))

    if periodic:
        for i in cols[:n]:
            graph = contracted_nodes(graph, (i, 0), (i, height), copy=True)
        for i in cols[1:]:
            graph = contracted_nodes(graph, (i, 1), (i, height + 1), copy=True)
        for j in rows[1:height]:
            graph = contracted_nodes(graph, (0, j), (n, j), copy=True)
        graph.remove_node((n, height))

    if with_positions:
        sqrt3_over_2 = _math.sqrt(3) / 2
        positions = {}
        for i in cols:
            for j in rows:
                if (i, j) not in graph:
                    continue
                x = 0.5 + i + i // 2 + (j % 2) * ((i % 2) - 0.5)
                if periodic:
                    y = sqrt3_over_2 * j + 0.01 * i * i
                else:
                    y = sqrt3_over_2 * j
                positions[(i, j)] = (x, y)
        set_node_attributes(graph, positions, "pos")
    return graph


def triangular_lattice_graph(
    m,
    n,
    periodic=False,
    with_positions=True,
    create_using=None,
):
    """Return a triangular lattice graph."""
    graph = empty_graph(0, create_using)
    if n == 0 or m == 0:
        return graph
    if periodic and (n < 5 or m < 3):
        raise NetworkXError(f"m > 2 and n > 4 required for periodic. m={m}, n={n}")

    width = (n + 1) // 2
    rows = range(m + 1)
    cols = range(width + 1)

    graph.add_edges_from(((i, j), (i + 1, j)) for j in rows for i in cols[:width])
    graph.add_edges_from(((i, j), (i, j + 1)) for j in rows[:m] for i in cols)
    graph.add_edges_from(
        ((i, j), (i + 1, j + 1))
        for j in rows[1:m:2]
        for i in cols[:width]
    )
    graph.add_edges_from(
        ((i + 1, j), (i, j + 1))
        for j in rows[:m:2]
        for i in cols[:width]
    )

    if periodic:
        for i in cols:
            graph = contracted_nodes(graph, (i, 0), (i, m), copy=True)
        for j in rows[:m]:
            graph = contracted_nodes(graph, (0, j), (width, j), copy=True)
    elif n % 2:
        graph.remove_nodes_from((width, j) for j in rows[1::2])

    if with_positions:
        sqrt3_over_2 = _math.sqrt(3) / 2
        positions = {}
        for i in cols:
            for j in rows:
                if (i, j) not in graph:
                    continue
                x = 0.5 * (j % 2) + i
                if periodic:
                    y = sqrt3_over_2 * j + 0.01 * i * i
                else:
                    y = sqrt3_over_2 * j
                positions[(i, j)] = (x, y)
        set_node_attributes(graph, positions, "pos")
    return graph


def grid_graph(dim, periodic=False):
    """Return an n-dimensional grid graph.

    The dimension n is the length of `dim` and the size in each dimension
    is the value of the corresponding list element.
    """
    if not dim:
        return Graph()

    dimensions = list(dim)
    periodic_flags = (
        iter(periodic) if isinstance(periodic, _Iterable) else _itertools.repeat(periodic)
    )

    axes = []
    periods = []
    for axis in dimensions:
        periods.append(bool(next(periodic_flags)))
        if isinstance(axis, _numbers.Integral):
            # br-r37-c1-grid-neg: nx routes grid_graph through
            # cartesian_product of path_graph(d) for each d; a
            # negative ``d`` raises NetworkXError("Negative number
            # of nodes not valid: {d}") on the first negative
            # encountered.  fnx previously silently produced an
            # empty graph (range(-3) yielded nothing).  Same
            # defect family as br-r37-c1-{rgg-neg, ...}.
            if axis < 0:
                raise NetworkXError(
                    f"Negative number of nodes not valid: {axis}"
                )
            axes.append(list(range(axis)))
        else:
            axes.append(list(axis))

    graph = Graph()
    output_axes = list(reversed(axes))
    if not output_axes or any(len(axis) == 0 for axis in output_axes):
        return graph

    index_axes = [range(len(axis)) for axis in output_axes]

    def make_node(positions):
        values = [
            output_axes[index][position]
            for index, position in enumerate(positions)
        ]
        return values[0] if len(values) == 1 else tuple(values)

    for positions in _itertools.product(*index_axes):
        graph.add_node(make_node(positions))

    for positions in _itertools.product(*index_axes):
        left = make_node(positions)
        for output_index, axis in enumerate(output_axes):
            axis_pos = positions[output_index]
            right_positions = list(positions)
            if axis_pos + 1 < len(axis):
                right_positions[output_index] = axis_pos + 1
            elif periods[len(output_axes) - 1 - output_index]:
                if len(axis) == 1:
                    graph.add_edge(left, left)
                    continue
                if len(axis) == 2:
                    continue
                right_positions[output_index] = 0
            else:
                continue
            graph.add_edge(left, make_node(right_positions))

    return graph


def lattice_reference(G, niter=5, D=None, connectivity=True, seed=None):
    """Return a lattice-like rewiring of *G* preserving degree sequence."""
    import bisect
    import math

    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if len(G) < 4:
        raise NetworkXError("Graph has fewer than four nodes.")
    if G.number_of_edges() < 2:
        raise NetworkXError("Graph has fewer that 2 edges")

    def cumulative_distribution(distribution):
        cdf = [0.0]
        cumulative = 0.0
        for element in distribution:
            cumulative += element
            cdf.append(cumulative)
        return [element / cumulative for element in cdf]

    def discrete_sequence(_count, cdistribution, rng):
        return [
            bisect.bisect_left(cdistribution, rng.random()) - 1
            for _ in range(_count)
        ]

    def matrix_value(matrix, row, col):
        try:
            return matrix[row, col]
        except (TypeError, KeyError):
            return matrix[row][col]

    def has_path(graph, source, target):
        if source == target:
            return True
        seen = {source}
        queue = [source]
        index = 0
        while index < len(queue):
            node = queue[index]
            index += 1
            for neighbor in graph[node]:
                if neighbor == target:
                    return True
                if neighbor not in seen:
                    seen.add(neighbor)
                    queue.append(neighbor)
        return False

    graph = Graph()
    graph.graph.update(dict(G.graph))
    graph.add_nodes_from((node, dict(attrs)) for node, attrs in G.nodes(data=True))
    graph.add_edges_from((u, v, dict(attrs)) for u, v, attrs in G.edges(data=True))
    rng = _generator_random_state(seed)
    keys, degrees = zip(*graph.degree)
    cdf = cumulative_distribution(degrees)

    node_count = len(graph)
    edge_count = graph.number_of_edges()
    if D is None:
        distance = [[0 for _ in range(node_count)] for _ in range(node_count)]
        lower = list(range(1, node_count))
        upper = list(range(node_count - 1, 0, -1))
        wrapped = [0] + [min(left, right) for left, right in zip(lower, upper)]
        for v in range(_math.ceil(node_count / 2)):
            row = wrapped[v + 1 :] + wrapped[: v + 1]
            distance[node_count - v - 1] = row
            distance[v] = list(reversed(row))
    else:
        distance = D

    total_iterations = niter * edge_count
    max_attempts = int(node_count * edge_count / (node_count * (node_count - 1) / 2))

    for _ in range(total_iterations):
        attempts = 0
        while attempts < max_attempts:
            ai, ci = discrete_sequence(2, cdf, rng)
            if ai == ci:
                continue
            a = keys[ai]
            c = keys[ci]
            b = rng.choice(list(graph.neighbors(a)))
            d = rng.choice(list(graph.neighbors(c)))
            bi = keys.index(b)
            di = keys.index(d)

            if b in [a, c, d] or d in [a, b, c]:
                continue

            if d not in graph[a] and b not in graph[c]:
                if (
                    matrix_value(distance, ai, bi) + matrix_value(distance, ci, di)
                    >= matrix_value(distance, ai, ci) + matrix_value(distance, bi, di)
                ):
                    graph.add_edge(a, d)
                    graph.add_edge(c, b)
                    graph.remove_edge(a, b)
                    graph.remove_edge(c, d)

                    if connectivity and not has_path(graph, a, b):
                        graph.remove_edge(a, d)
                        graph.remove_edge(c, b)
                        graph.add_edge(a, b)
                        graph.add_edge(c, d)
                    else:
                        break
            attempts += 1

    return graph


def margulis_gabber_galil_graph(n, create_using=None):
    """Return a Margulis-Gabber-Galil expander graph."""
    graph = empty_graph(0, create_using, default=MultiGraph)
    if graph.is_directed() or not graph.is_multigraph():
        raise NetworkXError("`create_using` must be an undirected multigraph.")

    for x, y in _itertools.product(range(n), repeat=2):
        for u, v in (
            ((x + 2 * y) % n, y),
            ((x + (2 * y + 1)) % n, y),
            (x, (y + 2 * x) % n),
            (x, (y + (2 * x + 1)) % n),
        ):
            graph.add_edge((x, y), (u, v))
    graph.graph["name"] = f"margulis_gabber_galil_graph({n})"
    return graph


def sudoku_graph(n=3):
    """Return the Sudoku constraint graph of order *n*.

    The n-Sudoku graph has n^4 vertices (cells of an n^2 × n^2 grid).
    Two cells are adjacent iff they share a row, column, or n×n box.
    """
    return _rust_sudoku_graph(n)


def fast_gnp_random_graph(n, p, seed=None, directed=False, *, create_using=None, backend=None, **backend_kwargs):
    """Return a fast G(n,p) random graph (Batagelj-Brandes O(n+m) algorithm)."""
    _validate_backend_dispatch_keywords("fast_gnp_random_graph", backend, backend_kwargs)
    from franken_networkx._fnx import fast_gnp_random_graph as _rust_fast_gnp

    # br-gnpvalid: see gnp_random_graph.
    if n < 0:
        raise NetworkXError(f"Negative number of nodes not valid: {n}")

    # br-r37-c1-fgnp-pnan: nx leaks ValueError("cannot convert
    # float NaN to integer") from its internal ``int(log(1-p)/...)``
    # computation.  fnx silently routed NaN through the gnp
    # fallback (which silently returns 0).  Match nx's leaky-but-
    # stable contract.  Note: gnp_random_graph (the slower Erdős-
    # Rényi path) intentionally accepts NaN silently — only
    # fast_gnp's int-conversion path raises.
    import math as _math
    if isinstance(p, float) and _math.isnan(p):
        raise ValueError("cannot convert float NaN to integer")

    # br-r37-c1-lsdek: out-of-range p is silent in nx (p<=0 -> empty,
    # p>=1 -> complete). The Rust fast path raises FailClosed for those,
    # so route to the boundary-aware gnp_random_graph wrapper.
    if create_using is None and 0 < p < 1:
        return _rust_fast_gnp(
            n,
            p,
            seed=_native_random_seed(seed),
            directed=directed,
        )

    if create_using is None and not (0 < p < 1):
        return gnp_random_graph(n, p, seed=seed, directed=directed)

    rng = _generator_random_state(seed)
    default = DiGraph if directed else Graph
    graph = _checked_create_using(
        create_using,
        directed=directed,
        multigraph=False,
        default=default,
    )
    if p <= 0 or p >= 1:
        return gnp_random_graph(
            n,
            p,
            seed=rng,
            directed=directed,
            create_using=graph,
        )

    graph = empty_graph(n, create_using=graph, default=default)
    lp = _math.log(1.0 - p)

    if directed:
        v = 1
        w = -1
        while v < n:
            lr = _math.log(1.0 - rng.random())
            w = w + 1 + int(lr / lp)
            while w >= v and v < n:
                w = w - v
                v += 1
            if v < n:
                graph.add_edge(w, v)

    v = 1
    w = -1
    while v < n:
        lr = _math.log(1.0 - rng.random())
        w = w + 1 + int(lr / lp)
        while w >= v and v < n:
            w = w - v
            v += 1
        if v < n:
            graph.add_edge(v, w)
    return graph


def newman_watts_strogatz_graph(n, k, p, seed=None, *, create_using=None, backend=None, **backend_kwargs):
    """Return a Newman-Watts-Strogatz small-world graph."""
    _validate_backend_dispatch_keywords(
        "newman_watts_strogatz_graph", backend, backend_kwargs
    )
    # br-nwsval: validate with nx-shaped NetworkXError at the Python edge so
    # that the Rust ValueError(FailClosed{...}) doesn't leak. nx accepts
    # k=0 and k=1 (returns the empty graph on n nodes — the ring with
    # k//2=0 has no edges); the Rust binding rejects k<2 so we short-circuit
    # those cases here.
    if k > n:
        raise NetworkXError("k>=n, choose smaller k or larger n")
    if k == n:
        return complete_graph(n, create_using=create_using)
    if k < 2:
        return empty_graph(n, create_using=create_using)
    # br-r37-c1-nws-pnan: nx accepts NaN / inf / out-of-range p
    # silently — its weighted-flip ``random.random() < p`` evaluates
    # naturally (NaN → False / no rewiring; inf → True / full
    # rewiring; p<0 / p>1 → comparable extremes).  fnx's Rust
    # binding rejected these with leaky ``FailClosed`` formats.
    # Clamp / route to match nx's silent contract.
    import math as _math
    if isinstance(p, float) and _math.isnan(p):
        # NaN: nx's < comparison returns False → no rewiring →
        # equivalent to p=0
        p = 0.0
    elif isinstance(p, (int, float)) and p > 1:
        p = 1.0  # full rewiring
    elif isinstance(p, (int, float)) and p < 0:
        p = 0.0  # no rewiring
    graph = _rust_newman_watts_strogatz_graph(
        n, k, p, seed=_native_random_seed(seed)
    )
    if create_using is None:
        return graph
    return _copy_graph_into(
        graph,
        _checked_create_using(
            create_using,
            directed=False,
            multigraph=False,
            default=Graph,
        ),
    )


def connected_watts_strogatz_graph(n, k, p, tries=100, seed=None, *, create_using=None):
    """Return a connected Watts-Strogatz small-world graph."""
    # br-cwsval: validate at the Python edge so the Rust ValueError(FailClosed)
    # surface doesn't leak — nx raises NetworkXError for both k>n and the
    # tries-exceeded path.
    if k > n:
        raise NetworkXError("k>n, choose smaller k or larger n")
    if n == 0:
        raise NetworkXPointlessConcept("Connectivity is undefined for the null graph.")
    if n == 1 and k < 1:
        return empty_graph(n, create_using=create_using)
    if k == n:
        return complete_graph(n, create_using=create_using)
    if k < 2:
        raise NetworkXError("Maximum number of tries exceeded")
    # br-r37-c1-cws-tries: nx raises NetworkXError("Maximum number
    # of tries exceeded") for tries <= 0; fnx's Rust binding leaked
    # ``ValueError(FailClosed { ... })`` for tries=0 and
    # ``OverflowError("can't convert negative int to unsigned")``
    # for tries<0 (the unsigned Rust signature).  Validate at the
    # wrapper to match nx's contract.
    if isinstance(tries, int) and tries <= 0:
        raise NetworkXError("Maximum number of tries exceeded")
    graph = _rust_connected_watts_strogatz_graph(
        n,
        k,
        p,
        tries=tries,
        seed=_native_random_seed(seed),
    )
    if create_using is None:
        return graph
    return _copy_graph_into(
        graph,
        _checked_create_using(
            create_using,
            directed=False,
            multigraph=False,
            default=Graph,
        ),
    )


def random_regular_graph(d, n, seed=None, *, create_using=None, backend=None, **backend_kwargs):
    """Return a random d-regular graph."""
    _validate_backend_dispatch_keywords("random_regular_graph", backend, backend_kwargs)
    # br-codrgen: seeded output diverges from nx because the Rust native
    # uses MT19937 while nx uses Python's random.Random. Keeping native
    # per the "no nx fallback for generators" design invariant guarded
    # by test_native_random_generators_do_not_fallback_to_networkx.
    # Exact-output parity requires a Rust-side RNG port and is tracked
    # separately.
    # br-rrgval: validate with nx-shaped NetworkXError *before* the Rust
    # branch; without this, invalid (d, n) leak the Rust
    # `ValueError("FailClosed { ... }")` instead of nx's NetworkXError.
    # Order matches nx (n*d parity check first, then d<n) so that inputs
    # failing both — e.g. (d=3, n=3) — surface the same message nx does.
    if (n * d) % 2 != 0:
        raise NetworkXError("n * d must be even")
    if not 0 <= d < n:
        raise NetworkXError("the 0 <= d < n inequality must be satisfied")

    # br-r37-c1-rrgseed: nx.random_regular_graph(d, n, seed=) uses
    # ``random.Random(seed)`` (Python's MT19937 with Python-side
    # state).  fnx's no-``create_using`` fast path used the Rust
    # ``_rust_random_regular_graph`` which has its own MT19937 with
    # different state evolution — same seed produced different
    # graphs (a documented divergence labeled br-codrgen).  Drop-in
    # callers using ``seed=N`` for reproducibility hit silent graph
    # divergence.
    #
    # Fix: route the no-``create_using`` path through the Python
    # implementation below (which uses ``_generator_random_state``
    # = ``random.Random``) — same RNG semantics as nx — so seeded
    # output matches nx exactly.  No nx-fallback is used (the
    # ``test_native_random_generators_do_not_fallback_to_networkx``
    # lock-test still passes); the algorithm is fnx's own Python
    # implementation.
    if create_using is None:
        create_using = Graph

    rng = _generator_random_state(seed)
    graph = _checked_create_using(
        create_using,
        directed=False,
        multigraph=False,
        default=Graph,
    )

    graph = empty_graph(n, create_using=graph)
    if d == 0:
        return graph

    def _suitable(edges, potential_edges):
        if not potential_edges:
            return True
        for s1 in potential_edges:
            for s2 in potential_edges:
                if s1 == s2:
                    break
                if s1 > s2:
                    s1, s2 = s2, s1
                if (s1, s2) not in edges:
                    return True
        return False

    def _try_creation():
        edges = set()
        stubs = list(range(n)) * d

        while stubs:
            potential_edges = _defaultdict(lambda: 0)
            rng.shuffle(stubs)
            stubiter = iter(stubs)
            for s1, s2 in zip(stubiter, stubiter):
                if s1 > s2:
                    s1, s2 = s2, s1
                if s1 != s2 and (s1, s2) not in edges:
                    edges.add((s1, s2))
                else:
                    potential_edges[s1] += 1
                    potential_edges[s2] += 1

            if not _suitable(edges, potential_edges):
                return None

            return_stubs = []
            for node, potential in potential_edges.items():
                return_stubs.extend([node] * potential)
            stubs[:] = return_stubs

        return edges

    edges = _try_creation()
    while edges is None:
        edges = _try_creation()
    graph.add_edges_from(edges)
    return graph


def powerlaw_cluster_graph(n, m, p, seed=None, *, create_using=None, backend=None, **backend_kwargs):
    """Return a powerlaw-cluster graph."""
    _validate_backend_dispatch_keywords("powerlaw_cluster_graph", backend, backend_kwargs)
    # br-powerlawexc: nx raises NetworkXError with its own wording; fnx used
    # to surface the Rust 'ValueError(FailClosed{...})' on the default path.
    # Normalize to nx's exact message so regex-matched pytest.raises keeps
    # working on the drop-in surface. nx accepts m == n (returns n nodes
    # with 0 edges) — only m > n is rejected.
    if m < 1 or m > n:
        raise NetworkXError(
            f"NetworkXError must have m>1 and m<n, m={m},n={n}"
        )
    if p > 1 or p < 0:
        raise NetworkXError(f"NetworkXError p must be in [0,1], p={p}")
    # br-r37-c1-pcg-pnan: nx accepts p=NaN silently — its weighted
    # ``random.random() < p`` flip evaluates False (NaN comparison
    # always False), so triangle-closure never fires and the base
    # preferential-attachment graph is returned.  fnx's Rust binding
    # rejected NaN with the leaky ``FailClosed`` format.  Coerce
    # NaN → 0.0 to match nx's silent contract.  Same defect family
    # as br-r37-c1-r3ct1 (newman_watts_strogatz NaN).
    import math as _math
    if isinstance(p, float) and _math.isnan(p):
        p = 0.0
    graph = _rust_powerlaw_cluster_graph(n, m, p, seed=_native_random_seed(seed))
    if create_using is None:
        return graph
    return _copy_graph_into(
        graph,
        _checked_create_using(
            create_using,
            directed=False,
            multigraph=False,
            default=Graph,
        ),
    )


def directed_configuration_model(
    in_degree_sequence,
    out_degree_sequence,
    create_using=None,
    seed=None,
):
    """Return a directed configuration model graph."""
    if sum(in_degree_sequence) != sum(out_degree_sequence):
        raise NetworkXError("Invalid degree sequences: sequences must have equal sums")

    graph = _empty_graph_from_create_using(
        create_using,
        default=MultiDiGraph,
    )
    return _configuration_model_local(
        out_degree_sequence,
        graph,
        directed=True,
        in_degree_sequence=in_degree_sequence,
        seed=seed,
    )


def directed_joint_degree_graph(in_degrees, out_degrees, nkk, seed=None):
    """Return a directed graph matching a directed joint-degree distribution."""
    if not is_valid_directed_joint_degree(in_degrees, out_degrees, nkk):
        raise NetworkXError("Input is not realizable as a simple graph")

    graph = DiGraph()
    degree_nodes_in = {}
    degree_nodes_out = {}
    degree_nodes_in_unsat = {}
    degree_nodes_out_unsat = {}
    residual_out = {}
    residual_in = {}
    partition_out = {}
    partition_in = {}
    non_chords = {}

    for idx, in_degree in enumerate(in_degrees):
        idx = int(idx)
        if in_degree > 0:
            degree_nodes_in.setdefault(in_degree, [])
            degree_nodes_in_unsat.setdefault(in_degree, set())
            degree_nodes_in[in_degree].append(idx)
            degree_nodes_in_unsat[in_degree].add(idx)
            residual_in[idx] = in_degree
            partition_in[idx] = in_degree

    for idx, out_degree in enumerate(out_degrees):
        non_chords[(out_degree, in_degrees[idx])] = (
            non_chords.get((out_degree, in_degrees[idx]), 0) + 1
        )
        idx = int(idx)
        if out_degree > 0:
            degree_nodes_out.setdefault(out_degree, [])
            degree_nodes_out_unsat.setdefault(out_degree, set())
            degree_nodes_out[out_degree].append(idx)
            degree_nodes_out_unsat[out_degree].add(idx)
            residual_out[idx] = out_degree
            partition_out[idx] = out_degree
        graph.add_node(idx)

    count_in = {degree: len(nodes) for degree, nodes in degree_nodes_in.items()}
    count_out = {degree: len(nodes) for degree, nodes in degree_nodes_out.items()}
    rng = _generator_random_state(seed)

    for out_degree in nkk:
        for in_degree in nkk[out_degree]:
            edges_to_add = nkk[out_degree][in_degree]
            if edges_to_add <= 0:
                continue

            chords = set()
            out_count = count_out[out_degree]
            in_count = count_in[in_degree]
            sample = rng.sample(
                range(out_count * in_count),
                edges_to_add + non_chords.get((out_degree, in_degree), 0),
            )

            sample_index = 0
            while len(chords) < edges_to_add:
                source = degree_nodes_out[out_degree][sample[sample_index] % out_count]
                target = degree_nodes_in[in_degree][sample[sample_index] // out_count]
                sample_index += 1
                if source != target:
                    chords.add((source, target))

            out_unsat = degree_nodes_out_unsat[out_degree]
            in_unsat = degree_nodes_in_unsat[in_degree]

            while edges_to_add > 0:
                source, target = chords.pop()
                chords.add((source, target))

                if residual_out[source] == 0:
                    switched = _directed_neighbor_switch_local(
                        graph,
                        source,
                        out_unsat,
                        residual_out,
                        chords,
                        partition_in,
                        in_degree,
                    )
                    if switched is not None:
                        source = switched

                if residual_in[target] == 0:
                    switched = _directed_neighbor_switch_rev_local(
                        graph,
                        target,
                        in_unsat,
                        residual_in,
                        chords,
                        partition_out,
                        out_degree,
                    )
                    if switched is not None:
                        target = switched

                graph.add_edge(source, target)
                residual_out[source] -= 1
                residual_in[target] -= 1
                edges_to_add -= 1
                chords.discard((source, target))

                if residual_out[source] == 0:
                    out_unsat.discard(source)
                if residual_in[target] == 0:
                    in_unsat.discard(target)

    return graph


def joint_degree_graph(joint_degrees, seed=None):
    """Return an undirected graph matching a joint-degree distribution."""
    if not is_valid_joint_degree(joint_degrees):
        raise NetworkXError("Input joint degree dict not realizable as a simple graph")

    degree_count = {
        degree: sum(edges.values()) // degree
        for degree, edges in joint_degrees.items()
        if degree > 0
    }
    graph = empty_graph(sum(degree_count.values()))

    degree_nodes = {}
    residual = {}
    node_id = 0
    for degree, num_nodes in degree_count.items():
        degree_nodes[degree] = range(node_id, node_id + num_nodes)
        for node in degree_nodes[degree]:
            residual[node] = degree
        node_id += int(num_nodes)

    rng = _generator_random_state(seed)
    for degree_left in joint_degrees:
        for degree_right in joint_degrees[degree_left]:
            edges_to_add = joint_degrees[degree_left][degree_right]
            if edges_to_add <= 0 or degree_left < degree_right:
                continue

            left_count = degree_count[degree_left]
            right_count = degree_count[degree_right]
            left_nodes = degree_nodes[degree_left]
            right_nodes = degree_nodes[degree_right]
            left_unsat = {node for node in left_nodes if residual[node] > 0}

            if degree_left != degree_right:
                right_unsat = {node for node in right_nodes if residual[node] > 0}
            else:
                right_unsat = left_unsat
                edges_to_add = joint_degrees[degree_left][degree_right] // 2

            while edges_to_add > 0:
                source = left_nodes[rng.randrange(left_count)]
                target = right_nodes[rng.randrange(right_count)]

                if graph.has_edge(source, target) or source == target:
                    continue

                if residual[source] == 0:
                    _neighbor_switch_local(graph, source, left_unsat, residual)
                if residual[target] == 0:
                    if degree_left != degree_right:
                        _neighbor_switch_local(graph, target, right_unsat, residual)
                    else:
                        _neighbor_switch_local(
                            graph,
                            target,
                            right_unsat,
                            residual,
                            avoid_node_id=source,
                        )

                graph.add_edge(source, target)
                residual[source] -= 1
                residual[target] -= 1
                edges_to_add -= 1

                if residual[source] == 0:
                    left_unsat.discard(source)
                if residual[target] == 0:
                    right_unsat.discard(target)

    return graph


def expected_degree_graph(w, seed=None, selfloops=True):
    """Return a Chung-Lu expected-degree random graph."""
    n = len(w)
    graph = empty_graph(n)
    if n == 0 or max(w) == 0:
        return graph

    rng = _generator_random_state(seed)
    rho = 1 / sum(w)
    order = sorted(enumerate(w), key=lambda item: item[1], reverse=True)
    mapping = {canonical: node for canonical, (node, _) in enumerate(order)}
    sequence = [weight for _, weight in order]
    last = n if selfloops else n - 1
    for source in range(last):
        target = source if selfloops else source + 1
        factor = sequence[source] * rho
        probability = min(sequence[target] * factor, 1)
        while target < n and probability > 0:
            if probability != 1:
                target += _math.floor(_math.log(rng.random(), 1 - probability))
            if target < n:
                next_probability = min(sequence[target] * factor, 1)
                if rng.random() < next_probability / probability:
                    graph.add_edge(mapping[source], mapping[target])
                target += 1
                probability = next_probability
    return graph


def directed_havel_hakimi_graph(in_deg_sequence, out_deg_sequence, create_using=None):
    """Return a directed graph with prescribed in/out degree sequences."""
    try:
        in_deg_sequence = [int(degree) for degree in in_deg_sequence]
        out_deg_sequence = [int(degree) for degree in out_deg_sequence]
    except (TypeError, ValueError):
        raise NetworkXError("Invalid degree sequences. Sequence values must be positive.")

    sumin = 0
    sumout = 0
    nin = len(in_deg_sequence)
    nout = len(out_deg_sequence)
    maxn = max(nin, nout)
    graph = _empty_graph_from_create_using(create_using, default=DiGraph)
    graph.add_nodes_from(range(maxn))
    if maxn == 0:
        return graph

    maxin = 0
    stubheap = []
    zeroheap = []
    for node in range(maxn):
        out_degree = out_deg_sequence[node] if node < nout else 0
        in_degree = in_deg_sequence[node] if node < nin else 0
        if in_degree < 0 or out_degree < 0:
            raise NetworkXError(
                "Invalid degree sequences. Sequence values must be positive."
            )
        sumin += in_degree
        sumout += out_degree
        maxin = max(maxin, in_degree)
        if in_degree > 0:
            _heappush(stubheap, (-out_degree, -in_degree, node))
        elif out_degree > 0:
            _heappush(zeroheap, (-out_degree, node))
    if sumin != sumout:
        raise NetworkXError("Invalid degree sequences. Sequences must have equal sums.")

    modified = [(0, 0, 0)] * (maxin + 1)
    while stubheap:
        freeout, freein, target = _heappop(stubheap)
        freein *= -1
        if freein > len(stubheap) + len(zeroheap):
            raise NetworkXError("Non-digraphical integer sequence")

        modified_len = 0
        for _ in range(freein):
            if zeroheap and (not stubheap or stubheap[0][0] > zeroheap[0][0]):
                stubout, source = _heappop(zeroheap)
                stubin = 0
            else:
                stubout, stubin, source = _heappop(stubheap)
            if stubout == 0:
                raise NetworkXError("Non-digraphical integer sequence")
            graph.add_edge(source, target)
            if stubout + 1 < 0 or stubin < 0:
                modified[modified_len] = (stubout + 1, stubin, source)
                modified_len += 1

        for i in range(modified_len):
            stub = modified[i]
            if stub[1] < 0:
                _heappush(stubheap, stub)
            else:
                _heappush(zeroheap, (stub[0], stub[2]))
        if freeout < 0:
            _heappush(zeroheap, (freeout, target))

    return graph


